// Category: java_advanced — 188 questions
export const category = "java_advanced";
export const questions = [{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"JVM 垃圾回收算法","content":"请介绍 JVM 中常见的垃圾回收算法及其优缺点。","answer":"答案：标记-清除（有内存碎片）、标记-复制（无碎片但浪费一半空间）、标记-整理（无碎片但效率低）、分代收集（新生代复制，老年代标记-整理）。","hints":["Java 8 默认的垃圾回收器是什么","CMS 和 G1 的区别"],"tags":["JVM","GC"],"company":"阿里巴巴","id":1706},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"线程池的核心参数","content":"请解释 ThreadPoolExecutor 的核心参数及其作用。","answer":"答案：corePoolSize（核心线程数）、maximumPoolSize（最大线程数）、keepAliveTime（空闲线程存活时间）、workQueue（任务队列）、threadFactory（线程工厂）、handler（拒绝策略）。","hints":["任务提交后线程池的处理流程","四种拒绝策略分别是什么"],"tags":["并发","线程池"],"company":"阿里巴巴,腾讯","id":1707},{"category":"java_advanced","difficulty":"hard","type":"coding","title":"实现一个带超时的缓存","content":"请实现一个支持过期时间的泛型缓存，要求线程安全。","answer":"```java\npublic class TimedCache<K, V> {\n    private final ConcurrentHashMap<K, CacheEntry<V>> cache = new ConcurrentHashMap<>();\n    \n    private record CacheEntry<V>(V value, long expireAt) {}\n    \n    public void put(K key, V value, long ttlMs) {\n        cache.put(key, new CacheEntry<>(value, System.currentTimeMillis() + ttlMs));\n    }\n    \n    public V get(K key) {\n        CacheEntry<V> entry = cache.get(key);\n        if (entry == null || System.currentTimeMillis() > entry.expireAt()) {\n            cache.remove(key);\n            return null;\n        }\n        return entry.value();\n    }\n}\n```","hints":["如何清理过期条目","ConcurrentHashMap 能保证线程安全吗"],"tags":["并发","缓存"],"id":1708},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"NIO 与 BIO 的区别","content":"请比较 Java NIO 和传统 BIO 的区别及适用场景。","answer":"答案：BIO 是阻塞 I/O，一个线程处理一个连接，简单但线程开销大。NIO 是非阻塞 I/O，基于 Channel 和 Selector，一个线程可处理多个连接，适合高并发场景。","hints":["NIO 的三个核心组件","零拷贝（Zero-Copy）是什么"],"tags":["NIO","IO"],"company":"阿里巴巴","id":1709},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"Java 反射机制","content":"请解释 Java 反射机制及其常见用途。","answer":"答案：反射允许程序在运行时获取类的完整信息（方法、字段、构造器）并动态调用。常用于框架（Spring）、ORM、动态代理、序列化等场景。","hints":["获取 Class 对象的三种方式","反射的性能开销如何优化"],"tags":["反射","基础"],"id":1710},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"泛型的类型擦除","content":"请解释 Java 泛型的类型擦除机制及其影响。","answer":"答案：Java 泛型在编译时进行类型检查，编译后擦除类型信息，生成原始类型（Raw Type）的字节码。导致运行时无法获取泛型参数类型，List<String> 和 List<Integer> 实际上是同一个类。","hints":["如何绕过类型擦除获取泛型参数类型","桥方法（Bridge Method）的作用"],"tags":["泛型","基础"],"id":1711},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"类加载机制与双亲委派模型","content":"请描述 JVM 类加载机制和双亲委派模型的工作原理。","answer":"答案：类加载分三步：加载、连接（验证/准备/解析）、初始化。双亲委派：加载类时先委派给父加载器，父加载器无法加载时才由子加载器加载。核心类由 Bootstrap 加载，保证核心 API 不被篡改。","hints":["如何打破双亲委派模型","Tomcat 的类加载器为什么打破双亲委派"],"tags":["JVM","类加载"],"company":"阿里巴巴","id":1712},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"ReentrantLock 与 synchronized 的区别","content":"请比较 ReentrantLock 和 synchronized 的区别。","answer":"答案：synchronized 是 JVM 层面关键字，自动释放锁。ReentrantLock 是 API 层面的锁，需要手动释放，支持可中断、可定时、公平锁、条件变量等高级功能。Java 6 优化后性能差距不大。","hints":["什么是锁升级","Condition 的 await/signal 与 wait/notify 的区别"],"tags":["并发","锁"],"id":1713},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"CompletableFuture 异步编程","content":"请介绍 CompletableFuture 的核心用法及异步编排能力。","answer":"答案：CompletableFuture 提供了 supplyAsync/runAsync 创建异步任务，thenApply/thenCompose 串行编排，thenCombine 合并结果，allOf/anyOf 等待多个任务。支持异常回调 exceptionally/handle。","hints":["默认线程池是什么","thenApply 和 thenApplyAsync 的区别"],"tags":["并发","异步"],"id":1714},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"Stream API 的中间操作和终端操作","content":"请列举 Java Stream API 的常见中间操作和终端操作。","answer":"答案：中间操作：filter、map、flatMap、distinct、sorted、peek、limit/skip（延迟执行）。终端操作：collect、forEach、reduce、count、anyMatch/allMatch/noneMatch、findFirst/findAny（触发执行）。","hints":["中间操作为什么是延迟执行的","parallelStream 的注意事项"],"tags":["函数式","Stream"],"id":1715},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"JVM 垃圾回收器选型","content":"关于 JVM 垃圾回收器，以下说法正确的是？","options":["A) 新生代使用标记-整理算法","B) 老年代使用标记-复制算法","C) CMS 是并行回收器","D) G1 是分代收集器"],"answer":"D) G1 是分代收集器\n\n解析：G1 将堆划分成多个 Region，兼顾新生代和老年代。新生代使用标记-复制算法，老年代使用标记-整理算法。CMS 是并发回收器（非并行），目标是降低停顿时间。\n\n扩展延伸：G1 的设计目标是替代 CMS，支持可预测的停顿时间模型（-XX:MaxGCPauseMillis）。相比 CMS，G1 的优势在于减少了内存碎片且停顿更可预测。推荐阅读《深入理解 Java 虚拟机》第 3 章。","hints":["CMS 和 G1 的核心区别","什么是 Stop-The-World"],"tags":["JVM","GC"],"company":"阿里巴巴","id":1716},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"ThreadPoolExecutor 描述错误的是","content":"以下关于 ThreadPoolExecutor 的描述，错误的是？","options":["A) corePoolSize 是核心线程数","B) 队列满后创建新线程直到 maximumPoolSize","C) 默认拒绝策略是 AbortPolicy","D) keepAliveTime 对核心线程也生效"],"answer":"D) keepAliveTime 对核心线程也生效\n\n解析：keepAliveTime 默认只对超出 corePoolSize 的额外空闲线程生效。核心线程默认一直存活，如需要对核心线程也生效需调用 allowCoreThreadTimeOut(true)。\n\n扩展延伸：线程池处理流程：提交任务 → 核心线程满 → 入队列 → 队列满 → 创建新线程至 maximumPoolSize → 超限则执行拒绝策略。四种拒绝策略：AbortPolicy（默认，抛异常）、CallerRunsPolicy（调用者线程执行）、DiscardPolicy（静默丢弃）、DiscardOldestPolicy（丢弃最旧未处理任务）。","hints":["线程池处理任务的完整流程","四种拒绝策略分别是什么"],"tags":["并发","线程池"],"id":1717},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"Java 并发包同步辅助类","content":"以下哪个属于 java.util.concurrent 包中的同步辅助类？","options":["A) ArrayList","B) CountDownLatch","C) FileReader","D) StringBuffer"],"answer":"B) CountDownLatch\n\n解析：CountDownLatch 是 java.util.concurrent 包中的同步辅助类，允许一个或多个线程等待其他线程完成操作。类似工具还包括 CyclicBarrier（可循环屏障）和 Semaphore（信号量，控制并发数量）。\n\n扩展延伸：CountDownLatch 与 CyclicBarrier 的关键区别：CountDownLatch 是一次性的、一个或多个线程等待其他线程完成；CyclicBarrier 是可循环使用的、多个线程相互等待到达同一屏障点。Semaphore 适用于限流场景，通过 acquire/release 控制许可证数量。","hints":["CountDownLatch 和 CyclicBarrier 的区别","Semaphore 的作用"],"tags":["并发","同步"],"id":1718},{"category":"java_advanced","difficulty":"easy","type":"true_false","title":"Java 泛型运行时类型信息","content":"Java 泛型在运行时可以获取具体的泛型参数类型。","options":["正确","错误"],"answer":"错误\n\n解析：Java 泛型通过类型擦除实现，编译后泛型参数信息被擦除为原始类型（Raw Type），List<String> 和 List<Integer> 运行时是同一个 Class。但可通过反射和 TypeToken 技巧间接获取泛型参数。\n\n扩展延伸：类型擦除的具体过程：编译器将 T 替换为 Object（无界）或上界类型，并插入必要的强制转换。桥方法（Bridge Method）是编译器在子类中生成的合成方法，确保多态正确。推荐阅读《Java 核心技术 卷 I》第 8 章泛型部分。","hints":["类型擦除的具体过程","什么是桥方法"],"tags":["泛型","基础"],"id":1719},{"category":"java_advanced","difficulty":"easy","type":"true_false","title":"ReentrantLock 公平锁","content":"ReentrantLock 支持公平锁和非公平锁两种模式。","options":["正确","错误"],"answer":"正确\n\n解析：ReentrantLock 构造器接受 fair 参数控制模式。公平锁按线程等待时间顺序获取锁，避免饥饿但吞吐量低；非公平锁允许插队（默认），性能更高但极端情况可能导致线程饥饿。\n\n扩展延伸：synchronized 是非公平的，性能与 ReentrantLock 差距已缩小（JDK 6 锁优化）。ReentrantLock 在需要可中断锁、定时锁、公平锁或条件变量（Condition）的场景仍不可替代。推荐阅读《Java 并发编程实战》第 13 章。","hints":["公平锁和非公平锁的性能差异","synchronized 是公平的还是非公平的"],"tags":["并发","锁"],"id":1720},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"ThreadLocal 内存泄漏场景","content":"ThreadLocal 为什么可能导致内存泄漏？使用时应注意什么？","answer":"答案：ThreadLocalMap 的 key 是弱引用（WeakReference），value 是强引用\n\n解析：ThreadLocalMap.Entry 继承 WeakReference，key（ThreadLocal 实例）为弱引用，value 为强引用。当 ThreadLocal 外部强引用被回收后，GC 会回收 key（弱引用），但 value 仍有强引用链（Thread → ThreadLocalMap → Entry → value）。只要线程存活，value 就无法回收，造成内存泄漏。\n\n扩展延伸：最佳实践 1）每次使用后调用 remove() 清除 Entry 2）使用 try-finally 确保 remove 执行 3）线程池场景尤其危险——线程复用会持续累积泄漏。Tomcat、Jetty 等容器经常有大流量经过，ThreadLocal 泄漏可能快速撑满老年代引发 Full GC。","hints":["WeakReference 在 GC 时怎么处理","为什么线程池会放大这个泄漏问题"],"tags":["并发","内存","陷阱"],"company":"阿里巴巴","id":1721},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"线程池异常吞没陷阱","content":"用 ExecutorService.submit() 提交任务，任务中抛出的运行时异常会发生什么？execute() 和 submit() 对异常处理有何区别？","answer":"答案：submit() 会吞没异常，execute() 会抛出异常\n\n解析：submit() 返回 Future，任务异常被封装在 Future.get() 返回的 ExecutionException 中。如果从未调用 Future.get()，异常会被静默吞没。execute() 提交的任务抛异常时，未被捕获的异常会传播到线程池的 uncaughtExceptionHandler，线程销毁并创建新线程替换。\n\n扩展延伸：如何避免 1）调用 Future.get() 捕获异常 2）使用 execute() 提交关键任务 3）设置自定义 UncaughtExceptionHandler 记录日志 4）使用 afterExecute() 钩子（ThreadPoolExecutor 扩展点）。生产中线上问题排查往往因异常被吞没而无从下手，建议所有 submit 的任务都显式处理异常。","hints":["Future.get() 会抛出什么异常","execute 和 submit 内部实现有何不同"],"tags":["并发","线程池","陷阱"],"company":"阿里巴巴,腾讯","id":1722},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"ConcurrentModificationException 场景","content":"在什么情况下会抛出 ConcurrentModificationException？如何在遍历时安全删除集合元素？","answer":"答案：遍历集合时直接调用集合的 remove/add 方法会抛此异常\n\n解析：ArrayList、HashMap 等集合的迭代器采用 fail-fast 机制，内部维护 modCount 计数器。遍历期间若非通过迭代器修改集合（如 list.remove()），modCount 与预期值不符即抛出 ConcurrentModificationException。\n\n扩展延伸：三种安全删除方式 1）使用 Iterator.remove()（单线程安全）2）使用 ConcurrentHashMap/CopyOnWriteArrayList（并发场景）3）使用 Java 8 的 removeIf() 内部已处理迭代器同步。需要注意的是，即使单线程也可能在多处代码间接修改集合时触发此异常。","hints":["迭代器的 fail-fast 机制是什么","CopyOnWriteArrayList 为什么不会抛此异常"],"tags":["并发","集合","陷阱"],"id":1723},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"线上 CPU 100% 排查思路","content":"线上应用突然 CPU 持续 100%，你如何定位根因？请描述完整排查流程。","answer":"答案：top → top -H → jstack → 分析线程栈\n\n解析：1）top 确认 CPU 100% 的进程 PID 2）top -H -p PID 找到 CPU 最高的线程 TID 3）printf '%x\\n' TID 转十六进制 4）jstack PID | grep -A 30 TID_HEX 查看线程栈。常见原因包括：死循环（无锁）、频繁 GC（内存不足/泄漏）、锁竞争激烈（上下文切换开销）、正则表达式回溯过多。\n\n扩展延伸：如果是频繁 GC 导致 CPU 高，重点排查堆内存和 GC 日志。如果是锁竞争，看线程是否大量处于 BLOCKED 状态。如果周期性飙升，可能和大对象分配/定时任务有关。高级工具：Arthas（在线诊断）、async-profiler（火焰图）、VisualVM（离线分析）。","hints":["如何将线程 ID 从十进制转十六进制","jstack 输出的线程状态有哪些含义"],"tags":["JVM","排查","性能"],"id":1724},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"死锁的排查与预防","content":"请描述死锁的四个必要条件，以及如何排查和预防死锁。","answer":"答案：互斥、占有且等待、不可抢占、循环等待\n\n解析：排查死锁步骤 1）jps 找到进程 PID 2）jstack PID 搜索 deadlock 关键字 3）JVM 会在死锁检测中输出线程持有和等待的锁信息。预防策略：统一加锁顺序（最重要的）、使用 tryLock 带超时（Lock API）、缩小锁粒度、使用无锁数据结构。\n\n扩展延伸：实战中数据库死锁比代码死锁更常见——两个事务以不同顺序加行锁导致。从死锁恢复：jstack 检测后可以 kill -3 触发线程转储，或重启进程。长期方案：代码审查中加入锁顺序检查、使用静态分析工具（FindBugs 等）检测违反锁顺序的代码。","hints":["jstack 输出中如何识别死锁","为什么统一加锁顺序可以预防死锁"],"tags":["并发","锁","排查"],"id":1725},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"线上 OOM 排查完整流程","content":"线上服务频繁 OOM，你如何定位内存泄漏的根因？","answer":"答案：配置 OOM dump → 使用 MAT/Eclipse Memory Analyzer 分析\n\n解析：排查流程 1）JVM 启动参数上加 -XX:+HeapDumpOnOutOfMemoryError -XX:HeapDumpPath=/path/dump.hprof 2）服务 OOM 后自动生成 dump 文件 3）用 MAT 打开 dump，查看 Leak Suspects Report（泄漏嫌疑报告）4）查看 Dominator Tree（支配树），按保留堆大小排序找最大对象 5）检查 GC Roots 引用链确定泄漏源头。\n\n扩展延伸：常见泄漏类型 a）集合类泄漏（HashMap key 未移除）b）回调/监听器未注销 c）类加载器泄漏（Tomcat 热部署）d）ThreadLocal 不 remove e）直接内存泄漏（ByteBuffer.allocateDirect 未释放）。建议结合 jstat -gcutil 观察 GC 趋势和内存上涨斜率来预警。","hints":["HeapDumpOnOutOfMemoryError 有什么用","MAT 的 Leak Suspects 和 Dominator Tree 分别看什么"],"tags":["JVM","排查","性能","内存"],"id":1726},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"AQS 的核心实现原理","content":"关于 AbstractQueuedSynchronizer（AQS）的核心实现原理，以下描述正确的是？","options":["A) AQS 使用数组存储等待线程","B) AQS 的核心是一个 volatile int 状态变量和 CLH 双向队列","C) AQS 只支持独占模式","D) AQS 基于自旋锁实现"],"answer":"B) AQS 的核心是一个 volatile int 状态变量和 CLH 双向队列\n\n解析：AQS 维护一个 volatile int state（同步状态）和一个 CLH 双向队列（等待线程队列）。通过 CAS 操作 state，子类通过 tryAcquire/tryRelease 模板方法控制状态变化。支持独占（如 ReentrantLock）和共享（如 Semaphore）两种模式。\n\n扩展延伸：AQS 是 JUC 包的基石，基于它的同步器包括 ReentrantLock（tryAcquire）、Semaphore（tryAcquireShared）、CountDownLatch（tryAcquireShared）、ReentrantReadWriteLock（读写分离）。条件队列（ConditionObject）也是 AQS 的内部实现。","hints":["ReentrantLock 和 Semaphore 在 AQS 上的实现差异","CLH 队列和条件队列的关系"],"tags":["并发","AQS"],"id":1727},{"category":"java_advanced","difficulty":"easy","type":"true_false","title":"虚拟线程与平台线程的关系","content":"JDK 21 的虚拟线程（Virtual Threads）旨在完全替代平台线程（Platform Threads）。","options":["正确","错误"],"answer":"错误\n\n解析：虚拟线程是 JDK 实现的用户态线程（纤程），挂载在平台线程上执行，不是替代关系。适用 IO 密集型任务（大量阻塞等待），不适用 CPU 密集型任务。虚拟线程的优势在于可以创建数百万级别，但同步锁（synchronized）内会 pin 住载体线程，建议改用 ReentrantLock。\n\n扩展延伸：虚拟线程底层通过 Continuation 实现 yield 和 resume，遇到阻塞操作时自动从载体线程卸载。使用时注意：synchronized 块内虚拟线程不会卸载，大量 synchronized 会降低虚拟线程的优势。推荐阅读 JEP 444。","hints":["虚拟线程和操作系统线程的映射关系","什么场景下虚拟线程性能不如平台线程"],"tags":["并发","虚拟线程"],"company":"腾讯","id":1728},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"CAS 操作的 ABA 问题","content":"CAS 操作中的 ABA 问题是指什么？以下哪种方式可以解决？","options":["A) 值从 A 变 B 又变回 A，CAS 误认为未修改过","B) 值从未变化过但 CAS 失败","C) 使用 synchronized 代替 CAS","D) 增大自旋次数"],"answer":"A) 值从 A 变 B 又变回 A，CAS 误认为未修改过\n\n解析：ABA 问题的本质是 CAS 只检查值是否和预期相同，不关心中间是否修改过。在指针复用场景中特别危险（如栈操作时，A→B→A 的指针可能指向已被回收的对象）。\n\n扩展延伸：解决方案 1）AtomicStampedReference（带版本号的原子引用，每次修改更新 stamp）2）AtomicMarkableReference（带布尔标记）3）使用传统的锁。Java 的 ConcurrentLinkedDeque 等无锁数据结构内部已处理了 ABA 问题。","hints":["AtomicStampedReference 和 AtomicReference 的区别","为什么说 ABA 问题对数值操作通常无害"],"tags":["并发","CAS"],"id":1729},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"锁升级过程（偏向锁→轻量级锁→重量级锁）","content":"请描述 synchronized 在 HotSpot JVM 中的锁升级过程，包括偏向锁、轻量级锁、重量级锁的触发条件和切换机制。","answer":"答案：无锁 → 偏向锁 → 轻量级锁 → 重量级锁（单向升级，不可降级）\n\n解析：偏向锁：第一个获取锁的线程将对象头 Mark Word 设为偏向模式，记录线程 ID，后续该线程再次获取无需同步操作。轻量级锁：有另一个线程竞争时，偏向锁撤销，升级为轻量级锁（自旋获取）。重量级锁：自旋超过阈值或等待线程数过多，膨胀为重量级锁，未获取到的线程阻塞进入等待队列。\n\n扩展延伸：JDK 15 起默认禁用偏向锁（JEP 374），因为偏向锁的撤销在高并发场景下成本较高（需要在全局安全点执行）。自适应自旋（JDK 6 引入）让 JVM 根据上次自旋结果动态调整自旋次数。","hints":["JDK 15 为什么默认禁用了偏向锁","轻量级锁自旋失败会立即升级吗"],"tags":["并发","锁","JVM"],"id":1730},{"category":"java_advanced","difficulty":"medium","type":"short_answer","title":"JMM 与 happens-before 原则","content":"请解释 Java 内存模型（JMM）中的 happens-before 原则，列举常见的 happens-before 规则。","answer":"答案：happens-before 确保前一个操作的结果对后续操作可见\n\n解析：JMM 是抽象的内存模型，定义了多线程环境下共享变量的可见性规则。happens-before 原则用于判断数据是否存在竞争，无需关心具体的重排序和内存屏障实现细节。\n\n扩展延伸：八条 happens-before 规则 1）程序次序规则—同一线程前一个操作 happens-before 后一个 2）volatile 规则—volatile 变量的写 happens-before 读 3）锁规则—解锁 happens-before 加锁 4）传递性—A happens-before B, B happens-before C ⇒ A happens-before C 5）线程 start 规则—start() happens-before 该线程任何动作 6）线程 join 规则—线程的所有操作 happens-before join() 返回 7）中断规则—interrupt() happens-before 检测到中断 8）对象终结规则—构造函数结束 happens-before finalize()。","hints":["volatile 写和读的 happens-before 关系","传递性如何推导出对某个字段的可见性保证"],"tags":["并发","JMM"],"id":1731},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"安全点（Safepoint）是什么","content":"请解释 JVM 中的安全点（Safepoint）是什么，它有什么作用？哪些场景会触发全局安全点？","answer":"答案：Safepoint 是所有线程都到达的一个安全状态点，JVM 在此可以执行全局操作\n\n解析：JVM 需要所有线程到达 Safepoint 才能执行 STW 操作。线程在 Safepoint 时栈状态是确定的，可以安全地进行 GC、偏向锁撤销、类重定义等操作。线程通过主动轮询检查 Safepoint 标志来进入 Safepoint。\n\n扩展延伸：触发全局 Safepoint 的场景：1）GC 停顿（最常见）2）偏向锁撤销 3）JIT 编译优化 4）线程堆栈 dump。Safepoint 导致的长时间停顿问题：循环中没有 Safepoint 轮询点（如大数组遍历）导致线程迟迟无法进入。JVM 参数 -XX:+PrintSafepointStatistics 可打印 Safepoint 日志。","hints":["循环中有没有 Safepoint 轮询点的影响","长时间 STW 的常见原因有哪些"],"tags":["JVM","性能"],"id":1732},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"Record 类（JDK 16）","content":"请介绍 Java 14 预览、JDK 16 正式发布的 Record 类型。它和普通类有什么区别？","answer":"答案：Record 是用于创建不可变数据载体的特殊类，自动生成构造器、getter、equals/hashCode/toString\n\n解析：声明 record Point(int x, int y) {} 等效于一个包含 private final 字段、全参构造器、x()/y() 访问方法（不是 getX()）、equals/hashCode/toString 的普通类。Record 是 final 类，不能继承也不能被继承，所有字段隐式为 final。\n\n扩展延伸：Record 的优势 1）极大简化 POJO/DTO 的编写 2）自动提供的 equals/hashCode 基于所有字段（按值比较而非引用）3）构造器可做验证：Record Point { Point { if (x < 0) throw new IllegalArgumentException(); } }。不适合场景：需要 JPA/Hibernate 代理的实体类、需要继承的类。推荐阅读 JEP 395。","hints":["Record 和 Lombok @Data 的区别","Record 的访问方法为什么是字段名而不是 getX()"],"tags":["基础","JDK 新特性"],"id":1733},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"ForkJoinPool 的描述","content":"关于 ForkJoinPool 框架，以下描述正确的是？","options":["A) ForkJoinPool 使用单线程处理所有任务","B) 工作窃取（Work-Stealing）是 ForkJoinPool 的核心机制","C) ForkJoinPool 的任务队列是全局统一的","D) ForkJoinPool 只能用于递归任务"],"answer":"B) 工作窃取（Work-Stealing）是 ForkJoinPool 的核心机制\n\n解析：ForkJoinPool 采用工作窃取算法：每个工作线程维护自己的双端任务队列，完成自己队列任务后从其他线程队列尾部「窃取」任务执行。这充分利用多核 CPU，减少线程竞争。\n\n扩展延伸：ForkJoinPool.commonPool() 是全局共享实例（默认并行度 = CPU 核心数 - 1）。Java 8 的 parallelStream 默认使用 commonPool。但 I/O 密集型任务不应使用 parallelStream（会阻塞公共池线程）。","hints":["工作窃取算法为什么从队列尾部窃取","parallelStream 使用的什么线程池"],"tags":["并发","ForkJoinPool"],"id":1734},{"category":"java_advanced","difficulty":"medium","type":"short_answer","title":"JVM 调优方法论与核心原则","content":"JVM 调优应该遵循什么方法论？什么时候需要调优？调优的核心原则是什么？","answer":"答案：JVM 调优应遵循「问题驱动」原则：先明确症状（GC 频繁/响应抖动/OOM）→ 诊断定位（工具分析）→ 针对性调参 → 验证效果。核心是理解 JVM 的工作原理，而不是死记参数。\n\n解析：调优的前提是明确「为什么需要调优」。常见症状：1）GC 频繁——Young GC 每秒多次或 Full GC 频繁触发。2）响应抖动（Pause）——GC 停顿导致请求延迟突增。3）内存泄漏/OOM——堆内存持续增长无法回收。4）CPU 高但业务 QPS 低——GC 线程或编译线程占 CPU。\n\n诊断工具选型：1）快速排查——jstat -gcutil PID 1000 看 GC 频率和耗时。2）线程问题——jstack 看死锁/卡顿。3）堆分析——jmap -histo 看对象分布，OOM 时 Heap Dump + MAT 分析 Dominator Tree。4）在线诊断——Arthas watch/trace 实时观测方法级调用。5）GC 日志——开启 GC 日志（JDK 8: -Xloggc:gc.log -XX:+PrintGCDetails -XX:+PrintGCDateStamps；JDK 9+: -Xlog:gc*:file=gc.log），用 GCeasy 在线分析。\n\n扩展延伸：常见调优场景及思路：1）吞吐量优先（批处理/离线计算）→ Parallel Scavenger + Parallel Old，堆设大些减少 GC 次数。2）低延迟优先（在线服务/API）→ G1/ZGC，控制 MaxGCPauseMillis。3）内存占用优先（资源受限）→ 合理设 Xmx，避免内存泄漏。4）容器化环境注意 -Xmx 不能超过容器内存限制，UseContainerSupport（JDK 8u191+ 默认开启）。\n\n黄金原则：不要为了调优而调优——先确认问题，再针对性调参。调优后用 GC 日志验证效果，持续监控。理解 JVM 的内存模型和 GC 算法比记忆具体参数重要得多。","hints":["调优前如何确认 JVM 是否真的需要调优","容器化环境中 JVM 参数配置需要注意什么"],"tags":["JVM","调优","方法论","GC"],"company":"","id":1735},{"category":"java_advanced","difficulty":"easy","type":"true_false","title":"String.intern() 与常量池","content":"String.intern() 方法会将字符串放入运行时常量池，并返回常量池中的引用。","options":["正确","错误"],"answer":"正确\n\n解析：intern() 方法检查字符串常量池中是否存在 equals 相等的字符串，存在则返回常量池中的引用，不存在则在常量池中创建并返回引用。JDK 7 之前常量池在方法区（永久代），JDK 7 起常量池移到了堆中。\n\n扩展延伸：大量重复字符串场景下 intern() 可显著节省内存（如数据库查询返回的相同状态码）。但滥用 intern() 会导致常量池膨胀。String 字面量（如 \"hello\"）自动执行 intern 行为，new String(\"hello\") 会创建两个对象：堆中的 String 对象和常量池中的字面量。","hints":["new String(\"hello\") 创建了几个对象","JDK 6 和 JDK 7+ 的 intern() 行为有何不同"],"tags":["基础","JVM","String"],"id":1736},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"HashMap 线程不安全的表现","content":"为什么 HashMap 是线程不安全的？多线程环境下使用 HashMap 会出现哪些问题？","answer":"答案：死循环（JDK 7）、数据覆盖、modCount 不一致\n\n解析：JDK 7 中 put 触发扩容时（transfer 方法），头插法在多线程并发 resize 下可能形成环形链表，导致 get 时死循环（CPU 100%）。数据覆盖：两个线程同时 put，后写入覆盖前写入。modCount 不一致：迭代时其他线程修改结构，触发 fail-fast 抛 ConcurrentModificationException。\n\n扩展延伸：JDK 8 改用尾插法修复了死循环问题，但仍有数据覆盖和 ConcurrentModificationException 问题。线程安全替代方案：ConcurrentHashMap（分段锁/CAS + synchronized）、Collections.synchronizedMap（全表锁）、Hashtable（全表锁）。","hints":["JDK 7 的头插法为什么会导致死循环","JDK 8 为什么改为尾插法"],"tags":["集合","HashMap","并发"],"company":"阿里巴巴,腾讯","id":1737},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"HashMap 长度为什么是 2 的幂次方","content":"HashMap 要求初始容量是 2 的幂次方，主要原因是什么？","options":["A) 减少哈希碰撞概率","B) 可以用位运算 (n - 1) & hash 替代取模提高性能","C) 节省内存空间","D) 方便扩容时重新哈希"],"answer":"B) 可以用位运算 (n - 1) & hash 替代取模提高性能\n\n解析：HashMap 用 (n - 1) & hash 计算桶位置，等价于 hash % n 但位运算更快。这要求 n 是 2 的幂次方，此时 (n-1) 的二进制是全 1，与 hash 做 & 运算能充分利用 hash 值的低位，分布均匀。\n\n扩展延伸：如果指定容量不是 2 的幂，HashMap 会通过 tableSizeFor() 方法向上取整到最近的 2 的幂（通过多次无符号右移和或运算实现）。扩容时重新计算位置：元素在新数组中的位置要么在原位置，要么在原位置 + 旧容量，这得益于容量始终是 2 的幂。","hints":["位运算 (n - 1) & hash 和 hash % n 等价的条件","扩容时元素位置为什么要么不变要么偏移旧容量"],"tags":["集合","HashMap"],"company":"阿里巴巴","id":1738},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"ConcurrentHashMap 复合操作原子性","content":"关于 ConcurrentHashMap 的原子性，以下说法正确的是？","options":["A) 所有操作都是原子性的","B) putIfAbsent() 是原子操作，但先 get 再 put 不是","C) 遍历时不会抛 ConcurrentModificationException","D) 多线程 put 一定互相覆盖"],"answer":"B) putIfAbsent() 是原子操作，但先 get 再 put 不是\n\n解析：ConcurrentHashMap 的单个方法（put、get、putIfAbsent、replace）是线程安全的原子操作。但组合操作如 if (!map.containsKey(key)) { map.put(key, value); } 不是原子性的，两个线程可能同时通过检查并 put。\n\n扩展延伸：ConcurrentHashMap 提供的原子复合方法：putIfAbsent(key, val)（不存在才 put）、compute(key, (k, v) -> ...)（原子更新）、merge(key, val, (old, new) -> ...)（原子合并）。这些方法内部用 CAS + synchronized 保证原子性。推荐使用这些原子方法替代手动组合的 get-then-put 模式。","hints":["compute() 和 putIfAbsent() 为什么是原子的","先判断 containsKey 再 put 有什么问题"],"tags":["并发","集合","ConcurrentHashMap"],"company":"阿里巴巴","id":1739},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"Java 语法糖","content":"什么是 Java 语法糖？列举 Java 中常见的语法糖及其底层实现。","answer":"答案：语法糖是编译器提供的便捷语法，本质由编译器 desugar 为底层代码\n\n解析：泛型——编译时擦除为强制转换和 Object 操作。自动拆装箱——编译为 Integer.valueOf() 和 intValue()。for-each 循环——编译为 Iterator 迭代（数组为 fori）。枚举（enum）——编译为继承 Enum 的 final 类。变长参数——编译为数组参数。try-with-resources——编译为 try-finally + close 调用。switch 支持 String——编译为 hashCode + equals。\n\n扩展延伸：语法糖在编译阶段（javac）解析，生成的字节码与手写底层代码等价。反编译工具（如 jad、CFR）可查看 desugar 后的代码。理解语法糖有助于避免陷阱——如 for-each 在遍历时 remove 会抛 ConcurrentModificationException，因为底层仍是 Iterator。","hints":["for-each 在遍历删除时会怎样","枚举在字节码层面是什么样的"],"tags":["基础","语法糖"],"id":1740},{"category":"java_advanced","difficulty":"medium","type":"short_answer","title":"动态代理原理","content":"请解释 JDK 动态代理和 CGLIB 动态代理的实现原理和区别。Spring AOP 默认使用哪种？","answer":"答案：JDK 动态代理基于接口实现：通过 Proxy.newProxyInstance() 创建代理类，代理类实现了目标接口并在 InvocationHandler.invoke() 中执行增强逻辑。代理类继承 java.lang.reflect.Proxy。\n\nCGLIB 动态代理基于继承实现：通过 ASM 字节码技术生成目标类的子类（代理类），在子类中重写父类方法并织入增强逻辑。\n\n区别：1）JDK 代理只能代理接口，CGLIB 可以代理普通类；2）JDK 代理使用 Java 反射 API，CGLIB 使用 ASM 直接操作字节码；3）CGLIB 不能代理 final 类和方法；4）CGLIB 性能更好（生成代理类后调用时无需反射）。\n\nSpring AOP 默认策略：如果 Bean 实现了接口，使用 JDK 动态代理；如果 Bean 没有实现接口，使用 CGLIB 代理。可以通过 @EnableAspectJAutoProxy(proxyTargetClass=true) 强制使用 CGLIB。\n\n扩展延伸：Spring Boot 2.0+ 默认将 proxy-target-class 设为 true（总是使用 CGLIB），即使 Bean 实现了接口。这是因为 JDK 代理的类转换限制（只能转换到接口类型）在实际开发中容易引发 ClassCastException。","hints":["JDK 代理基于接口，CGLIB 基于继承","Spring Boot 2.0+ 默认使用 CGLIB"],"tags":["Java","动态代理","AOP","Spring"],"id":1741},{"category":"java_advanced","difficulty":"medium","type":"short_answer","title":"反射性能优化","content":"Java 反射的性能开销主要来自哪里？有哪些优化反射性能的方法？","answer":"答案：反射的性能开销主要来自：\n1. 方法查找：Class.getMethod() 需要遍历类的所有 public 方法，时间复杂度 O(N)。\n2. 安全检查：每次 invoke() 都会进行访问权限校验（AccessibleObject 的 checkAccess）。\n3. 参数装箱/拆箱：反射调用时参数需要包装为 Object[]。\n4. JIT 无法内联：反射调用点无法被 JIT 编译器正常内联优化。\n5. 类型检查：每次调用检查方法签名和参数类型是否匹配。\n\n优化方法：\n1. 缓存 Method 对象：将 getMethod() 结果缓存到 Map 中，避免重复查找。\n2. setAccessible(true)：跳过安全检查，显著加速（可以提升 2-3 倍）。\n3. MethodHandles（Java 7+）：比反射更轻量，JIT 可以内联。\n4. LambdaMetafactory（Java 8+）：生成函数式接口实现，调用性能接近直接调用。\n5. 编译期处理（APT）：在编译期生成代码，零运行期开销（如 MapStruct、Lombok）。\n\n扩展延伸：Spring 5 和 Spring Boot 内部大量使用 MethodHandles 替代传统反射（如 GenericTypeResolver）。LambdaMetafactory 可以将任意方法转换为函数式接口，调用性能比反射高 10 倍以上。","hints":["setAccessible(true) 跳过安全检查是最直接的优化","MethodHandles 和 LambdaMetafactory 是反射的现代替代品"],"tags":["Java","反射","性能优化","MethodHandles"],"id":1742},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"Synchronized 锁优化","content":"请解释 Java 中 synchronized 关键字的锁升级过程（偏向锁→轻量级锁→重量级锁），以及 JDK 15+ 的变动。","answer":"答案：synchronized 通过对象头中的 Mark Word 实现锁状态存储，锁升级是单向不可逆的：\n\n1. 偏向锁（Biased Locking）：线程首次获得锁时，Mark Word 记录线程 ID。后续该线程进入同步块时无需 CAS 操作。适用于锁大部分时间被同一个线程持有的场景。\n2. 轻量级锁（Lightweight Lock）：当另一个线程竞争偏向锁时，偏向锁撤销并升级为轻量级锁。线程通过 CAS 在 Mark Word 中记录 Lock Record 地址。适用于少量线程交替获取锁的场景。\n3. 重量级锁（Heavyweight Lock / Mutex Lock）：当 CAS 失败或线程自旋超过阈值（默认 10 次），锁膨胀为重量级锁。线程阻塞，由操作系统管调度，涉及用户态到内核态的切换。\n\nJDK 15+ 的变动：JDK 15 默认禁用了偏向锁（通过 -XX:-UseBiasedLocking）。因为偏向锁的撤销（尤其是遇到批量重偏向和高并发场景时）在高版本 JDK 中的维护成本超过了收益。JDK 21 彻底移除了偏向锁实现。\n\n扩展延伸：synchronized 锁升级的优化思路是尽量在无竞争或低竞争场景下使用轻量级机制（偏向/CAS），只有在高竞争时才使用重量级互斥量。锁粗化（Lock Coarsening）和锁消除（Lock Elimination）是 JIT 编译器做的额外优化。","hints":["锁升级方向：偏向锁→轻量级锁→重量级锁，单向不可逆","JDK 15+ 禁用了偏向锁"],"tags":["Java","synchronized","锁优化","并发"],"id":1743},{"category":"java_advanced","difficulty":"medium","type":"short_answer","title":"Fork/Join 框架","content":"请解释 Java 7 引入的 Fork/Join 框架的核心原理和适用场景。工作窃取（Work-Stealing）算法是如何工作的？","answer":"答案：Fork/Join 框架将大任务递归分解（Fork）为小任务并行执行，再合并（Join）结果。核心类：ForkJoinPool（线程池）、ForkJoinTask（任务抽象类）、RecursiveTask（有返回值）/RecursiveAction（无返回值）。\n\n工作窃取（Work-Stealing）算法：每个工作线程维护一个双端队列（Deque），自己从队头拿任务执行。当线程的队列为空时，从其他线程队列的队尾窃取（Steal）任务执行。\n\n优势：1）自动负载均衡——空闲线程帮忙繁忙线程；2）减少了线程间的竞争（窃取从队尾取，正常执行从队头）；3）适合递归分解的分治算法。\n\n适用场景：1）数值计算和科学计算（数组求和、矩阵乘法）；2）排序和搜索（快速排序、二分查找的并行版本）；3）大规模数据处理；4）递归算法（树的遍历和计算）。\n\n扩展延伸：ForkJoinPool.commonPool() 是 JVM 提供的全局 ForkJoinPool（默认 size = CPU 核数 - 1），CompletableFuture 的并行执行也使用这个线程池。Fork/Join 的拆分粒度很重要——任务太小会导致任务创建和调度的开销大于计算本身，一般经验是阈值为 100-10000 个元素。","hints":["Fork/Join 的核心设计是工作窃取算法","拆分粒度太细反而降低性能"],"tags":["Java","Fork/Join","并行","Work-Stealing"],"id":1744},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"try-with-resources","content":"请解释 Java 7 引入的 try-with-resources 语句的原理和优势。哪些类可以使用 try-with-resources？","answer":"答案：try-with-resources 是自动资源管理的语法糖，确保实现了 AutoCloseable 接口的资源在使用完毕后自动调用 close() 方法。\n\n原理：编译器将 try-with-resources 编译为 try-finally 块，在 finally 中按资源声明顺序的逆序关闭资源。如果 try 块和 close() 都抛出了异常，close() 的异常会被抑制（Suppressed）并附加到 try 块的异常上。\n\n哪些类可以使用：所有实现了 java.lang.AutoCloseable 接口的类。常见包括：java.io.InputStream/OutputStream（文件流）、java.sql.Connection/Statement/ResultSet（数据库连接）、java.io.Reader/Writer。AutoCloseable 是 Closeable 的父接口，区别在于 Closeable.close() 声明抛出 IOException 且要求幂等。\n\n优势：1）代码简洁——不用手动在 finally 中写 close()；2）异常处理更完善——不会因为 close() 的异常覆盖掉业务异常；3）防止资源泄漏——即使 try 块异常退出资源也会被关闭。\n\n扩展延伸：Java 9 允许在 try-with-resources 中使用 effectively final 的外部变量（try (conn; stmt) 格式）。可以自定义实现 AutoCloseable 接口来管理非 I/O 资源（如 Redis 连接、Netty Channel）。getSuppressed() 方法可以获取被抑制的异常数组。","hints":["try-with-resources 确保 AutoCloseable 资源自动关闭","关闭异常被抑制（Suppressed）而非覆盖业务异常"],"tags":["Java","try-with-resources","异常","最佳实践"],"id":1745},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"Java 模块化系统（JPMS）","content":"请介绍 Java 9 引入的模块化系统（JPMS）的核心概念和优势。模块化对现有代码有何影响？","answer":"答案：JPMS（Java Platform Module System）通过 module-info.java 定义模块，实现强封装和显式依赖。\n\n解析：模块声明通过 module 关键字定义，exports 导出包给其他模块，requires 声明对其他模块的依赖，opens 允许反射访问。模块化解决了长期以来 JAR 地狱（类路径冲突）和内部 API 无限制访问的问题。未命名模块（unnamed module）中的代码可以访问类路径上的所有 JAR，但命名模块不能访问未命名模块中的类。\n\n扩展延伸：影响 1）JDK 内部 API 被封裝——sun.misc.Unsafe 等需要通过 --add-opens 才能反射访问。2）Spring Boot 2.x 和 3.x 对 JPMS 的支持情况——Spring 5 通过自动模块支持 JPMS。3）迁移策略：先加 module-info.java 到模块路径测试，逐步将类路径迁移到模块路径。4）jlink 工具——基于模块化的自定义 JRE 构建工具，可以生成仅包含所需模块的最小运行时镜像。","hints":["module-info.java 中的 exports/requires/opens 分别控制什么","自动模块和未命名模块的区别"],"tags":["Java","JPMS","模块化","JDK 新特性"],"id":1746},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"密封类（Sealed Class）","content":"请介绍 Java 17 正式发布的密封类（Sealed Class）的作用和用法。它与 final 类有什么区别？","answer":"答案：密封类通过 sealed 关键字限制哪些类或接口可以继承或实现它，提供比访问修饰符更精细的继承控制。\n\n解析：声明语法：sealed class Shape permits Circle, Rectangle, Triangle { }。子类必须使用 final（禁止继续继承）、sealed（继续限制子类）或 non-sealed（开放继承）之一来声明。密封类结合 switch 模式匹配（Java 17+ 预览，Java 21 正式）可以实现穷举检查——编译器确保 switch 覆盖了所有允许的子类型，无需 default 分支。\n\n扩展延伸：密封类在领域驱动设计中的应用——精确建模有限子类型（如支付方式、订单状态）。密封接口（sealed interface）同样支持。与 final 的区别：final 完全禁止继承；密封类允许有限的、可控的继承。框架开发者可以用密封类限制用户只能扩展特定子类。","hints":["密封类的三种子类声明方式：final/sealed/non-sealed","密封类与 switch 模式匹配的结合"],"tags":["Java","密封类","sealed-class","JDK 17"],"id":1747},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"ZGC 垃圾回收器","content":"请介绍 ZGC（Z Garbage Collector）的设计目标和核心原理。ZGC 如何做到几乎无停顿？","answer":"答案：ZGC 是 JDK 11 引入的实验性低延迟垃圾回收器（JDK 15 正式），目标是将 GC 停顿时间控制在 10ms 以内，且停顿时间不随堆大小增长。\n\n解析：核心设计 1）染色指针（Colored Pointer）——对象头中 64 位地址的高 4 位（42-45 bit）存储元数据状态（Finalizable/Remapped/Marked0/Marked1），不需要对象头额外字段。2）读屏障（Load Barrier）——读对象引用时，如果指针状态标记显示需要修正，读屏障会立即修复指针引用到正确地址。3）并发回收——几乎全部阶段（标记、转移、重映射）都是并发的，仅初始标记和最终标记有极短暂的 STW。4）Region 化——堆分为大小 Region（小 2MB、中 32MB、大 N*2MB），动态管理。\n\n扩展延伸：与 Shenandoah 的区别——ZGC 用染色指针实现并发标记和转移；Shenandoah 用 Brooks 转发指针（读/写屏障）。ZGC 在 JDK 16+ 支持了并发栈处理（Concurrent Thread Stack Processing），进一步减少 STW 时间。ZGC 当前不支持分代收集（JDK 21 引入分代 ZGC 实验特性），这意味着如果对象存活率高，全堆遍历还是可能带来一些性能开销。推荐使用参数 -XX:+UseZGC。","hints":["染色指针和读屏障是 ZGC 的核心技术","ZGC 的 STW 阶段有哪些"],"tags":["JVM","ZGC","GC","低延迟"],"id":1748},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"Shenandoah GC","content":"请介绍 Shenandoah GC 的核心设计。它和 ZGC 的异同是什么？","answer":"答案：Shenandoah 是 JDK 12 引入的低延迟 GC（JDK 15 转正），通过 Brooks 转发指针和读/写屏障实现并发转移，目标也是降低停顿时间。\n\n解析：Shenandoah 的核心机制是 Brooks Pointer——对象头部新增一个转发指针字段。当对象被转移后，原对象的转发指针指向新对象。读屏障检查被访问对象的转发指针，如果被转移则跟随转发指针获取新对象。转移过程是并发的，不需要 STW 来移动对象。\n\n与 ZGC 的异同：同——都是几乎全并发的低延迟 GC，目标停顿时间 < 10ms。异 1）实现方式：ZGC 使用染色指针（读屏障检查指针标记位），Shenandoah 使用 Brooks 转发指针（对象头额外字段 + 读/写屏障）。2）堆内存：ZGC 需要额外地址空间做染色指针预留；Shenandoah 没有染色指针开销。3）ZGC 在 JDK 21 前不支持分代，Shenandoah 在 JDK 17+ 支持分代模式（-XX:+UseShenandoahGC -XX:ShenandoahGCMode=generational）。4）Shenandoah 的写屏障开销略高。\n\n扩展延伸：Shenandoah 从 JDK 18 开始被包含在 Oracle OpenJDK 中（之前仅在 Red Hat 构建的 OpenJDK 中）。使用参数 -XX:+UseShenandoahGC。","hints":["Brooks 转发指针的工作原理","为什么 Shenandoah 需要写屏障而 ZGC 不需要"],"tags":["JVM","Shenandoah","GC","低延迟"],"id":1749},{"category":"java_advanced","difficulty":"medium","type":"short_answer","title":"Lambda 表达式的底层实现","content":"请解释 Java Lambda 表达式在字节码层面的实现原理。它与匿名内部类有何不同？","answer":"答案：Lambda 表达式通过 invokedynamic 指令在运行时动态生成函数式接口实现，而不是编译为匿名内部类。\n\n解析：编译器将 Lambda 表达式编译为 invokedynamic 指令 + 引导方法（Bootstrap Method）。引导方法调用 LambdaMetafactory.metafactory()，在运行时通过 ASM 生成函数式接口的实现类。生成的类实现了函数式接口的抽象方法，方法体指向 Lambda 表达式体。核心优势 1）没有匿名内部类文件（减少类加载开销和 Metaspace 占用）。2）invokedynamic 链接后的调用点可以像普通方法调用一样被 JIT 内联。3）捕获的变量直接作为方法参数传入生成的实现方法，无需生成额外的实例字段。\n\n扩展延伸：性能对比——匿名内部类每次创建都生成新的 .class 文件，首次使用需要类加载验证准备初始化，Lambda 的 invokedynamic 只在首次调用时执行引导方法，后续调用直接调用已链接的方法句柄（方法句柄可以更容易被 JIT 内联）。序列化——Lambda 表达式不推荐序列化（其实现类是运行时生成的，序列化形式依赖于具体的 JVM 实现）。调试——Lambda 的栈跟踪信息在早期 JDK 8 中较模糊，JDK 8u20+ 通过 -Dlambda.formalized.parameters=true 改善了这个问题。","hints":["invokedynamic 指令和 LambdaMetafactory 的作用","为什么 Lambda 比匿名内部类性能更好"],"tags":["Java","Lambda","invokedynamic","JVM"],"id":1750},{"category":"java_advanced","difficulty":"medium","type":"short_answer","title":"Java 代理的三种实现方式对比","content":"请比较 JDK 动态代理、CGLIB 和字节码增强（Javaassist/ASM）三种代理实现方式的优劣。","answer":"答案：三种代理方式各有优劣：JDK 动态代理基于接口、CGLIB 基于继承子类、字节码增强直接操作字节码。\n\n解析：1）JDK 动态代理——通过 Proxy.newProxyInstance() 创建，基于 InvocationHandler 反射调用。优点是 JDK 原生支持，不需要额外依赖；缺点是被代理类必须实现接口。2）CGLIB——通过 ASM 生成子类字节码，覆盖父类方法。优点是不需要接口，可以代理普通类；缺点是不能代理 final 类/final 方法，且需依赖 CGLIB 库。3）字节码增强（ASM/Javaassist/ByteBuddy）——直接操作字节码，可以生成任意结构的类。优点是灵活性最高，可以完全控制生成的字节码；缺点是学习成本高，容易出错。\n\n扩展延伸：Spring AOP 默认策略——Spring Boot 2.0+ 强制使用 CGLIB（proxy-target-class=true），即使 Bean 实现了接口。性能对比——JDK 动态代理和 CGLIB 在 JDK 8+ 后性能接近。ByteBuddy 是 CGLIB 的现代替代品，被 Hibernate、Mockito 等广泛使用。实际应用中代理创建的开销通常远小于代理调用的优化收益，不应过度关注微基准测试中的差异。","hints":["JDK 动态代理要求目标类实现接口","Spring Boot 2.0+ 默认使用 CGLIB 而非 JDK 动态代理"],"tags":["Java","代理","CGLIB","AOP","字节码"],"id":1751},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"Java 内存泄漏的 8 种典型场景","content":"请列举 Java 中 8 种典型的内存泄漏场景，以及如何检测和预防。","answer":"答案：8 种典型内存泄漏场景：1）静态集合类持有对象引用 2）未关闭的资源 3）ThreadLocal 未调用 remove 4）内部类持有外部类引用 5）equals 和 hashCode 不一致 6）String.intern() 滥用 7）类加载器泄漏 8）回调/监听器未注销。\n\n解析：1）静态集合——static List 持有对象，导致对象无法被 GC。2）未关闭资源——InputStream/Connection 未关闭导致堆外内存泄漏。3）ThreadLocal——线程池中线程复用，弱引用 Key 被回收后 Value 仍存活。4）非静态内部类——持有外部类强引用，外部类无法回收。5）equals/hashCode 不一致——HashMap key 无法被访问。6）intern() 滥用——字符串常量池膨胀。7）类加载器泄漏——Tomcat 热部署时 PermGen/Metaspace 上涨。8）监听器/回调——注册后未反注册。\n\n扩展延伸：检测工具——MAT 的 Leak Suspects Report、Dominator Tree 分析、OQL 查询；JProfiler 的堆遍历器；Eclipse Memory Analyzer 的 GC Root 链分析。预防方法——代码审查中加入资源管理检查、使用 try-with-resources、ThreadLocal 用后 remove()、静态内部类代替非静态内部类、使用弱引用或虚引用管理回调。","hints":["ThreadLocal 在线程池中造成的泄漏最隐蔽","类加载器泄漏在 Tomcat 热部署时最明显"],"tags":["JVM","内存泄漏","排查","性能"],"id":1752},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"Java 值类型与引用类型的本质区别","content":"请解释 Java 中值类型（基本类型）和引用类型的本质区别，包括存储方式、传递方式和 GC 行为。","answer":"答案：基本类型直接存储值在栈上，引用类型存储对象地址在栈上、对象数据在堆上。\n\n解析：存储方式——基本类型变量直接包含值（如 int a = 10 在栈帧中直接存 10）；引用类型变量存储对象在堆中的地址（如 String s = \"hello\" 在栈中存地址，堆中存对象数据）。传递方式——都是值传递：基本类型传递值的副本；引用类型传递引用的副本（地址的副本），所以修改引用指向不影响外部变量，但修改引用指向的对象内部会影响。GC 行为——基本类型随栈帧弹出自动销毁；引用类型的对象由 GC 管理，当没有引用指向时被回收。\n\n扩展延伸：JDK 24 的 Valhalla 项目计划引入值类型（Value Type / Primitive Class），将不可变的对象实例直接内联到栈上或对象字段中（无需通过指针间接访问），大幅减少内存占用和缓存未命中。","hints":["基本类型和引用类型在方法参数传递时的行为差异","Valhalla 项目的值类型计划在未来如何改变这一点"],"tags":["Java","基础","值类型","引用类型"],"id":1753},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"GC 日志分析与调优实践","content":"如何通过 GC 日志分析 JVM 内存健康状况？关键指标有哪些？如何基于日志进行调优决策？","answer":"答案：通过 GC 日志分析 Young GC 和 Full GC 频率、单次耗时、堆内存变化趋势来诊断内存问题。\n\n解析：开启 GC 日志——JDK 8：-Xloggc:gc.log -XX:+PrintGCDetails -XX:+PrintGCDateStamps -XX:+PrintGCTimeStamps；JDK 9+：-Xlog:gc*:file=gc.log:time,uptime,level,tags。关键指标：1）Young GC 频率——每秒/每几分钟一次。过高说明新生代过小或分配速率过高。2）Young GC 耗时——正常 < 100ms，过高说明存活对象多（晋升多）。3）Full GC 频率——最好为 0，Full GC 间隔短说明老年代空间不足或存在内存泄漏。4）GC 暂停总时间——GC 耗时占总运行时间的比例（吞吐量损耗）。5）晋升（Promotion）大小——每次 Young GC 升到老年代的对象大小。6）堆使用趋势——持续上涨不回落说明泄漏。\n\n扩展延伸：调优决策——1）Young GC 太频繁（< 1 秒一次）→ 增大 -Xmn 或 -XX:NewRatio。2）晋升过快（老年代短时间被填满）→ 增大 Survivor 空间或晋升阈值 -XX:MaxTenuringThreshold。3）Full GC 太频繁（几十分钟一次）→ 查看老年代使用率是否持续上涨，考虑堆内存泄漏检测。4）CMS 并发模式失败（Concurrent Mode Failure）→ 增大老年代或调低 CMSInitiatingOccupancyFraction。5）G1 的 Mixed GC 暂停长 → 调整 -XX:G1MixedGCLiveThresholdPercent。推荐使用 GCeasy 在线分析工具或 gceasy.io 的 GC 日志分析报告。","hints":["Young GC 频率是判断新生代大小是否合适的第一指标","Full GC 几乎总是需要优化的对象"],"tags":["JVM","GC","调优","日志分析"],"id":1754},{"category":"java_advanced","difficulty":"medium","type":"short_answer","title":"String 常量池与 Integer 缓存池的实现差异","content":"请比较 String 常量池和 Integer 缓存池在实现机制、存储位置和管理方式上的异同。","answer":"答案：String 常量池在堆中（JDK 7+），存储 String 对象，通过 intern() 管理；Integer 缓存池是 IntegerCache 内部类，缓存 [-128, 127] 的 Integer 对象。\n\n解析：String 常量池——1）存储位置：JDK 6 在永久代，JDK 7+ 在堆中。2）存储内容：String 对象（字面量和 intern 引入的）。3）管理方式：JVM 自身管理，String.intern() 手动入池。4）无大小限制（受堆大小限制）。Integer 缓存池——1）存储位置：堆（IntegerCache 的静态数组）。2）存储内容：Integer 对象（范围 -128~127）。3）管理方式：类加载时创建，通过 Integer.valueOf() 使用。4）上限可通过 -XX:AutoBoxCacheMax 调整。\n\n扩展延伸：String 常量池大小可通过 -XX:StringTableSize 设置（JDK 6 默认 1009，JDK 7+ 默认 60013，可调大减少冲突）。大量不同字符串 intern 会导致常量池膨胀和 GC 压力（因为 StringTable 是固定大小的哈希表）。Integer 缓存池不可变，所有 Integer 在范围内都使用同一组对象。其他包装类也有类似缓存：Boolean（全部布尔值）、Byte/Short/Long（-128~127）、Character（0~127），但只有 Integer 可以配置上限。","hints":["String 常量池通过 hashtable 实现，Integer 缓存池通过静态数组实现","Integer 缓存池大小可以配置，String 常量池在 JDK 7+ 在堆中"],"tags":["JVM","String","Integer","缓存池","常量池"],"id":1755},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"ZGC 的并发标记与重定位原理","content":"请详细解释 ZGC（Z Garbage Collector）的并发标记和并发重定位（Relocation）是如何实现的。ZGC 为什么能做到极低的暂停时间？","answer":"答案：ZGC 通过染色指针（Colored Pointers）和读屏障（Load Barrier）实现并发标记和并发重定位，暂停时间与堆大小无关。\n\n解析：ZGC 的核心创新——1）染色指针（Colored Pointers）：在 64 位指针的高 4 位（Linux 仅使用 42 位地址，AMD64 虚拟地址空间高 18 位未使用）中编码标记信息。指针的 4 个额外位分别是 Finalizable、Remapped、Marked1、Marked0。通过这些位判断对象的标记状态，无需对象头额外空间。2）读屏障（Load Barrier）：每次从堆中读取对象引用时执行检查。根据指针的染色位决定是否需要处理（如标记或重映射），处理成本极低。3）并发重定位：ZGC 在重定位期间通过读屏障拦截访问，如果访问到已移动的对象，读屏障自动将引用更新为新地址（自愈，Self-Healing）。\n\n扩展延伸：ZGC 的标记阶段分为 Mark Start（STW，初始化标记根）、Concurrent Mark（并发遍历对象图，使用染色指针标记）、Mark End（STW，处理漏标的根）、Concurrent Prepare Relocation（计算要回收的 Region）、Concurrent Relocate（并发重定位存活对象到其他 Region）。重定位中读屏障自愈机制——访问旧地址时通过读屏障检测到 Remapped 位未设置，触发转发到新地址并更新引用，后续访问直接命中新地址。ZGC 适用于大堆（TB 级）和低延迟（<10ms 暂停）要求的场景，与 G1 相比牺牲了吞吐量换取更低的延迟。","hints":["染色指针在 64 位指针的高 4 位编码状态信息","读屏障在对象引用加载时执行，实现自愈"],"tags":["JVM","ZGC","GC","低延迟"],"id":1756},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"Shenandoah GC 原理","content":"请介绍 Shenandoah GC 的工作原理。它与 ZGC 有什么异同？","answer":"答案：Shenandoah 是 OpenJDK 的另一种低延迟 GC，通过 Brooks Pointer（转发指针）实现并发压缩，暂停时间与堆大小无关。\n\n解析：Shenandoah 的核心机制——1）Brooks Pointer：在对象头部增加一个转发指针（forward pointer），初始指向自身。对象被移动后，转发指针更新为新地址。所有对象访问通过 Brooks Pointer 间接寻址。2）读屏障：Shenandoah 使用读屏障（-XX:+UseShenandoahGC 后默认开启），每次对象读取都检查 Brooks Pointer 是否需要转发。3）并发压缩：Shenandoah 可以并发地移动对象、压缩堆，不需要像 CMS 那样在 Remark 阶段 STW。\n\n扩展延伸：Shenandoah 与 ZGC 的对比——相同点：都实现并发标记和并发重定位，暂停时间与堆大小无关，目标 <10ms 暂停。不同点：1）屏障位置：ZGC 在读引用时（Load Barrier），Shenandoah 在读写对象时（Brooks Pointer Access Barrier）。2）指针技术：ZGC 用染色指针（利用高位 bit），Shenandoah 用 Brooks Pointer（对象头额外字段）。3）JDK 支持：ZGC 在 JDK 11 实验性引入（JDK 15 正式），Shenandoah 在 JDK 12 实验性引入（JDK 15 正式）。4）堆大小限制：ZGC 最大支持 16TB，Shenandoah 支持大堆但性能在 TB 级不如 ZGC。","hints":["Brooks Pointer 在对象头中存储转发地址","Shenandoah 使用读屏障 + 写屏障（取决于版本）"],"tags":["JVM","Shenandoah","GC","低延迟"],"id":1757},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"Project Valhalla 与值类型（Value Types）","content":"请介绍 Project Valhalla 引入的值类型（Value Types / Inline Types）概念。它解决了什么问题？对 Java 性能有何影响？","answer":"答案：Project Valhalla 旨在为 Java 引入值类型（Value Types，JEP 401），让开发者可以定义没有对象身份（Identity）的轻量级数据类型，消除对象头的内存开销和间接访问。\n\n解析：值类型用 value 关键字声明（如 value record Point(int x, int y)），特性——1）无对象身份：值类型实例没有对象头（Mark Word + Klass Pointer），只有字段数据。在栈上、数组中和作为其他对象的字段时直接内联存储（Flattened），而不是通过引用间接访问。2）不可变：值类型字段隐式为 final，实例创建后不可变（有利于 JIT 优化和并发安全）。3）可为空值类型（Nullable Value Types）：通过包装引用实现，可赋值为 null。\n\n扩展延伸：性能优势——1）内存减少：值类型数组直接存储数据（如 Point[] 直接存 x,y 整数对），而对象数组存引用 + 堆中对象（多一层间接和对象头开销）。2）缓存局部性改善：连续内存存储，无指针跳跃。3）JIT 优化：内联特性使得逃逸分析、标量替换更有效。现状：Project Valhalla 仍在预览阶段（JDK 22+ 有预览 JEP），需要等到 JDK 24+ 才可能正式发布。与原始类型（int, long）不同，值类型是用户自定义的，编译器会将其视为原始类型的扩展。","hints":["值类型没有对象身份，没有对象头，没有引用语义","值类型在多维数组和集合中性能提升最明显"],"tags":["JVM","Project Valhalla","值类型","性能"],"id":1758},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"虚拟线程（Virtual Threads）的原理与应用","content":"请解释 Project Loom 引入的虚拟线程（Virtual Threads）的原理。虚拟线程和平台线程（Platform Threads）有什么区别？使用虚拟线程需要注意什么？","answer":"答案：虚拟线程是 JDK 21 正式发布的轻量级线程（JEP 444），由 JVM 调度而非操作系统，数百万个虚拟线程可以在少量平台线程上运行。\n\n解析：虚拟线程的核心机制——1）载体线程（Carrier Thread）：虚拟线程在平台线程（称为载体）上运行。当虚拟线程执行阻塞操作（如 I/O、锁等待）时，虚拟线程从载体线程上 yield（卸载），载体线程去执行其他虚拟线程。2）Continuation：虚拟线程的底层实现是 Continuation（可暂停和恢复的执行上下文）。JVM 在虚拟线程阻塞时保存 Continuation 状态，切换出来；阻塞完成后恢复执行。3）ForkJoinPool：虚拟线程的调度器是 ForkJoinPool，它管理载体线程池。\n\n扩展延伸：与平台线程的对比——1）创建成本：平台线程 ≈ 1MB 栈空间 + OS 内核线程；虚拟线程 ≈ 几百字节。2）最大数量：平台线程数千到数万；虚拟线程百万级。3）适用场景：虚拟线程适合大量 IO 密集型任务，特别适合 Web 服务器（每个请求一个虚拟线程）。注意事项：1）避免 synchronized 阻塞（pinned 问题——虚拟线程阻塞在 synchronized 上时会 pinned 到载体线程，使载体线程不可用，影响吞吐量）。建议使用 ReentrantLock 替代。2）避免 CPU 密集型任务（虚拟线程切换也有开销）。3）谨慎使用 ThreadLocal（虚拟线程数量巨大时 ThreadLocal 内存量巨大）。","hints":["虚拟线程是 JVM 管理的用户态线程，非 OS 线程","synchronized 和 native 方法会导致虚拟线程 pinned"],"tags":["JVM","Project Loom","虚拟线程","并发"],"id":1759},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"Foreign Function & Memory API（FFM API）","content":"请介绍 Java 的 Foreign Function & Memory API（FFM API, JEP 454）以及它的前身。它和 JNI 相比有什么优势？","answer":"答案：FFM API（JDK 22 正式发布，JEP 454）是 Java 用于调用外部函数和访问外部内存的新 API，取代 JNI 更安全、更易用。\n\n解析：FFM API 分为两部分——1）Foreign Memory API（java.lang.foreign.MemorySegment）：提供安全的内存访问，支持堆内、堆外和映射文件内存。MemorySegment 具有空间和时间边界检查，防止野指针和 use-after-free。2）Foreign Function API（java.lang.foreign.Linker）：允许 Java 代码调用 C 库函数（如调用操作系统 API），不需要写 C 头文件和 JNI 胶水代码。通过 SymbolLookup 查找库函数，通过 MethodHandle 调用。\n\n扩展延伸：与 JNI 对比——1）安全性：FFM API 有类型检查和内存边界检查，JNI 出现错误时可能导致 JVM 崩溃。2）性能：FFM API 调用开销比 JNI 低（无线程状态切换开销）。3）易用性：FFM API 从 Java 侧直接声明函数签名和内存布局，不需要 C 编译器和平台特定的头文件处理。4）依赖：JNI 需编写 C 代码、编译成动态库；FFM API 只需 Java 代码。典型应用：Panama 项目（FFM API 是其成果）使得 Java 可以直接调用 C 标准库、OS API、GPU 库（CUDA）等，为 Java 在底层系统编程和高性能计算领域打开新空间。","hints":["FFM API 是 Panama 项目的一部分，标准库替代 JNI","MemorySegment 提供内存边界检查，防止野指针"],"tags":["JVM","FFM","JNI","panama","外部内存"],"id":1760},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"StructuredTaskScope 结构化并发","content":"请介绍 Java 21 引入的 StructuredTaskScope（结构化并发 / JEP 453）。结构化并发解决了什么问题？StructuredTaskScope 与 ExecutorService 的区别是什么？","answer":"答案：结构化并发将并发任务的生命周期与代码块绑定——子任务在代码块结束前必须完成，避免任务泄漏和取消传播问题。\n\n解决的问题：\n- 任务泄漏：提交给 ExecutorService 的任务可能在主线程结束后仍然运行（孤儿线程）\n- 取消传播：一个子任务失败时，其他相关子任务得不到通知，继续运行浪费资源\n- 错误处理：传统编程需要手动管理所有 Future 的取消、超时和异常合并\n\nStructuredTaskScope 的核心：\n- try-with-resources 管理生命周期：Scope 关闭时自动等待所有子任务完成或取消\n- 子任务与 Scope 绑定：子任务在 Scope 内创建，Scope 关闭前必须全部 Join\n\n基本用法：\ntry (var scope = new StructuredTaskScope.ShutdownOnFailure()) {\n    Future<String> user = scope.fork(() -> fetchUser(id));\n    Future<String> order = scope.fork(() -> fetchOrder(id));\n    scope.join();              // 等待所有任务\n    scope.throwIfFailed();     // 如果有任务失败，抛出异常\n    return user.resultNow() + order.resultNow();\n}  // Scope 自动关闭，未完成的任务被取消\n\n两种策略：\n1. ShutdownOnFailure：任一子任务失败 → 取消其他未完成的任务（适合「并发请求，一个失败全取消」的场景）\n2. ShutdownOnSuccess：任一子任务成功 → 取消其他未完成的任务（适合「并发请求，取最快响应」的场景）\n\n与 ExecutorService 的对比：\n- ExecutorService.submit()：任务提交后返回 Future，需要调用方手动 cancel 和处理异常\n- StructuredTaskScope.fork()：任务与 Scope 绑定，scope.join() 统一等待，scope 关闭自动清理\n- 结构化并发保证：所有子任务的生命周期不会超过创建它的代码块\n\n扩展延伸：StructuredTaskScope + 虚拟线程 = 最佳实践——每个子任务对应一个虚拟线程，创建成本极低。自定义策略：可以继承 StructuredTaskScope 实现自定义的关闭策略（如「多数投票成功即可」）。结构化并发是 Java 对 Go 的 errgroup 和 Kotlin 的 coroutineScope 概念的实现。","hints":["结构化并发 = 子任务生命周期与代码块绑定（try-with-resources），Scope 关闭前所有子任务必须完成","两种策略：ShutdownOnFailure（一个失败全取消）+ ShutdownOnSuccess（一个成功全取消）","vs ExecutorService：自动管理取消、异常合并、统一 Join，避免任务泄漏"],"tags":["Java","并发","StructuredTaskScope","结构化并发"],"id":1766},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"Vector API 向量计算","content":"请介绍 Java 22 正式发布的 Vector API（Project Panama 的一部分 / JEP 460）。Vector API 的作用是什么？如何在 Java 中利用 SIMD 指令加速计算？","answer":"答案：Vector API 让 Java 程序可以显式利用 CPU 的 SIMD（Single Instruction Multiple Data）指令集，在循环计算中获得显著的性能提升（2-16 倍）。\n\nSIMD 原理：\n- 普通代码（SISD）：一条指令处理一个数据元素\n- SIMD：一条指令同时处理多个数据元素（如一次处理 8 个 int 或 4 个 double）\n- 现代 CPU 都支持：x86 的 AVX-512（512 位）、ARM 的 NEON（128 位）、SVE（可变长度）\n\n传统做法的问题：\n- JIT 编译器会自动向量化一些简单循环（如数组求和），但条件复杂时无法自动向量化\n- 无法利用新指令集（如 AVX-512 的掩码操作）\n\nVector API 示例：\n\n// 传统标量计算\nfloat[] a, b, c;\nfor (int i = 0; i < N; i++) c[i] = a[i] * b[i] + c[i];  // 一次一个元素\n\n// Vector API 向量计算\nvar species = FloatVector.SPECIES_256;  // 256 位 = 8 个 float\nfor (int i = 0; i < N; i += species.length()) {\n    var va = FloatVector.fromArray(species, a, i);\n    var vb = FloatVector.fromArray(species, b, i);\n    var vc = FloatVector.fromArray(species, c, i);\n    va.mul(vb).add(vc).intoArray(c, i);  // 一次 8 个元素\n}\n\n性能提升场景：\n1. 矩阵乘法：2-4 倍加速\n2. 图像处理（像素操作）：4-8 倍加速\n3. 神经网络推理：2-4 倍加速\n4. 加密算法：3-6 倍加速\n5. 科学计算（FFT、卷积）：4-16 倍加速\n\nVector Species（向量宽度）：\n- FloatVector.SPECIES_128 / 256 / 512：对应 128/256/512 位宽\n- FloatVector.SPECIES_MAX：使用 CPU 支持的最大宽度\n- 不同 CPU 支持不同宽度，Vector API 自动适配\n\n扩展延伸：Vector API 经过多次迭代（JEP 414 孵化 → JEP 417 再次孵化 → JEP 426 预览 → JEP 438 第二次预览 → JEP 460 正式版）。Vector API 不是替代 JIT 自动向量化的——自动向量化处理简单场景，Vector API 处理 JIT 无法处理的复杂场景。实际使用建议：先在性能热点上用 Vector API 重写，用 JMH 验证加速效果。","hints":["Vector API = Java 中显式利用 CPU SIMD 指令（一条指令处理多个数据），实现 2-16 倍性能提升","示例：FloatVector.SPECIES_256 一次处理 8 个 float，替代 for 循环一个一个处理","适用场景：矩阵乘法/图像处理/神经网络/科学计算；JIT 能自动向量化简单的场景不需要 Vector API"],"tags":["Java","Vector","SIMD","性能"],"id":1767},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"CompletableFuture 深度：异步编排与线程模型","content":"请深入介绍 CompletableFuture 的异步编排能力。thenApply 与 thenApplyAsync 的线程模型有什么区别？如何处理多个 CompletableFuture 的组合和异常？","answer":"答案：CompletableFuture 是 Java 8 引入的异步编程工具，Java 9+ 进一步增强，支持丰富的任务编排和灵活的线程模型。\n\n线程模型（关键！！！）：\n- thenApply/Fnally/accept：由上一个阶段的完成线程执行（不切换线程）\n- thenApplyAsync/FnallyAsync/acceptAsync：由 ForkJoinPool.commonPool()（或指定 Executor）执行\n- 区别：Async 版本保证在新的线程池中执行，非 Async 版本可能在调用线程或已完成线程中执行\n\n规则：\n1. 如果前一阶段已完成，当前回调在执行代码的线程中立即执行（非 Async）\n2. 如果前一阶段未完成，当前回调在完成前一阶段的线程中执行（非 Async）\n3. Async 版本始终在指定线程池中执行\n\n任务编排方法：\n\n1. 串行编排：\n   CompletableFuture.supplyAsync(() -> fetchUser())\n       .thenApply(user -> process(user))       // 同一线程\n       .thenApplyAsync(user -> save(user))      // 新线程池\n       .exceptionally(e -> handleError(e));\n\n2. 并行编排：\n   // 两个并行任务 + 结果合并\n   CompletableFuture<String> f1 = CompletableFuture.supplyAsync(() -> fetchA());\n   CompletableFuture<String> f2 = CompletableFuture.supplyAsync(() -> fetchB());\n   f1.thenCombine(f2, (a, b) -> a + b);        // 两者都完成\n\n3. 任意完成：\n   CompletableFuture.anyOf(f1, f2, f3)          // 任一完成即返回\n\n4. 全部完成：\n   CompletableFuture.allOf(f1, f2, f3).thenRun(() -> /* all done */)\n\n异常处理：\n- exceptionally(e -> defaultValue)：类似 catch，对异常提供默认值\n- handle((result, e) -> ...)：不管成功/失败都调用，返回新结果\n- whenComplete((result, e) -> ...)：类似 finally，不改变结果\n\n常见陷阱：\n1. 默认线程池（ForkJoinPool.commonPool()）是所有并行流的共享池，阻塞操作会导致整个池阻塞\n2. 必须使用 Async 版本 + 自定义线程池处理阻塞 I/O\n3. CompletableFuture.get() 阻塞调用线程 → 应使用 thenApply 链式调用避免阻塞\n4. get() 抛出的异常包装在 ExecutionException 中，需要拆开\n\n扩展延伸：Java 21 的 StructuredTaskScope 是 CompletableFuture 的替代方案——更适合虚拟线程场景。CF 的链式调用与虚拟线程的「每个请求一个线程」是两种不同的并发模型。在虚拟线程时代，StructuredTaskScope 通常比 CF 更优（代码更简单、更容易理解）。","hints":["线程模型：thenApply（不切换线程，在完成线程执行）vs thenApplyAsync（始终在线程池执行）","串行：thenApply/thenCompose；并行：thenCombine；任意：anyOf；全部：allOf","陷阱：commonPool 被阻塞阻塞整个 JVM；Async + 自定义线程池处理阻塞 I/O；get() 阻塞"],"tags":["Java","CompletableFuture","异步","并发"],"id":1768},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"ScopedValue 与线程局部变量对比","content":"请介绍 Java 21 预览的 ScopedValue（JEP 446 / Project Loom）。ScopedValue 与 ThreadLocal 相比有什么优势？ScopedValue 如何解决 ThreadLocal 的内存泄漏和传递问题？","answer":"答案：ScopedValue 是 ThreadLocal 的现代化替代方案，不可变、安全、支持虚拟线程，解决 ThreadLocal 的多个根本问题。\n\nThreadLocal 的问题：\n1. 内存泄漏：ThreadLocal 中的值存活时间 = 线程生命周期（特别在线程池中，线程复用导致泄漏）\n2. 可修改性：用 ThreadLocal 传递的上下文可以被任何代码修改（安全隐患）\n3. 虚拟线程不可用：虚拟线程数量巨大（百万级），每个 ThreadLocal 占用的内存不可接受\n4. 传递困难：线程池中新建的线程不继承父线程的 ThreadLocal（需要手动传递）\n\nScopedValue 的设计：\n- 不可变（Immutable）：值在绑定后不能被修改\n- 有限生命周期：值存活在 try-with-resources 代码块内（超出范围自动释放）\n- 继承语义：子线程自动继承 ScopedValue（剪枝继承——只继承被捕获的值的快照）\n- 轻量级：虚拟线程可以安全使用（不会被 Pin 住）\n\n使用方式：\n// 定义 ScopedValue（静态常量）\nprivate static final ScopedValue<User> CURRENT_USER = ScopedValue.newInstance();\n\n// 绑定值（只能在一个线程内绑定一次）\nScopedValue.where(CURRENT_USER, user)  // 绑定用户到当前上下文\n    .run(() -> {\n        // 在这个 lambda 中可读取 CURRENT_USER.get()\n        handleRequest();\n    });  // 离开 run 后 CURRENT_USER 自动释放\n\n// 读取\nUser user = CURRENT_USER.get();\n\n// 不可修改：在 run() 中不能调用 CURRENT_USER.set(user2)（没有 set 方法）\n// 重新绑定（嵌套）：ScopedValue.where(CURRENT_USER, admin).run(() -> { ... })\n\n对比总结：\n| 特性 | ThreadLocal | ScopedValue |\n|------|------------|-------------|\n| 可变性 | 可修改 | 不可变 |\n| 生命周期 | 线程生命周期 | 代码块生命周期 |\n| 虚拟线程 | 不友好（内存大） | 友好（轻量） |\n| 内存泄漏 | 常见 | 不会（超出自动释放） |\n| 继承 | 不可靠 | 可靠（值捕获） |\n\n扩展延伸：ScopedValue 在 Web 框架中可以替代 ThreadLocal 做请求上下文的传递（当前用户、请求 ID、租户）。在虚拟线程时代，ThreadLocal 被设计为「不推荐使用」（deprecate），ScopedValue 是推荐的替代方案。ScopedValue 还支持 rebind（重新绑定），用于在不改变父作用域值的情况下，创建子作用域的新值。","hints":["ThreadLocal 的问题：内存泄漏（线程池）、可修改（不安全）、虚拟线程不友好、线程间传递困难","ScopedValue 的设计：不可变 + try-with-resources 有限生命周期 + 自动继承 + 虚拟线程友好","最佳实践：ScopedValue 替代 ThreadLocal 做请求上下文传递（用户/请求ID/租户）"],"tags":["Java","ScopedValue","ThreadLocal","Loom"],"id":1769},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"Continuation 与栈恢复","content":"请介绍 Java 中 Continuation（协程的底层机制）的概念。Continuation 与虚拟线程的关系是什么？什么是栈恢复（Stack Recovery）？","answer":"答案：Continuation 是虚拟线程的底层实现机制，是一种可以暂停和恢复执行的计算状态。\n\nContinuation 的概念：\n- Continuation 表示程序执行到某个点的状态（包括局部变量、栈帧、程序计数器）\n- 可以暂停（yield）当前执行，保存状态\n- 稍后从暂停点恢复执行（resume）\n\nContinuation 与虚拟线程：\n- 虚拟线程的底层使用 Continuation 实现（JDK 内部 jdk.internal.vm.Continuation）\n- 当虚拟线程执行阻塞操作（如 I/O、锁）时，Continuation 自动 yield（保存当前栈帧）\n- 当阻塞操作完成时，Continuation resume（恢复栈帧，继续执行）\n- 这种机制称为 JVM 内部的栈恢复（Stack Recovery）\n\n栈恢复（Stack Recovery）的原理：\n1. 虚拟线程运行在 Carrier 线程上，执行到阻塞调用时\n2. Continuation.yield() 被调用——虚拟线程的栈帧从 Carrier 的栈上拷贝到堆内存（拷贝栈）\n3. Carrier 线程被释放，可以执行其他虚拟线程\n4. 阻塞操作完成后（如 I/O 数据就绪）\n5. Continuation.resume() 被调用——堆内存中的栈帧恢复回某个 Carrier 线程的栈\n\n栈恢复的技术挑战：\n1. 栈帧拷贝：需要将 native 栈帧拷贝到堆（JVM 内部有完善的机制）\n2. 栈回滚（Stack Unwalk）：virtual thread 在 yield 时需要 unwalk 栈\n3. Pin 问题：在 synchronized 块或 native 方法中无法 yield（栈帧 pinned）\n\n扩展延伸：Continuation 是编程语言层面的协程原语。Kotlin 的协程（suspend/resume）也是基于类似 Continuation 的概念。Java 的 Continuation 在 JDK 内部使用（不对外公开 API），是虚拟线程的基石。理解 Continuation 有助于理解为什么虚拟线程在 synchronized 块中会被 Pin 住（因为 synchronized 的栈帧结构阻止了安全的 yield）。","hints":["Continuation = 程序执行状态的保存和恢复（暂停/恢复），是虚拟线程的底层实现","栈恢复（Stack Recovery）：虚拟线程阻塞时栈帧从 Carrier 拷贝到堆，完成后恢复回栈","Pin 问题：synchronized 块中无法 Yield（栈帧结构阻止安全的 Continuation 操作）"],"tags":["Java","Continuation","虚拟线程","Loom"],"id":1770},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"JMM 与 happens-before 规则","content":"请解释 Java 内存模型（JMM）中的 happens-before 规则及其在并发编程中的作用。","answer":"答案：happens-before 是 JMM 保证多线程操作可见性和有序性的核心规则\n\n解析：happens-before 规则定义了一组操作之间的偏序关系。如果操作 A happens-before 操作 B，则 A 对所有后续线程的可见效果在 B 执行前已确定。关键规则包括：1）程序顺序规则——同一个线程中的每个操作 happens-before 该线程的后续操作（as-if-serial 语义）2）监视器锁规则——对一个锁的解锁 happens-before 后续对该锁的加锁 3）volatile 规则——对 volatile 变量的写 happens-before 后续对该 volatile 变量的读 4）传递性——A happens-before B 且 B happens-before C，则 A happens-before C 5）线程启动/中断/终止规则——Thread.start() happens-before 新线程的任意操作，线程中操作 happens-before Thread.join() 返回。\n\n扩展延伸：JMM 不要求时间上的先后顺序（物理时间上 A 先执行 B 不一定意味着 A happens-before B），只保证可见性和有序性。重排序在满足 happens-before 时是安全的：编译器/CPU 可以在不违反 happens-before 的前提下自由对指令重排以提高性能。volatile 实现原理：JVM 在 volatile 写之前插入 StoreStore 屏障（禁止前面的写与 volatile 写重排），写后插入 StoreLoad 屏障（强制刷新到主存）。synchronized 实现：Java 1.6 后大量优化（偏向锁、轻量级锁、锁粗化、锁消除），在无竞争时代价很小。hb(volatile写) -> hb(volatile读) —— 这道保证是双检锁（DCL）单例模式可以配合 volatile 使用的理论基础。","hints":["dcl 双检锁单例模式中 volatile 关键字的含义","重排序在满足 happens-before 时如何保证安全"],"tags":["JMM","并发","happens-before"],"id":1771},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"Java Fork/Join 框架","content":"请解释 Fork/Join 框架的工作窃取算法及其适用场景。","answer":"答案：Fork/Join 框架通过分治法和工作窃取算法高效利用多核 CPU\n\n解析：核心概念：将大任务（ForkJoinTask）递归拆分为子任务，子任务的结果再合并（Join）。工作窃取（Work-Stealing）算法：每个工作线程拥有一个双端队列（Deque）存放自己的子任务，线程从队头取任务执行；空闲线程从其他线程的队尾窃取任务执行。这种设计减少了线程之间的竞争（头尾互不冲突）。ForkJoinPool 维护一个全局提交队列，通过 execute/submit/invoke 提交外部任务。任务类型：RecursiveAction（无返回值，如数组排序）、RecursiveTask（有返回值，如求和）。ForkJoinTask 在 Java 8 中作为并行流（Parallel Stream）的底层实现。\n\n扩展延伸：Fork/Join 适合纯计算密集型且任务可独立拆分的场景——数组/列表的排序、遍历、矩阵运算、归并操作。不适合：IO 密集型任务（因为在等待 IO 时无法窃取别人的任务）。ForkJoinPool 的线程数默认 = Runtime.availableProcessors() - 1。阈值（Threshold）选择：任务拆分的最小大小，太小任务拆分开销大，太大无法充分利用多核。通常经过实验确定（如数组排序任务拆分到 10000 个元素作为基准）。工作窃取可能导致更多缓存缺失（因为线程从一个核心窃取数据到另一个核心）。Common Pool（ForkJoinPool.commonPool()）被 CompletableFuture 和 Parallel Stream 共享，应避免阻塞操作（如 sleep 或同步 IO 阻塞公共池中的线程）。ManagedBlocker 接口用于在公共池中处理阻塞操作。","hints":["工作窃取为什么从双端队列的队尾窃取","ForkJoinPool 的线程数怎么确定以及为什么不适合 IO 密集"],"tags":["Fork/Join","并发","工作窃取"],"id":1772},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"Java 内存泄漏场景","content":"以下哪个场景不会导致 Java 堆内存泄漏？","options":["A) 静态集合类持有不再使用的对象","B) 未关闭的数据库连接和文件流","C) ThreadLocal 中 set 了值但没有 remove","D) 某个局部变量在方法执行完成后未被回收"],"answer":"D","hints":["局部变量在方法栈帧弹出后自动成为垃圾回收目标，不会泄漏"],"tags":["JVM","内存","泄漏"],"id":1773},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"Java 伪共享 False Sharing","content":"请解释 Java 并发编程中的伪共享（False Sharing）问题以及常见的解决方案。","answer":"答案：伪共享是指多个线程修改同一缓存行的不同变量导致不必要的缓存同步\n\n解析：CPU 缓存以缓存行（Cache Line，通常 64 字节）为单位从内存加载数据。当两个线程运行在不同 CPU 核心上，各自修改同一缓存行中的不同变量时，缓存一致性协议（MESI）会让两个核心的缓存行在每次写入时互相失效。即使线程操作的是不同变量（逻辑上无关），物理上在同一缓存行仍会触发缓存行状态的频繁切换，导致严重的性能下降（可能降低 10-100 倍）。解决方案的核心是缓存行填充（Padding）：在变量前后填充无用字节，确保不同线程操作的变量位于不同缓存行。\n\n扩展延伸：Java 中的解决方案演进：1）Java 8 前手动填充（long p1, p2, ... p7 在 volatile long value 前后）2）Java 8 引入 @Contended 注解（JVM 参数 -XX:-RestrictContended 开启），自动填充到缓存行对齐。3）JCTools（Java Concurrency Tools）等并发库内部广泛使用了缓存行填充。Log4j 2 的 RingBuffer（LMAX Disruptor）架构是避免伪共享的经典实践。检测伪共享：使用 Linux perf（查看 cache-misses 指标）和 JDK Flight Recorder 分析缓存行为。现代 CPU 的 MESI 优化方向：不同 Intel 微架构的各级缓存命中/失效行为不同，伪共享的惩罚在不同 CPU 上不同（从几纳秒到几百纳秒）。","hints":["@Contended 注解怎么实现缓存行填充","Disruptor 框架是怎么解决伪共享的"],"tags":["并发","缓存","性能"],"id":1774},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"Java 偏置锁撤销机制","content":"请解释 Java 偏向锁的撤销过程和 JDK 15 后偏置锁被禁用的原因。","answer":"答案：偏向锁减少同一线程重复获取锁的 CAS 开销，但撤销成本高且复杂\n\n解析：偏向锁在对象头 Mark Word 中存储偏向线程 ID，当该线程再次获取同一锁时无需任何 CAS 操作。偏向锁撤销发生在另一个线程尝试竞争该锁时：1）检查偏向线程是否存活 2）如果存活，在全局安全点暂停偏向线程 3）检查偏向线程是否仍在持有该锁（如果已退出同步块，则撤销 4）如果是，将偏向锁升级为轻量级锁或膨胀为重量级锁。回退方案：如果偏向线程已释放，可退回到无锁状态或轻量级锁。撤销操作需要在全局安全点暂停所有线程，触发所有线程的 Stop-The-World 暂停，这在高并发应用中可能显著增加延迟。\n\n扩展延伸：JDK 15 通过 JEP 374 默认禁用了偏向锁（-XX：-UseBiasedLocking）。原因：1）偏向锁的撤销必须在全局安全点进行，在高吞吐应用（如 Web 应用）中，持有同一个锁的线程竞争很常见，撤销频繁导致 STW 暂停 2）现代应用的同步块趋向于短时间，轻量级锁 CAS 开销已经很小 3）偏向锁的代码复杂度显著增加了 JVM 的维护成本。JDK 21 移除了偏向锁代码。替代方案：对于有大量锁竞争且没有线程偏向的场景，默认使用轻量级锁（通过 CAS 加锁）就足够了。对于非常明确是单线程访问的锁，可以考虑消除锁（Lock Elimination）——JIT 通过逃逸分析自动优化。","hints":["偏向锁撤销发生在什么时候","JDK 15 移除偏向锁的根本原因是什么"],"tags":["Java","锁","偏向锁"],"id":1775},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"FFM API 中 Linker 与外部函数调用","content":"请介绍 Foreign Function & Memory API 中 Linker 接口的角色，以及如何通过 SymbolLookup 调用 C 标准库函数。","answer":"答案：FFM API 中 Linker 接口用于将 Java 方法签名与外部函数（C 函数）链接。核心流程：1）通过 `Linker.nativeLinker()` 获取平台 Linker；2）通过 `SymbolLookup.libraryLooker()` 或 `SymbolLookup.loaderLookup()` 查找外部符号（函数指针）；3）通过 `Linker.downcallHandle()` 将符号绑定到 MethodHandle——需要描述函数的签名（FunctionDescriptor）和内存布局（MemoryLayout）；4）使用 Arena 管理参数和返回值的内存生命周期。例如调用 C 的 `strlen`：先查找符号，构建 FunctionDescriptor（参数为 AddressLayout，返回值为 ValueLayout.JAVA_LONG），获取 MethodHandle 后在 Arena 中分配 C 字符串（使用 MemorySegment）并调用。Linker 还支持 upcall——从 C 代码回调 Java 方法。","hints":["downcallHandle 和 upcallStub 分别用于什么场景","FunctionDescriptor 如何描述 C 函数的参数和返回值类型"],"tags":["FFM API","Linker","Project Panama","外部函数","SymbolLookup"],"id":1776},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"Vector API 的 Species 选择与 FMA 运算","content":"请介绍 Vector API 中 Species（向量物种）的作用，以及熔乘加（FMA）运算在数值计算中的优势。","answer":"答案：VectorSpecies 定义了向量运算的位宽和元素类型组合，如 `FloatVector.SPECIES_256` 表示 256 位宽、可容纳 8 个 float 元素。Species 的选择需要平衡 CPU 支持（不同架构支持的 SIMD 指令宽度不同）和数据量。最佳做法是使用 `FloatVector.SPECIES_PREFERRED` 让 JIT 自动选择当前 CPU 架构的最优宽度。Vector API 支持逐元素的加减乘除运算，以及熔乘加（FMA，`v.fma(a, b)` 等价于 `v * a + b`）——FMA 在硬件层面只需一条指令（如 AVX-512 的 VFMADD），比先乘后加更快且更精确（单次舍入而非两次舍入）。Vector API 还支持 lane 操作（如 `withLane`、`lane`）、重排操作（rearrange）、比较和选择（blend）等。适合矩阵乘法、卷积、FFT 等计算密集型场景。","hints":["SPECIES_PREFERRED 在 x86 和 ARM 架构下分别对应多少位","FMA 指令减少舍入误差的原因是什么"],"tags":["Vector API","SIMD","FMA","Project Panama","性能优化"],"id":1777},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"结构化并发的错误传播与任务取消","content":"请解释结构化并发中 ShutdownOnFailure 和 ShutdownOnSuccess 策略如何传播错误和取消任务，以及 StructuredTaskScope 的生命周期保证。","answer":"答案：StructuredTaskScope 封装了结构化并发的生命周期管理。通过 try-with-resources 创建 scope，在 scope 内调用 `fork()` 提交子任务（每个子任务通常由虚拟线程执行）。scope 关闭时（try 块结束）自动等待所有子任务完成。ShutdownOnFailure 策略：任何一个子任务抛出异常时立即关闭 scope（调用 shutdown()），取消所有尚未完成的子任务，主线程在 join() 时抛出异常。ShutdownOnSuccess 策略：第一个子任务成功返回结果时立即关闭 scope，取消其他未完成子任务，主线程通过 result() 获取结果。两种策略都确保了：1）无任务泄漏——scope 关闭时未完成的子任务被强制取消；2）错误传播——异常不会无声吞没；3）取消传播——一个任务的结果或异常影响其他任务。用户还可以自定义策略。","hints":["自定义 StructuredTaskScope 策略需要实现 handleComplete 方法","shutdown() 和 close() 在取消传播中的协同方式"],"tags":["结构化并发","StructuredTaskScope","错误处理","Project Loom","Java 21"],"id":1778},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"ScopedValue 的绑定生命周期与传递规则","content":"请解释 ScopedValue 的绑定（binding）生命周期机制，以及它在虚拟线程间传递数据时相比 ThreadLocal 的优势。","answer":"答案：ScopedValue 使用 `where(key, value)` 静态方法创建绑定，通过 `run()` 或 `call()` 方法限定作用域。绑定只在 lambda 执行期间有效，退出后自动解绑。特性：1）单次写入（single shot）——绑定后值不可变，读取调用 `get()` 返回当前绑定的值；2）作用域化——绑定生命周期由方法调用栈决定，不依赖线程生命周期；3）不可变性——避免了 ThreadLocal 常见的脏读和值意外修改问题。相比 ThreadLocal 的优势：1）虚拟线程友好——ScopedValue 利用栈帧结构存储绑定，虚拟线程 context switch 时无需像 ThreadLocal 那样维护哈希表；2）无内存泄漏风险——绑定自动随作用域结束释放；3）不可变性提供线程安全保证。ScopedValue 支持跨线程边界传递：在 `run()` 内创建的虚拟线程自动继承当前绑定的 ScopedValue。","hints":["ScopedValue 在虚拟线程的 context switch 时如何实现高效传递","ThreadLocal 在虚拟线程场景下的大量线程导致的内存开销问题"],"tags":["ScopedValue","ThreadLocal","Project Loom","虚拟线程","并发"],"id":1779},{"category":"java_advanced","difficulty":"medium","type":"short_answer","title":"有序集合 SequencedCollection 与 SequencedMap","content":"请介绍 Java 21 中 SequencedCollection、SequencedSet 和 SequencedMap 接口的设计目标和新增方法。","answer":"答案：Sequenced Collections（JDK 21 正式）为有序集合定义了标准接口。SequencedCollection 接口新增方法：`addFirst(E)`、`addLast(E)`、`getFirst()`、`getLast()`、`removeFirst()`、`removeLast()`、`reversed()`（返回逆序视图）。实现类包括 ArrayList、LinkedList、ArrayDeque 等。SequencedSet 接口继承 SequencedCollection，增加 `reversed()` 返回 SequencedSet。实现类包括 LinkedHashSet、TreeSet 等。SequencedMap 接口新增方法：`putFirst(K, V)`、`putLast(K, V)`、`firstEntry()`、`lastEntry()`、`pollFirstEntry()`、`pollLastEntry()`、`reversed()`（返回 SequencedMap 逆序视图）。实现类包括 LinkedHashMap、TreeMap 等。设计目标是消除之前访问有序集合首尾元素时的 API 不一致问题（ArrayList 没有 addFirst/getFirst，TreeMap 没有一致的逆序视图方法）。","hints":["reversed() 返回的是新集合还是原始集合的视图","SequencedCollection 如何统一 LinkedList 和 ArrayList 的首尾操作"],"tags":["SequencedCollection","SequencedMap","Java 21","集合框架","API设计"],"id":1780},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"FFM API SegmentAllocator 使用","content":"请说明 Foreign Function & Memory API（JDK 22 正式）中 MemorySegment 和 SegmentAllocator 的关系，以及 SegmentAllocator 在不同 Arena 作用域下的使用方式。","answer":"答案：SegmentAllocator 是分配 MemorySegment 的策略接口。MemorySegment 是内存段的抽象表示，而 SegmentAllocator 负责如何分配这些段。\\n关系：\\n1. Arena 实现了 SegmentAllocator 接口，因此 Arena 本身可作为分配器使用。\\n2. 通过 Arena.allocate() 分配的内存段生命周期由 Arena 管理，arena 关闭时所有段失效。\\n3. SegmentAllocator 也提供 `slicingAllocator(SegmentAllocator, long)` 从现有 Arena 分配器中切分出一个子分配器。\\n不同 Arena 类型下的使用：\\n- Arena.ofAuto()：内存由 GC 自动回收，适合生命周期不明确的场景。\\n- Arena.ofConfined()：线程限制，仅创建线程可分配和访问，性能最高。\\n- Arena.ofShared()：多线程共享，通过同步机制保证安全，性能低于 confined。\\n分配方法包括 allocate(ValueLayout)、allocateArray(ValueLayout, long)、allocate(MemoryLayout)、allocateFrom(ValueLayout, 值) 等。\\nSegmentAllocator 还支持追加分配策略（如 NativeSegmentList 在 GraalVM 中），减少单次分配的开销。","hints":["Arena 实现了 SegmentAllocator 接口，可以直接调用 allocate 方法","SegmentAllocator.allocateFrom 可以直接从 Java 字符串或 int 数组创建 MemorySegment"],"tags":["FFM API","SegmentAllocator","MemorySegment","Arena","panama"],"id":1781},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"Vector API SIMD 向量化性能建模","content":"请介绍 Vector API 中 VectorSpecies 的作用和选择策略，以及熔乘加（FMA）运算在数值计算中的性能优势。","answer":"答案：VectorSpecies 定义了向量运算的位宽和元素类型组合，如 `FloatVector.SPECIES_256` 表示 256 位宽可容纳 8 个 float。\\n选择策略：\\n1. 使用 `FloatVector.SPECIES_PREFERRED` 让 JVM 自动选择当前 CPU 架构最优宽度（x86 上为 256 或 512 位，ARM 上为 128 位）。\\n2. 数据量较小时选择 smaller species 避免尾部循环处理过多。\\n3. 需要根据数据集大小做 Loop Unrolling，每轮处理多个 species 单元。\\nFMA 运算优势：\\n1. `v.fma(a, b)` 等价于 `v * a + b`，但在硬件层面只需一条指令（如 AVX-512 的 VFMADD、ARM NEON 的 FMLA）。\\n2. 精度优势：FMA 只做一次舍入，而先乘后加做两次舍入，FMA 结果更精确。\\n3. 性能优势：一条指令替代两条，降低指令发射压力和延迟。\\nVector API 还支持 lane 操作（withLane/lane）、重排（rearrange）、比较选择（blend/compare）、类型转换（convertShape）等，适合矩阵乘法、卷积、FFT 等计算密集型场景。","hints":["SPECIES_PREFERRED 在 x86 和 ARM 架构下可能返回不同位宽","FMA 减少一次舍入既提高精度也提升性能"],"tags":["Vector API","SIMD","FMA","VectorSpecies","panama"],"id":1782},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"Structured Concurrency ShutdownOnFailure vs ShutdownOnSuccess","content":"请对比说明结构化并发中 ShutdownOnFailure 和 ShutdownOnSuccess 两种内置策略的错误传播和任务取消行为，以及如何自定义关闭策略。","answer":"答案：ShutdownOnFailure：任一子任务失败时立即关闭 scope，取消所有尚未完成的子任务。主线程在 join() 完成后调用 `throwIfFailed()` 重新抛出第一个异常。适用于「全有或全无」场景——所有子任务都需成功。\\nShutdownOnSuccess：第一个子任务成功返回结果时立即关闭 scope，取消其他未完成子任务。主线程通过 `result()` 获取第一个成功结果。适用于「谁先完成用谁」场景——如多数据源查询取最快响应。\\n共同保证：\\n1. 无任务泄漏——scope 关闭时未完成的子任务被强制取消。\\n2. try-with-resources 确保 scope 正确关闭。\\n3. scope.close() 等待所有已 fork 的子任务完成（非取消方式完成）。\\n自定义策略：继承 StructuredTaskScope 并覆写 `handleComplete()` 方法。在 handleComplete 中接收已完成子任务的 Future，根据自定义条件决定是否调用 shutdown()。例如实现「半数通过」策略——当超过半数的子任务成功时才停止。","hints":["ShutdownOnFailure 用 throwIfFailed 获取异常，ShutdownOnSuccess 用 result() 获取成功值","自定义策略需要重写 handleComplete 方法并调用 shutdown() 控制关闭时机"],"tags":["structured-concurrency","StructuredTaskScope","shutdown","lomb","Java 21"],"id":1783},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"ScopedValue 与 ThreadLocal 性能对比","content":"请解释 ScopedValue（JDK 21 预览转正）的绑定生命周期和不可变性机制，以及相比 ThreadLocal 在虚拟线程场景下的性能优势。","answer":"答案：ScopedValue 使用 `ScopedValue.where(key, value).run(() -> { ... })` 创建临时绑定。绑定只在 lambda 执行期间有效，退出后自动解绑。\\n核心特性：\\n1. 单次写入（single shot）——绑定值在作用域内不可变，避免并发修改。\\n2. 作用域化——绑定由方法调用栈作用域决定而非线程生命周期。\\n3. 可继承——在 run() 内创建的虚拟线程自动继承当前绑定的 ScopedValue（无需声明 InheritableThreadLocal）。\\n相比 ThreadLocal 的优势：\\n1. 不可变性——ThreadLocal 可变导致脏读问题，ScopedValue 不可变保证安全性。\\n2. 虚拟线程友好——虚拟线程数量可达百万级，ThreadLocal 的哈希表查找在线程数极大时性能退化严重。ScopedValue 利用栈帧结构存储，在虚拟线程 context switch 时高效传递。\\n3. 无内存泄漏——ThreadLocal 若未 remove() 会导致内存泄漏（线程池场景），ScopedValue 自动随作用域结束释放。\\n4. 性能——ScopedValue 的 get() 操作复杂度为 O(1) 且无哈希计算开销。","hints":["ScopedValue 的不可变性消除了 ThreadLocal 的脏读和值意外修改问题","虚拟线程百万级别时 ThreadLocal 的内存开销和查找性能都显著恶化"],"tags":["ScopedValue","ThreadLocal","virtual-thread","lomb","concurrency"],"id":1784},{"category":"java_advanced","difficulty":"medium","type":"short_answer","title":"SequencedCollection reversed 视图与接口设计","content":"请介绍 Java 21 中 SequencedCollection、SequencedSet 和 SequencedMap 接口的设计目标和新增方法，尤其是 reversed() 方法的视图语义。","answer":"答案：Sequenced Collections（JDK 21 正式）解决了有序集合 API 长期不一致的问题，为标准有序集合定义了统一接口。\\nSequencedCollection 新增方法：addFirst(E)、addLast(E)、getFirst()、getLast()、removeFirst()、removeLast()、reversed()。reversed() 返回逆序视图（不是新集合），修改逆序视图会反映到原始集合。实现类：ArrayList、LinkedList、ArrayDeque 等。\\nSequencedSet 继承 SequencedCollection，保证 reversed() 返回 SequencedSet。实现类：LinkedHashSet、TreeSet 等。\\nSequencedMap 新增：putFirst(K,V)、putLast(K,V)、firstEntry()、lastEntry()、pollFirstEntry()、pollLastEntry()、reversed()（返回 SequencedMap 逆序视图）。实现类：LinkedHashMap、TreeMap 等。\\n设计意义：\\n1. 统一了首尾操作 API——之前 addFirst 只在 LinkedList 和 ArrayDeque 里有，ArrayList 没有。\\n2. reversed() 视图消除了 TreeMap 的 DescendingMap 和 NavigableMap 的 descendingMap() 之间的不一致。\\n3. 视图而非副本的设计保证了内存效率——O(1) 空间开销。","hints":["reversed() 返回的是原始集合的逆序视图，不是数据副本","SequencedCollection 统一了 ArrayList 和 LinkedList 的首尾操作方法"],"tags":["SequencedCollection","SequencedMap","reversed","Java 21","collection-framework"],"id":1785},{"category":"java_advanced","difficulty":"hard","type":"coding","title":"泛型LRU缓存实现","content":"用Java实现一个泛型LRU缓存，满足以下要求：\n1) 支持泛型<K, V>；\n2) get()和put()时间复杂度为O(1)；\n3) 线程安全；\n4) 当容量超出时淘汰最近最少使用的条目。\n请写出完整实现并解释原理。","answer":"public class LRUCache<K, V> {\n    private final int capacity;\n    private final LinkedHashMap<K, V> cache;\n\n    public LRUCache(int capacity) {\n        this.capacity = capacity;\n        this.cache = new LinkedHashMap<K, V>(capacity, 0.75f, true) {\n            @Override\n            protected boolean removeEldestEntry(Map.Entry<K, V> eldest) {\n                return size() > LRUCache.this.capacity;\n            }\n        };\n    }\n\n    public synchronized V get(K key) {\n        return cache.get(key);\n    }\n\n    public synchronized void put(K key, V value) {\n        cache.put(key, value);\n    }\n}\n\n核心原理：LinkedHashMap的access-order=true开启访问顺序模式，每次get/put会将节点移到链表尾部（最近使用），头部即为淘汰候选。removeEldestEntry()在插入后检查容量，超限时淘汰头部。access-order模式将访问行为转化为链表操作，实现O(1)淘汰。","hints":["access-order参数是实现关键","removeEldestEntry在put后回调","synchronized取决于并发场景"],"tags":["LRU","LinkedHashMap","缓存","O(1)"],"id":1786},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"ConcurrentHashMap读操作为何无锁","content":"Java 8的ConcurrentHashMap在get()操作中完全不使用锁（lock-free），请从内部数据结构和volatile使用的角度解释其实现原理。Node的val和next字段用了什么机制保证内存可见性？","answer":"答案：Java 8 ConcurrentHashMap的get()无锁实现依赖以下机制：\n\n1) Node<K,V>的val和next字段声明为volatile，保证一个线程写入的值对其他线程立即可见；\n2) table数组引用本身也是volatile，保证扩容后新数组的可见性；\n3) 读取时先通过槽位的volatile读找到头节点，然后遍历链表/树（next同样volatile），读取节点的val；\n4) 写操作（put/remove）使用synchronized锁定桶的头节点，保证并发写入互斥；\n5) 写完成后对volatile字段的写入会建立happens-before关系，后续读必然看到最新值。\n\n简言之：写用锁保证原子性，volatile保证写结果对读可见，读通过volatile读保证看到最新链表结构，无需额外加锁。","hints":["volatile保证直接写入主存","写线程修改后读线程如何感知","JDK 8简化了Segment架构"],"tags":["ConcurrentHashMap","volatile","Lock-Free","JMM","concurrency"],"id":1787},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"volatile与synchronized语义差异","content":"关于volatile关键字和synchronized关键字的区别，以下哪项描述是正确的？","options":["A) volatile保证原子性和可见性，synchronized仅保证可见性","B) volatile保证可见性和有序性，但不保证原子性；synchronized保证可见性、有序性和原子性","C) volatile和synchronized都保证可见性和有序性，但只有synchronized可以禁止指令重排","D) volatile只能修饰基本类型，synchronized只能修饰方法"],"answer":"B","hints":["volatile不保证count++的原子性","synchronized通过Monitor实现互斥","volatile通过屏障禁止指令重排"],"tags":["volatile","synchronized","JMM","可见性","原子性"],"id":1788},{"category":"java_advanced","difficulty":"easy","type":"true_false","title":"ThreadLocal内存泄漏风险","content":"ThreadLocal在使用后若不显式调用remove()，在线程池场景下可能导致内存泄漏，其根本原因是Entry的key（ThreadLocal实例）是弱引用，但value是强引用。","options":["A) 正确","B) 错误"],"answer":"A","hints":["弱引用回收时value不会自动释放","线程池中线程长期存活引用链不断"],"tags":["ThreadLocal","memory leak","WeakReference","thread pool"],"id":1789},{"category":"java_advanced","difficulty":"hard","type":"coding","title":"有界阻塞队列实现","content":"用synchronized + wait/notify机制实现一个有界阻塞队列（BoundedBlockingQueue），支持put()和take()操作，容量固定，队列满时put阻塞，队列空时take阻塞。考虑单一锁vs两把锁的设计选择。","answer":"public class BoundedBlockingQueue<E> {\n    private final Object[] items;\n    private int takeIndex, putIndex, count;\n\n    public BoundedBlockingQueue(int capacity) {\n        if (capacity <= 0) throw new IllegalArgumentException();\n        items = new Object[capacity];\n    }\n\n    public synchronized void put(E e) throws InterruptedException {\n        while (count == items.length) {\n            wait();\n        }\n        items[putIndex] = e;\n        if (++putIndex == items.length) putIndex = 0;\n        count++;\n        notifyAll();\n    }\n\n    @SuppressWarnings(\"unchecked\")\n    public synchronized E take() throws InterruptedException {\n        while (count == 0) {\n            wait();\n        }\n        E e = (E) items[takeIndex];\n        items[takeIndex] = null;\n        if (++takeIndex == items.length) takeIndex = 0;\n        count--;\n        notifyAll();\n        return e;\n    }\n}\n\n关键点：\n1) 使用while循环而非if来检查条件（对付虚假唤醒）；\n2) 循环数组实现环形缓冲区，避免内部数组搬移；\n3) 使用notifyAll()而非notify()，防止信号丢失；\n4) 单一锁实现简单，但吞吐量不如ArrayBlockingQueue的两把锁（takeLock/putLock）分离方案。","hints":["虚假唤醒是pthreads规范允许的","环形缓冲区索引如何回绕到起点","notify可能在什么场景丢失信号"],"tags":["BlockingQueue","wait/notify","并发","环形缓冲区"],"id":1790},{"category":"java_advanced","difficulty":"easy","type":"true_false","title":"泛型类型擦除的运行时真相","content":"Java 的泛型通过类型擦除实现，运行时无法获取泛型参数的具体类型。因此 List<String> 和 List<Integer> 在运行时是相同的 Class 对象。\nA) 正确\nB) 错误","answer":"A","hints":["反射调用 getTypeParameters 返回的是类型变量而非实际参数","通过匿名内部类可以绕开擦除获取类型信息"],"tags":["Java","泛型","类型擦除"],"id":1791},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"ClassLoader 双亲委派模型的核心机制","content":"关于 ClassLoader 双亲委派模型的描述，哪一项是正确的？\nA) 类加载时首先由子 ClassLoader 尝试加载，加载失败后才交给父 ClassLoader\nB) 自定义 ClassLoader 必须重写 loadClass 方法才能遵循双亲委派模型\nC) loadClass 方法的核心逻辑是先委派父 ClassLoader 加载，父加载失败后才由自己尝试加载\nD) Thread.currentThread().getContextClassLoader() 返回当前类所属的 ClassLoader","answer":"答案：C","hints":["双亲委派是自底向上检查、自顶向下尝试加载","findClass 和 loadClass 的分工是关键设计"],"tags":["Java","ClassLoader","双亲委派"],"id":1792},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"JIT 编译的核心优化技术详解","content":"请列举 HotSpot JVM 中至少 5 种 JIT 编译优化技术，并重点说明方法内联和逃逸分析的工作原理。方法内联在哪些场景下会失效？逃逸分析的标量替换如何实现栈上分配？","answer":"答案：主要优化技术：1) 方法内联 2) 逃逸分析（含标量替换和锁消除）3) 循环优化（展开、不变代码外提）4) 空值检查消除 5) 类型精确推断（CHA）6) 窥孔优化。\n方法内联：将目标方法体直接复制到调用者代码中，消除方法调用和栈帧创建开销。阈值：方法体默认不超过 325 字节（-XX:MaxInlineSize），调用次数达到编译阈值（默认 10000）。内联失效条件：方法体过大、虚方法无法通过 CHA 确定唯一实现、-XX:-Inline 禁用内联。\n逃逸分析：分析对象引用是否逃逸出方法或线程边界。若未逃逸，JIT 可执行标量替换——将对象字段拆解为独立局部变量分配在栈上或寄存器中，而非在堆上分配完整对象。这消除了 GC 压力，对象随栈帧弹出自动回收。\n锁消除：若逃逸分析发现 synchronized 对象的引用不会逃逸到其他线程，JIT 会移除锁获取操作。","hints":["CHA 是方法内联的核心支撑技术","标量替换后对象可能完全不存在于堆中"],"tags":["JVM","JIT","逃逸分析","方法内联"],"id":1793},{"category":"java_advanced","difficulty":"hard","type":"coding","title":"实现遵循双亲委派的自定义 ClassLoader","content":"请实现一个自定义 ClassLoader，能够从指定包前缀的字节数组中加载类。要求：1) 严格遵循双亲委派模型 2) 只负责加载特定包前缀的类，其余交回父加载器 3) 说明 defineClass 和 resolveClass 的分工职责。","answer":"public class ByteArrayClassLoader extends ClassLoader {\n    private final String allowedPrefix;\n    private final Map<String, byte[]> classBytes;\n\n    public ByteArrayClassLoader(String allowedPrefix, Map<String, byte[]> classBytes, ClassLoader parent) {\n        super(parent);\n        this.allowedPrefix = allowedPrefix;\n        this.classBytes = classBytes;\n    }\n\n    @Override\n    protected Class<?> findClass(String name) throws ClassNotFoundException {\n        byte[] bytes = classBytes.get(name);\n        if (bytes == null) throw new ClassNotFoundException(name);\n        return defineClass(name, bytes, 0, bytes.length);\n    }\n\n    @Override\n    protected Class<?> loadClass(String name, boolean resolve) throws ClassNotFoundException {\n        if (!name.startsWith(allowedPrefix)) {\n            return super.loadClass(name, resolve);\n        }\n        Class<?> c = findLoadedClass(name);\n        if (c == null) {\n            try {\n                c = getParent().loadClass(name);\n            } catch (ClassNotFoundException e) {\n                c = findClass(name);\n            }\n        }\n        if (resolve) resolveClass(c);\n        return c;\n    }\n}\n\ndefineClass 职责：将 byte[] 转换为 Class 对象，内部校验字节码格式、验证常量池、检查 illegal access 等安全问题。resolveClass 职责：执行类的链接阶段（验证、准备、解析符号引用）。不调用 resolveClass 类仍可正常使用和实例化，符号引用在需要时按需解析。","hints":["findClass 是扩展点，loadClass 是委派逻辑","resolveClass 决定符号引用何时被解析"],"tags":["Java","ClassLoader","双亲委派","类加载机制"],"id":1794},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"Java 模块系统的封装边界与反射授权","content":"Java 9 模块系统如何解决类路径和访问控制层面的问题？exports 和 opens 在语义上有何本质区别？为什么 JPMS 要求「深度反射」必须通过 opens 显式授权？","answer":"答案：JPMS 解决的核心问题：1) 强封装——模块内包默认对外不可见，即使 public 类型也无法被外部访问 2) 可靠配置——声明式 requires transitive 建立依赖，不再依赖 Class-Path 隐式约定 3) 消除类路径地狱——模块路径不允许 split package，保证每个包唯一 4) 未命名模块保留向后兼容。\nexports 与 opens 的区别：exports 将包中的 public 类型开放给其他模块编译期和运行时正常调用；opens 将包中所有类型（含 private 成员）开放给运行时反射访问，但编译期不可见。\n深度反射需 opens 授权的原因：反射通过 setAccessible(true) 可以突破封装边界——访问 private 字段、调用私有方法。无模块化时代 setAccessible 可无条件突破一切可见性限制。JPMS 的设计哲学是「显式授权」：模块必须通过 opens 声明自愿开放包的反射权限。这既增强了安全性，也保留了 Spring、Hibernate 等框架的反射需求路径。","hints":["exports 只开放 public 类型的正常调用","opens 是反射特权操作的安全授权通道"],"tags":["Java","JPMS","模块系统","反射"],"id":1795},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"JFR 自定义事件开发","content":"Java Flight Recorder (JFR) 自 JDK 14 起已开源（JEP 349），允许用户自定义事件。请说明创建和提交一个 JFR 自定义事件所需的步骤：使用的基类是什么？需要哪些注解？事件的生命周期（配置 -> 创建 -> 提交）是怎样的？","answer":"答案：创建 JFR 自定义事件的步骤：\n1. 创建一个继承 `jdk.jfr.Event` 的类\n2. 使用 `@Label`、`@Description`、`@Timestamp`、`@MemoryAddress` 等注解标记字段（字段类型支持 boolean、int、long、float、double、String、Class、Thread 等）\n3. 可选：使用 `@Category` 给事件分组，使用 `@Enabled(true/false)` 控制默认启用状态\n4. 在使用处实例化事件对象（轻量操作，远轻于 log4j 日志），调用 event.begin()（可选）、设置字段值、调用 event.commit() 提交\n5. 事件提交后字段值被快照到 JFR 内部环形缓冲区，之后事件对象可被 GC\n6. 运行期可通过 `-XX:StartFlightRecording:settings=...` 启用或通过 JCMD 动态控制\n需要注意的是：事件类以 `jdk.jfr.Event` 引用时，JIT 会将其分配路径内联优化为极低开销（纳秒级），这是 JFR 低开销的核心机制。","hints":["JFR 事件框架通过 JIT 内联和 allocation merging 实现极低开销，与普通 Java 对象的分配路径不同","事件启用/禁用可由配置 files（.jfc 文件）或 programmatic configuration 控制，禁用的事件几乎零开销（只生成一个空方法调用）"],"tags":["JFR","jep-349","event","profiling","monitoring"],"id":1796},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"JDK 9+ String 拼接 invokeDynamic 优化","content":"在 JDK 9+ 中，Java 编译器将 String 的 + 拼接操作符编译为 invokedynamic 调用，而非传统的 StringBuilder。以下关于这种优化的描述，哪项是正确的？\nA) invokedynamic 方式在每次运行时都通过反射构造 StringBuilder，因此比 JDK 8 的显式 StringBuilder 更慢\nB) invokedynamic 方式使用 StringConcatFactory 作为 bootstrap method，在首次调用时生成最优的拼接实现策略，后续调用直接使用生成的 MethodHandle，JIT 可进一步内联优化\nC) invokedynamic 方式仅适用于 String 字面量的拼接，变量拼接仍然使用 StringBuilder\nD) 拼接结果仍然通过 StringBuilder.toString() 返回，只是创建 StringBuilder 的方式改用了 invokedynamic","answer":"答案：B) invokedynamic 方式使用 StringConcatFactory 作为 bootstrap method，在首次调用时根据参数数量和类型选择最优策略（如直接构造字符数组、StringBuilder 或 StringBuffer），生成并缓存 MethodHandle。JIT 可以进一步将生成的拼接代码内联到调用点，消除方法分派开销。这种方式比 JDK 8 固定使用 StringBuilder 更灵活且性能更优。","hints":["invokedynamic 的核心优势在于延迟决策——编译期不确定的策略在运行期首次调用时选择并固化","bootstrap method 返回的是一个 MethodHandle，不是反射调用——这是关键区别"],"tags":["string-concatenation","invokedynamic","stringconcatfactory","jep-280","java-9"],"id":1797},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"JIT 分层编译中 C1 和 C2 的协作机制","content":"HotSpot VM 的分层编译（Tiered Compilation）将编译分为 5 个级别（0-4）。以下关于各编译级别之间协作机制的描述，哪项是正确的？\nA) 代码从 level 0（解释器）直接升级到 level 4（C2），中间不经过带 profiling 的编译级别\nB) level 2（C1 不带 profiling）和 level 3（C1 带 profiling）是可选的中间状态；C2 编译基于 level 3 收集的类型 profiling 信息做出更激进的优化决策，如虚方法内联和分支预测\nC) C1 编译的所有级别（1-3）都不记录运行时类型信息，这些信息仅在解释器中收集\nD) level 3 带 profiling 的 C1 代码与 level 4 C2 代码可以共存，但 JVM 不会自动从 level 4 回退到较低级别","answer":"答案：B) level 2（C1 不带 profiling）和 level 3（C1 带 profiling）是可选中间状态。典型的升级路径是：0（解释器）-> 3（C1 带 profiling）-> 4（C2）。C1 的 level 3 收集方法调用频次、分支走向 profile、类型接收者分布等关键数据；C2 利用这些 profile 信息进行激进的优化，包括内联、锁消除、标量替换、循环展开等。所以 B 正确。A 错误——分层编译从 level 0 逐步升级。C 错误——C1 在 level 3 会收集 profiling。D 前半句正确，但 JVM 确实不会从 4 回退到更低级别（deoptimization 会回到解释器，不是回到 C1）。","hints":["分层编译各级别：0=解释器, 1=C1 简单, 2=C1 受限, 3=C1 全 profile, 4=C2","C2 的优化质量依赖 C1 收集的 profile 数据——包括分支命中率和类型接收者分布"],"tags":["JIT","tiered-compilation","C1","C2","hotspot-profile"],"id":1798},{"category":"java_advanced","difficulty":"easy","type":"true_false","title":"Epsilon GC 在内存耗尽时的行为","content":"Epsilon GC（JEP 318）是一种无操作（no-op）垃圾收集器。当堆内存耗尽时，Epsilon GC 不会触发任何垃圾收集，而是直接抛出 OutOfMemoryError。如果堆中仍有大量可回收的不可达对象，Epsilon GC 也不会回收它们。","options":["A) 正确","B) 错误"],"answer":"A) 正确","hints":["Epsilon GC 的设计目标就是零开销的内存分配——它只负责分配，不做任何回收","JEP 318 明确指出 Epsilon GC 适用于短生命周期的服务、性能测试和延迟敏感场景"],"tags":["epsilon-gc","jep-318","GC","no-op-gc","outofmemoryerror"],"id":1799},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"ScopedValue 与 ThreadLocal 核心区别","content":"ScopedValue（JEP 429，JDK 21+）是 JDK 新引入的线程上下文传值机制。请说明 ScopedValue 与 ThreadLocal 在以下三个方面的核心区别：1) 可变性约束 2) 生命周期范围 3) 对虚拟线程继承行为的支持。","answer":"答案：1) 可变性约束：ThreadLocal 的值可通过 set() 方法任意修改；ScopedValue 的值是不可变的——一旦在 `where(key, value).run(...)` 中绑定，在该 Runnable 执行期间不能修改，保证了数据的不变性。\n2) 生命周期范围：ThreadLocal 的值从 set() 到 remove() 一直存在（或直到线程死亡），容易出现内存泄漏（尤其在线程池场景）；ScopedValue 的值的生命周期严格限定在 Callable/Runnable 的执行范围内，执行完成后自动释放，从根本上消除了内存泄漏风险。\n3) 对虚拟线程继承：ThreadLocal 的可继承性（InheritableThreadLocal）在线程池场景下语义混乱，且虚拟线程中不推荐使用；ScopedValue 天然支持虚拟线程的「不切割上下文」语义——虚拟线程可以透明地访问其创建者的 ScopedValue，不需要显式的继承机制。","hints":["从不可变性和确定性角度看，ScopedValue 更像是方法的隐式参数，而不是可变的线程局部变量","ScopedValue 的 bounded 模式（rebind）虽然允许在嵌套作用域中绑定新值，但仍遵循 stack-like 的进出规则"],"tags":["ScopedValue","ThreadLocal","Virtual Threads","jep-429","Java 21"],"id":1800},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"Thread.onSpinWait() 自旋提示语义与 JIT 编译器的优化响应","content":"请详细解释 Thread.onSpinWait() 方法（JDK 9+）的核心语义。它在 JIT 编译器层面产生了什么影响？在 x86 平台上它被编译成什么指令？与 Thread.yield() 在行为上有哪些本质区别？适用场景是什么？","answer":"答案：Thread.onSpinWait() 向 JIT 编译器发出「当前线程正在自旋等待」的提示，在 x86 平台上被编译为 PAUSE 指令（AArch64 上映射为 ISB 或 YIELD 指令）。核心语义包括：1) 提示处理器当前正在执行自旋循环，减少内存顺序违规（memory order violation）导致的流水线冲刷性能惩罚——PAUSE 指令告诉 CPU 不要对自旋循环进行激进的内存排序推测；2) 允许 JIT 编译器调整自旋循环的优化策略，例如避免过度循环展开、在自旋循环中插入定时器中断检查等。与 Thread.yield() 的本质区别：yield() 是线程调度提示，可能导致当前线程被切换出 CPU（从 RUNNING 变为 RUNNABLE 但不运行），带来上下文切换开销和调度延迟；而 onSpinWait() 不会触发线程切换——当前线程继续保持运行状态。适用场景：在实现自旋锁、低延迟队列、Phaser 和 StampedLock 等并发原语的短暂等待阶段（预计等待时间远小于线程切换开销时），onSpinWait() 是比 LockSupport.park() 更轻量的选择。","hints":["JDK 内部在 Phaser、StampedLock、ForkJoinPool 等并发实现中大量使用 Thread.onSpinWait() 优化短暂自旋","x86 PAUSE 指令延迟约为 20-40 个周期，能显著降低超线程环境下自旋循环的功耗和内存顺序冲突"],"tags":["Thread.onSpinWait","PAUSE","自旋优化","JIT","并发原语"],"options":[],"company":"","id":1801},{"category":"java_advanced","difficulty":"easy","type":"short_answer","title":"ConstantDynamic (Condy) 引导方法解析机制","content":"ConstantDynamic（Condy，JDK 11+ JEP 309）允许在 class 文件的常量池中定义用户自定义常量。以下关于 Condy 引导方法解析机制的描述，哪项是正确的？\nA) 引导方法在类加载阶段对所有 Condy 常量池条目进行批量调用，并将结果缓存到运行时常量池\nB) 引导方法在 JIT 编译阶段被调用，编译结果直接嵌入机器码，不经过运行时常量池\nC) 引导方法在 CONSTANT_Dynamic 常量池条目首次被解析时调用，结果由 JVM 缓存供后续访问复用\nD) 引导方法每次访问 Condy 常量时都被重新调用，以确保返回值的「新鲜度」","answer":"答案：C) Condy 的引导方法（bootstrap method）在 class 文件的 BootstrapMethods 属性中定义。当运行时常量池中的 CONSTANT_Dynamic 条目首次被某条字节码指令实际访问时，JVM 调用对应的引导方法并将结果缓存。此后对同一常量池条目的访问直接返回缓存值，不再重复调用引导方法。引导方法的固定签名为 (MethodHandles.Lookup, String, Class<?>)，后续参数由 BootstrapMethods 属性中的参数指定。这意味 Condy 具有懒加载语义——从未被实际使用的 Condy 条目永远不会触发引导方法调用。实际应用包括：延迟初始化编译时常量、实现语言级元编程、提供更灵活的常量定义方式。","hints":["Condy 与 invokedynamic 共享 BootstrapMethods 属性，但 Condy 的引导方法不涉及 CallSite 规格化，直接返回常量值","Condy 的缓存语义由 JVMS 5.4.3.6 定义：解析一旦完成，结果在常量池条目的生命周期内保持不变"],"tags":["ConstantDynamic","Condy","引导方法","常量池","JEP 309"],"options":[],"company":"","id":1802},{"category":"java_advanced","difficulty":"easy","type":"true_false","title":"VarHandle opaque 模式的内存排序语义","content":"VarHandle 的 opaque 模式（setOpaque/getOpaque）保证了对变量的原子性访问和完全的有序性保证，即禁止编译器和处理器对该变量相关的所有内存操作进行重排序。","answer":"B) 错误","hints":["Opaque 模式只保证原子性和位的可见性（bitwise consistency），不提供任何跨线程重排序保证——它仅禁止比它更弱的非原子访问（torn read/write）","VarHandle 的三种内存排序模式强度递增：opaque < acquire/release < full fence（volatile语义）"],"tags":["VarHandle","内存排序","opaque","JMM","JEP 193"],"options":["A) 正确","B) 错误"],"company":"","id":1803},{"category":"java_advanced","difficulty":"hard","type":"short_answer","title":"JVMCI 与 Graal JIT 编译器集成机制","content":"请详细解释 JVMCI（JVM Compiler Interface，JEP 243）的作用和架构。Graal JIT 编译器如何通过 JVMCI 与 HotSpot JVM 集成？-XX:+UseJVMCINativeLibrary 参数启用后发生了哪些架构变化？JVMCI 与 JVMTI 的本质区别是什么？","answer":"答案：JVMCI（JVM Compiler Interface）是 JDK 9（JEP 243）引入的 Java 级 JIT 编译器接口，允许用 Java 语言（而非 C++）编写 JIT 编译器并集成到 HotSpot JVM 中。核心架构：JVMCI 定义了 HotSpot JVM 与编译器之间的双向通信协议——编译器从 JVM 获取编译请求、类型信息、profiling 数据，编译完成后将编译结果（compiled code 安装信息）回传给 JVM。Graal 编译器通过 JVMCI 成为 HotSpot 的顶级 JIT 编译器，可替代 C2（-XX:+UseJVMCICompiler）。-XX:+UseJVMCINativeLibrary（JDK 16+）将 Graal 编译器编译为 native shared library（通过 GraalVM Native Image），通过 JNI 与 HotSpot 通信。这一变化的关键意义在于 Graal 编译器本身不再运行于 HotSpot 之上，解决了「编译自己的编译器」的递归问题，显著降低编译时的 GC 压力和内存占用。与 JVMTI 的本质区别：JVMTI 是 C/C++ 级原生代理接口，用于监控、调试、分析；JVMCI 是为编译器优化而设计的 Java 级 API，提供类型系统、编译器 IR 构建等编译器专用的抽象能力。","hints":["JVMCI 在 JDK 9 为实验特性（--add-modules jdk.internal.vm.ci），JDK 16 转正但仍需 --XX:+UnlockExperimentalVMOptions","GraalVM 的 Native Image 和 Truffle 框架也基于 JVMCI 实现——它不仅是 JIT 接口，更是 Java 与底层 JVM 之间的元编程接口"],"tags":["JVMCI","Graal","JIT","编译器接口","HotSpot"],"options":[],"company":"","id":1804},{"category":"java_advanced","difficulty":"medium","type":"short_answer","title":"Continuation 原理解析——虚拟线程挂起与恢复的底层调度原语","content":"请解释 jdk.internal.vm.Continuation 在虚拟线程实现中的核心作用。什么是「栈冻结」（stack freeze）和「栈解冻」（stack thaw）？为什么虚拟线程在 synchronized 块或 native 方法中被阻塞时会出现「pinned」现象？Continuation 栈与平台线程栈在内存管理上的根本差异是什么？","answer":"答案：Continuation 是 Project Loom 引入的 JVM 内部可挂起执行原语，能够捕获当前执行栈的状态（方法调用链、局部变量、操作数栈）并保存到堆内存中的 Continuation 对象中。栈冻结（stack freeze）将栈帧从 carrier 线程的 native 栈复制到堆上的 byte[] 数组中（称为 frozen stack），随后 carrier 线程可以运载其他虚拟线程。栈解冻（stack thaw）将堆中的 frozen stack 帧复制回当前 carrier 线程的 native 栈，继续执行。Pinned 现象：当虚拟线程在 synchronized 块或 native 方法中被阻塞时，栈上存在 native 栈帧——Continuation 的栈冻结机制无法安全地捕获和复制 native 栈帧（native 栈帧包含平台相关的寄存器状态和栈布局信息），因此 JVM 无法在该点挂起虚拟线程，导致 carrier 线程被「钉住」（pinned），无法切换到其他虚拟线程。Continuation 栈与平台线程栈的根本差异：平台线程栈是固定在 native 内存中的连续区域（默认 1MB），整个生命周期内不可移动；而 Continuation 的 frozen stack 存储在 GC 可管理的堆中，体积仅与实际调用深度相关（初始仅数百字节），可被 GC 移动和压缩。这使得一个 carrier 线程（通常 ForkJoinPool 中的 worker）可以运载数千个虚拟线程的 Continuation，实现高效的 M:N 调度。","hints":["Continuation.yield() 触发栈冻结后控制权返回到虚拟线程调度器，调度器将 carrier 线程分配给其他就绪的虚拟线程","JDK 21 中虚拟线程在 ReentrantLock 上阻塞不会 pinned——因为 ReentrantLock 使用 LockSupport.park() 而非 synchronized 实现阻塞，park 操作会触发 Continuation.yield()"],"tags":["Continuation","虚拟线程","栈冻结","Project Loom","调度原语"],"options":[],"company":"","id":1805},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"JVM 运行时数据区域","content":"以下哪个不是 JVM 运行时数据区的组成部分？","answer":"D) 直接内存。解析：JVM 运行时数据区包括：程序计数器、虚拟机栈、本地方法栈、堆、方法区。直接内存（Direct Memory）不是 JVM 运行时数据区的一部分，它是 NIO 在堆外分配的内存，但受物理内存限制。","options":["A) 堆","B) 虚拟机栈","C) 方法区","D) 直接内存"],"hints":["区分 JVM 管理的内存和堆外内存"],"tags":["JVM","内存管理"],"id":1806},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"堆内存的分代结构","content":"关于 Java 堆内存分代，以下说法正确的是？","answer":"B) 对象首先在 Eden 区分配，经过 Minor GC 后进入 Survivor 区。解析：大多数新创建的对象首先在 Eden 区分配。Eden 区满时触发 Minor GC（Young GC），存活对象复制到 Survivor 区。经过多次 GC 仍然存活的对象（默认 15 次）晋升到老年代。","options":["A) 对象创建后直接进入老年代","B) 对象首先在 Eden 区分配，经过 Minor GC 后进入 Survivor 区","C) 所有对象都在老年代创建，根据使用频率降级到年轻代","D) Survivor 区满了才会触发 Minor GC"],"hints":["大多数对象都是朝生夕死的"],"tags":["JVM","堆内存"],"id":1807},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"GC Roots 包括哪些","content":"以下哪个不是可以作为 GC Roots 的对象？","answer":"C) 方法区中未被引用的常量。解析：GC Roots 包括：虚拟机栈中引用的对象、静态属性引用的对象、常量引用的对象、本地方法栈中 JNI 引用的对象。未被引用的常量自身可能已经被判定为无用常量，不能作为根。","options":["A) 虚拟机栈中引用的对象","B) 方法区中静态属性引用的对象","C) 方法区中未被引用的常量","D) 本地方法栈中 JNI 引用的对象"],"hints":["可作为 GC Root 的对象必须是活跃的引用"],"tags":["JVM","GC"],"id":1808},{"category":"java_advanced","difficulty":"hard","type":"choice","title":"CMS 与 G1 垃圾回收器的区别","content":"关于 CMS 和 G1 垃圾回收器的区别，以下说法错误的是？","answer":"D) G1 的停顿时间比 CMS 更短且完全可预测。解析：G1 通过 -XX:MaxGCPauseMillis 设置目标停顿时间，但这是软目标，并非绝对保证。G1 的停顿时间通常比 CMS 更可控，但不能完全可预测。CMS 已被 JDK 14 标记为移除，G1 是 JDK 9+ 的默认 GC。","options":["A) G1 是分代的、区域化的垃圾回收器","B) CMS 使用标记-清除算法，会产生内存碎片","C) G1 将堆划分为多个 Region，支持可预测的停顿","D) G1 的停顿时间比 CMS 更短且完全可预测"],"hints":["停顿时间目标和硬实时系统要求的区别"],"tags":["JVM","GC"],"id":1809},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"双亲委派模型","content":"关于双亲委派模型，以下说法正确的是？","answer":"A) 类加载器收到类加载请求时，先将请求委派给父类加载器加载。解析：双亲委派模型的核心是：当前类加载器收到加载请求时，不会自己尝试加载，而是先委派给父类加载器。每层都是如此，因此所有加载请求最终都应该到达启动类加载器。只有当父加载器无法加载（抛出 ClassNotFoundException）时，子加载器才会尝试自己加载。","options":["A) 类加载器收到类加载请求时，先将请求委派给父类加载器加载","B) 类加载器收到类加载请求时，先自己尝试加载，失败后再委派给父加载器","C) 双亲委派模型可以避免类被重复加载，但会降低安全性","D) 双亲委派模型只在 JDK 8 及以下版本中使用"],"hints":["双亲委派的核心目的是什么？"],"tags":["JVM","类加载"],"id":1810},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"类加载的完整过程","content":"JVM 类加载过程按顺序包括哪些阶段？","answer":"B) 加载 → 验证 → 准备 → 解析 → 初始化。解析：类加载包括 5 个阶段：加载（Loading）→ 验证（Verification）→ 准备（Preparation）→ 解析（Resolution）→ 初始化（Initialization）。验证确保 Class 文件字节流安全，准备为静态变量分配内存并设默认值，解析将符号引用转为直接引用，初始化执行类构造器 <clinit>() 方法。","options":["A) 加载 → 准备 → 验证 → 初始化 → 解析","B) 加载 → 验证 → 准备 → 解析 → 初始化","C) 加载 → 验证 → 初始化 → 准备 → 解析","D) 加载 → 解析 → 验证 → 准备 → 初始化"],"hints":["初始化是最后一步","顺序是固定的"],"tags":["JVM","类加载"],"id":1811},{"category":"java_advanced","difficulty":"hard","type":"choice","title":"OOM 常见场景","content":"以下哪种操作最可能导致 OutOfMemoryError: Metaspace？","answer":"B) 运行时大量生成动态代理类或 CGLIB 代理类。解析：Metaspace（元空间）用于存储类元信息。大量动态生成代理类（如 CGLIB、Javassist）会填满 Metaspace 导致 OOM。堆溢出常见于大对象或内存泄漏，栈溢出常见于递归调用过深。","options":["A) 循环创建大量 Java 对象不释放","B) 运行时大量生成动态代理类或 CGLIB 代理类","C) 递归调用深度过大","D) 创建超大数组"],"hints":["区分堆、栈、元空间的溢出场景"],"tags":["JVM","OOM"],"id":1812},{"category":"java_advanced","difficulty":"hard","type":"choice","title":"Java 引用类型","content":"以下哪种引用在 GC 被触发时一定会被回收？","answer":"D) 软引用和弱引用。解析：软引用（SoftReference）在内存不足时回收，弱引用（WeakReference）在下一次 GC 时回收。虚引用（PhantomReference）主要用于跟踪对象被回收的状态。强引用（Strong Reference）永远不会被 GC 回收，是导致内存泄漏的常见原因。","options":["A) 强引用一定会被回收","B) 弱引用只在内存不足时回收","C) 软引用的对象在下一次 GC 时一定被回收","D) 软引用和弱引用在 GC 时都会被回收"],"hints":["软引用和弱引用的回收时机不同"],"tags":["JVM","引用"],"id":1813},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"JDK 8 接口的新特性","content":"JDK 8 允许在接口中定义哪种类型的方法？","answer":"B) 默认方法和静态方法。解析：JDK 8 引入了接口的默认方法（default method）和静态方法（static method）。默认方法通过 default 关键字定义，子类可以选择重写或继承。静态方法只能通过接口名直接调用。这一变化使得接口在演化时能向后兼容。","options":["A) 私有方法","B) 默认方法和静态方法","C) 受保护方法","D) final 方法"],"hints":["JDK 8 中接口有哪些变化？"],"tags":["Java 8","接口"],"id":1814},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"Lambda 表达式本质","content":"Java 中的 Lambda 表达式的本质是什么？","answer":"A) 函数式接口的匿名实现。解析：Lambda 表达式本质上是函数式接口（只有一个抽象方法的接口）的匿名实现。编译器通过 invokedynamic 指令将 Lambda 转换为对应的函数式接口实例。常见的函数式接口有 Runnable、Comparator、Function、Predicate、Consumer 等。","options":["A) 函数式接口的匿名实现","B) 匿名内部类的语法糖","C) 一种新的数据类型","D) 运行时动态生成的方法"],"hints":["Lambda 表达式的目标类型是什么？"],"tags":["Java 8","Lambda"],"id":1815},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"Stream 中间操作与终止操作","content":"以下哪个是 Stream 的终止操作？","answer":"D) collect。解析：Stream 操作分为中间操作（Intermediate）和终止操作（Terminal）。中间操作返回 Stream，惰性执行（如 map、filter、sorted）。终止操作触发实际计算并消耗 Stream（如 collect、forEach、reduce、count）。filter、map、sorted 都是中间操作，collect 是终止操作。","options":["A) filter","B) map","C) sorted","D) collect"],"hints":["终止操作会消耗 Stream"],"tags":["Java 8","Stream"],"id":1816},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"Optional 的主要用途","content":"Optional 的主要用途是什么？","answer":"B) 避免 NullPointerException，更优雅地处理可能为 null 的值。解析：Optional 是一个容器对象，用于表示一个值存在或不存在。通过显式告诉调用者返回值可能为空，强制调用者处理空值情况，从而减少 NPE。但不建议将 Optional 作为字段类型、方法参数或序列化对象使用。","options":["A) 提高方法的执行效率","B) 避免 NullPointerException，更优雅地处理可能为 null 的值","C) 替代 try-catch 异常处理","D) 实现对象的深拷贝"],"hints":["Optional 的设计初衷是什么？"],"tags":["Java 8","Optional"],"id":1817},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"synchronized 的底层实现","content":"JDK 8 中 synchronized 关键字的底层实现机制是？","answer":"C) 基于 Monitor 对象，通过锁升级（偏向锁→轻量级锁→重量级锁）实现。解析：JDK 8 中 synchronized 通过 Monitor（监视器锁）实现。锁有四种状态：无锁→偏向锁→轻量级锁→重量级锁，在 JDK 6 之后引入的锁升级机制减少了锁的开销。偏向锁在只有一个线程访问时避免真正的同步，轻量级锁使用 CAS 自旋，重量级锁阻塞其他线程。","options":["A) 始终使用互斥量实现，性能较差","B) 基于 AQS 中的 CLH 队列实现","C) 基于 Monitor 对象，通过锁升级实现","D) 使用 atomic 变量实现"],"hints":["JDK 6 之后对 synchronized 做了哪些优化？"],"tags":["并发","synchronized"],"id":1818},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"volatile 关键字的作用","content":"volatile 关键字保证哪些特性？","answer":"A) 保证可见性和禁止指令重排序，但不保证原子性。解析：volatile 能保证：1）可见性——一个线程修改 volatile 变量后，其他线程立即可见；2）禁止指令重排序——插入内存屏障防止编译器或 CPU 重排。但 volatile 不保证原子性，如 count++ 操作仍需加锁。","options":["A) 保证可见性和禁止指令重排序，但不保证原子性","B) 保证可见性和原子性","C) 保证可见性、原子性和有序性","D) 只保证可见性"],"hints":["volatile 适合什么场景？"],"tags":["并发","volatile"],"id":1819},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"ThreadPoolExecutor 的核心参数","content":"ThreadPoolExecutor 的参数中，当任务数超过核心线程数且阻塞队列已满时的处理方式是？","answer":"C) 创建新线程（不超过最大线程数），如果已达最大线程数则执行拒绝策略。解析：线程池的工作流程：1）任务数 < corePoolSize → 创建核心线程执行；2）任务数 ≥ corePoolSize → 加入阻塞队列；3）队列满且线程数 < maximumPoolSize → 创建临时线程；4）队列满且线程数已达最大值 → 执行 RejectedExecutionHandler 拒绝策略。","options":["A) 直接抛出异常","B) 丢弃该任务","C) 创建新线程，如果已达最大线程数则执行拒绝策略","D) 阻塞等待线程空闲"],"hints":["线程池参数包括 corePoolSize、maximumPoolSize、workQueue"],"tags":["并发","线程池"],"id":1820},{"category":"java_advanced","difficulty":"hard","type":"choice","title":"AQS 的核心原理","content":"AQS（AbstractQueuedSynchronizer）的核心实现原理是？","answer":"B) 基于 volatile int state + CLH 双向队列 + CAS 操作。解析：AQS 是 JUC 锁和同步器的基类。核心数据结构：volatile int state（同步状态）+ CLH 双向队列（等待队列）+ CAS（原子操作）。子类通过重写 tryAcquire/tryRelease 等方法定义获取和释放资源的逻辑。ReentrantLock、Semaphore、CountDownLatch 都基于 AQS。","options":["A) 基于 synchronized 实现的阻塞队列","B) 基于 volatile int state + CLH 双向队列 + CAS 操作","C) 基于 ThreadLocal 实现线程隔离","D) 基于 HashMap 存储等待线程"],"hints":["ReentrantLock、Semaphore、CountDownLatch 都基于 AQS"],"tags":["并发","AQS"],"id":1821},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"ReentrantLock 与 synchronized 的区别","content":"以下关于 ReentrantLock 和 synchronized 的说法，错误的是？","answer":"D) synchronized 支持超时获取锁。解析：synchronized 不支持超时获取锁，线程获取不到锁时会一直阻塞。ReentrantLock 提供了 tryLock(long timeout, TimeUnit unit) 支持超时获取锁。其他区别：ReentrantLock 支持公平锁、可中断锁、条件变量（Condition），synchronized 自动释放锁，ReentrantLock 需要手动 unlock。","options":["A) ReentrantLock 支持公平锁和非公平锁","B) synchronized 是隐式锁，自动释放","C) ReentrantLock 支持多个 Condition 条件变量","D) synchronized 支持超时获取锁"],"hints":["synchronized 和 ReentrantLock 的获取方式有什么不同？"],"tags":["并发","锁"],"id":1822},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"CAS 操作存在的问题","content":"CAS（Compare And Swap）操作可能面临的问题不包括？","answer":"C) 死锁。解析：CAS 是乐观锁机制，常见问题包括：ABA 问题（通过 AtomicStampedReference 加版本号解决）、自旋开销（长时间自旋浪费 CPU）、只能保证单个变量的原子操作。CAS 不会导致死锁（因为没有锁等待），死锁通常发生在锁的嵌套使用中。","options":["A) ABA 问题","B) 自旋开销大","C) 死锁","D) 只能保证单个变量原子操作"],"hints":["CAS 是非阻塞的"],"tags":["并发","CAS"],"id":1823},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"Java 线程的六种状态","content":"Java 线程在生命周期中不包含以下哪种状态？","answer":"D) 运行中（Running）。解析：Java 线程的 6 种状态定义在 Thread.State 枚举中：NEW（新建）、RUNNABLE（可运行，包含就绪和运行）、BLOCKED（阻塞等待锁）、WAITING（无限等待）、TIMED_WAITING（超时等待）、TERMINATED（终止）。JVM 层面的 RUNNABLE 状态合并了操作系统层面的就绪（Ready）和运行（Running）状态。","options":["A) NEW","B) BLOCKED","C) WAITING","D) Running"],"hints":["Thread.State 枚举中有哪些值？"],"tags":["并发","线程"],"id":1824},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"JDK 8 接口默认方法的冲突解决","content":"当一个类实现了两个接口，两个接口中有相同签名的默认方法时，以下说法正确的是？","answer":"A) 必须在实现类中重写该方法，否则编译报错。解析：如果一个类同时实现了两个具有相同签名默认方法的接口，编译器会报错，强制要求实现类重写该方法以消除歧义。可以在重写中使用 InterfaceName.super.methodName() 指定使用哪个接口的默认实现。","options":["A) 必须在实现类中重写该方法，否则编译报错","B) 编译通过，运行时报错","C) 自动使用第一个接口的默认方法","D) 自动使用第二个接口的默认方法"],"hints":["钻石问题在 Java 接口中如何解决？"],"tags":["Java 8","接口"],"id":1825},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"JVM 参数类型的区分","content":"关于 JVM 参数类型的说法，以下正确的是？","answer":"C) -X 参数并非标准参数，可能在不同 JDK 版本中变化。解析：JVM 参数分三类：标准参数（-D、-verbose 等，所有 JVM 实现都支持），-X 非标准参数（如 -Xmx、-Xms，功能稳定但不保证在所有 JVM 实现中支持），-XX 非稳定参数（如 -XX:+UseG1GC，可能在不同版本间变更或移除）。","options":["A) -X 参数是标准参数，所有 JVM 实现都必须支持","B) -XX 参数在所有 JDK 版本中完全一致","C) -X 参数并非标准参数，可能在不同 JDK 版本中变化","D) 标准参数以 -XX: 开头"],"hints":["JVM 参数有三类：标准参数、-X 扩展参数、-XX 高级参数"],"tags":["JVM","参数调优"],"id":1826},{"category":"java_advanced","difficulty":"hard","type":"choice","title":"G1 垃圾回收器的工作方式","content":"关于 G1（Garbage First）垃圾回收器的特性，以下说法正确的是？","answer":"B) G1 将堆划分为多个 Region，优先回收垃圾最多的 Region。解析：G1 将堆划分为大小相等的 Region（约 1-32MB），通过维护每个 Region 的垃圾比例优先级列表，优先回收垃圾最多的 Region，从而在有限停顿时间内获得最大收益。G1 是 JDK 9 开始的默认 GC，目标是替代 CMS。","options":["A) G1 是串行垃圾回收器，只能单线程工作","B) G1 将堆划分为多个 Region，优先回收垃圾最多的 Region","C) G1 回收时会完全停止所有应用线程，无法控制停顿时间","D) G1 只能用于年轻代回收，老年代需要配合 CMS"],"hints":["G1 的设计目标是可预测的停顿时间和合理的吞吐量"],"tags":["JVM","GC"],"id":1827},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"ThreadLocal 的内存泄漏风险","content":"关于 ThreadLocal 可能导致内存泄漏的原因，以下说法正确的是？","answer":"D) ThreadLocalMap 的 key 是弱引用，value 是强引用，线程长时间存活时 value 可能无法回收。解析：ThreadLocalMap 的 Entry 继承 WeakReference，key（ThreadLocal 实例）是弱引用，value 是强引用。当 ThreadLocal 外部强引用被置 null 后，key 会被 GC 回收，但 value 仍然被 Entry 强引用，如果线程长期存活（如线程池中的线程），value 永远不会被回收，导致内存泄漏。","options":["A) ThreadLocal 内部使用强引用，导致 ThreadLocal 对象永远无法被回收","B) 内存泄漏是因为 ThreadLocal 没有实现 Serializable 接口","C) 每次调用 ThreadLocal.get() 都会创建新对象，导致堆内存溢出","D) ThreadLocalMap 的 key 是弱引用，value 是强引用，线程长时间存活时 value 可能无法回收"],"hints":["ThreadLocalMap 中的 Entry 如何引用 key 和 value？"],"tags":["ThreadLocal","内存管理"],"id":1828},{"category":"java_advanced","difficulty":"hard","type":"choice","title":"ForkJoinPool 的工作窃取算法","content":"关于 ForkJoinPool 的工作窃取（Work-Stealing）算法，以下说法正确的是？","answer":"A) 每个工作线程维护一个双端队列，空闲线程从其他线程队列尾部窃取任务。解析：ForkJoinPool 中每个工作线程都有自己的双端队列（Deque），线程正常工作时从队头取任务执行。当线程空闲时，会从其他线程的队列尾部「窃取」任务执行。窃取的是尾部任务，减少了与队列所有者（操作队头）的竞争，从而高效平衡负载。","options":["A) 每个工作线程维护一个双端队列，空闲线程从其他线程队列尾部窃取任务","B) 所有任务集中在一个全局队列中，空闲线程直接从全局队列取任务","C) 工作线程只处理自己提交的任务，不做跨线程的任务窃取","D) 空闲线程从其他线程队列的头部窃取任务，与队列所有者竞争同一端"],"hints":["工作窃取算法如何减少线程间的竞争？"],"tags":["并发","ForkJoinPool"],"id":1829},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"CompletableFuture 的异步方法","content":"关于 CompletableFuture 中 thenApply 和 thenApplyAsync 的区别，以下说法正确的是？","answer":"B) thenApply 默认在上一阶段线程中同步执行，thenApplyAsync 默认在 ForkJoinPool.commonPool() 中异步执行。解析：thenApply() 会在上一阶段 CompletionStage 执行的线程中同步执行（如果上一阶段已完成，则在当前线程执行），不会切换线程。thenApplyAsync() 无论上一阶段状态如何，都会提交到 ForkJoinPool.commonPool() 中异步执行。类似的区别也存在于 thenAccept/thenAcceptAsync、thenRun/thenRunAsync 等系列方法中。","options":["A) thenApply 和 thenApplyAsync 的行为完全相同，只是命名不同","B) thenApply 默认在上一阶段线程中同步执行，thenApplyAsync 默认在 ForkJoinPool.commonPool() 中异步执行","C) thenApply 可以处理异常，thenApplyAsync 不能","D) thenApplyAsync 只能用在 thenApply 之后"],"hints":["Async 结尾的方法和不带 Async 的方法在执行线程上有何不同？"],"tags":["并发","CompletableFuture"],"id":1830},{"category":"java_advanced","difficulty":"hard","type":"choice","title":"锁优化：偏向锁撤销","content":"关于 HotSpot VM 中偏向锁的撤销过程，以下说法正确的是？","answer":"C) 偏向锁撤销需要在全局安全点（SafePoint）暂停所有线程，检查持有锁的线程状态后决定是否撤销。解析：偏向锁撤销不是由持有偏向锁的线程自己完成的，而是由竞争线程触发，在全局安全点（所有线程暂停）执行。GC 发生时也会批量撤销偏向锁。JDK 15+ 默认禁用了偏向锁（-XX: -UseBiasedLocking），因为锁撤销的 SafePoint 开销在某些场景下影响了性能。","options":["A) 偏向锁撤销由持有偏向锁的线程在偏向另一个对象时自动完成，无需暂停","B) 偏向锁撤销只需要 CAS 替换 Mark Word，是轻量级操作","C) 偏向锁撤销需要在全局安全点（SafePoint）暂停所有线程，检查持有锁的线程状态后决定是否撤销","D) 偏向锁一旦获取就永远不会撤销"],"hints":["偏向锁撤销为什么需要在 SafePoint 暂停——因为需要检查持有锁的线程状态"],"tags":["JVM","锁优化","偏向锁","并发"],"id":1831},{"category":"java_advanced","difficulty":"hard","type":"choice","title":"ThreadLocal 内存泄漏","content":"关于 ThreadLocal 的内存泄漏问题，以下说法正确的是？","answer":"B) ThreadLocalMap 的 Entry 继承 WeakReference，Key 为弱引用，Value 为强引用，因此 Key 被 GC 回收后 Value 仍存在导致内存泄漏。解析：ThreadLocalMap 中 Entry 的 Key（ThreadLocal 实例）是弱引用（WeakReference），当 ThreadLocal 对象的外部强引用被置为 null 后，GC 会回收 Key。但 Entry 的 Value 是强引用，只要 Thread 仍然存活（在线程池中线程不会销毁），Value 就永远不会被回收。解决：每次使用完 ThreadLocal 后调用 remove() 清空 Entry。阿里 Java 规约也明确要求了这一点。","options":["A) ThreadLocal 不会有内存泄漏问题，因为 Java 的 GC 会自动回收所有不再使用的对象","B) ThreadLocalMap 的 Entry 继承 WeakReference，Key 为弱引用，Value 为强引用，因此 Key 被 GC 回收后 Value 仍存在导致内存泄漏","C) ThreadLocal 内存泄漏的根源是 ThreadLocalMap 的 Key 是强引用导致的","D) 使用 ThreadLocal 后不需要手动 remove，GC 会自动清理"],"hints":["弱引用 Key + 强引用 Value 的组合为什么会在线程池场景下产生内存泄漏"],"tags":["JVM","ThreadLocal","内存泄漏","并发"],"id":1832},{"category":"java_advanced","difficulty":"hard","type":"choice","title":"AQS 共享模式与独占模式","content":"关于 AQS（AbstractQueuedSynchronizer）的共享模式和独占模式，以下说法错误的是？","answer":"C) 共享模式获取同步状态失败时，线程进入 CLH 队列并阻塞，而独占模式会让线程自旋等待。解析：共享模式和独占模式在获取失败时都进入 CLH 队列并阻塞，区别在于同步状态释放时的传播行为：独占模式释放时只唤醒后继节点（head.next），共享模式释放时会唤醒后继节点并继续向后传播（因为可能有多个线程同时获得同步状态）。CountDownLatch 和 Semaphore 使用共享模式。ReentrantLock 使用独占模式。","options":["A) 共享模式释放同步状态时会唤醒后继节点并继续向后传播，独占模式只唤醒后继节点","B) ReentrantLock 使用独占模式，CountDownLatch 使用共享模式","C) 共享模式获取同步状态失败时，线程进入 CLH 队列并阻塞，而独占模式会让线程自旋等待","D) 共享模式和独占模式获取同步状态失败时都进入 CLH 队列等待"],"hints":["共享模式释放时「传播唤醒」的特性为什么适合信号量和闭锁"],"tags":["AQS","并发","JUC","锁"],"id":1833},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"CAS ABA 问题","content":"关于 CAS（Compare-And-Swap）操作的 ABA 问题，以下说法正确的是？","answer":"A) ABA 问题指变量从 A 变为 B 又变回 A，CAS 误认为没有变化。AtomicStampedReference 通过版本号解决。解析：ABA 场景：线程 1 读到值是 A，准备 CAS 更新。期间线程 2 将 A 改为 B 又改回 A。线程 1 的 CAS 比较发现还是 A 就认为没有变化，但实际上中间状态已经被改变了。AtomicStampedReference 内部维护 [reference, stamp] 配对，每次修改 stamp +1，CAS 同时比较 reference 和 stamp。AtomicMarkableReference 使用 boolean mark 表示是否被修改过。","options":["A) ABA 问题指变量从 A 变为 B 又变回 A，CAS 误认为没有变化。AtomicStampedReference 通过版本号解决","B) ABA 问题导致 CAS 一定会失败，需要使用 AtomicMarkableReference 修复","C) ABA 问题只发生在多核 CPU 上，单核 CPU 不会出现","D) ABA 问题无法解决，只能通过锁替代 CAS"],"hints":["ABA 问题的本质是 CAS 只检查值相等但不知道值是否被修改过——版本号提供了修改历史"],"tags":["CAS","并发","ABA","原子操作"],"id":1834},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"StampedLock 特性","content":"关于 StampedLock 的特性，以下说法错误的是？","answer":"D) StampedLock 支持重入（Reentrant），同一个线程可以多次获取同一把 StampedLock 锁。解析：StampedLock 不可重入！这是它与 ReentrantReadWriteLock 的关键区别之一。StampedLock 提供了三种模式：写锁（排他）、读锁（悲观，类似 ReadWriteLock 的读锁）、乐观读（不需要获取锁，直接读取，通过 stamp 校验有效性）。乐观读在读多写少的场景下性能最优——读取数据后检查 stamp 是否有效，如果期间没有写操作就避免了获取锁的开销。StampedLock 的锁获取方法返回一个 long stamp，解锁时传入 stamp。","options":["A) StampedLock 的乐观读模式在读多写少场景下性能优于 ReentrantReadWriteLock","B) StampedLock 获取锁时返回 stamp，解锁时需要用 stamp 验证","C) StampedLock 支持写锁、悲观读锁、乐观读三种模式","D) StampedLock 支持重入，同一个线程可以多次获取同一把 StampedLock 锁"],"hints":["StampedLock 的乐观读 + stamp 校验机制为什么在并发读取场景下比 ReadWriteLock 更快"],"tags":["并发","StampedLock","锁","JUC"],"id":1835},{"category":"java_advanced","difficulty":"medium","type":"choice","title":"MethodHandle 与 invokeExact","content":"关于 Java MethodHandle 的签名多态性（Signature Polymorphism），以下说法正确的是？","answer":"B) MethodHandle 的 invokeExact 方法要求参数类型和返回类型与目标方法严格匹配，不会自动进行类型转换。\n\n解析：MethodHandle 的 invoke 和 invokeExact 是签名多态方法——编译器根据实际调用时的参数类型和返回类型推导方法签名，生成 invokedynamic 指令（而非传统反射的反射调用）。invoke 允许自动类型转换（如 int → Integer 的自动装箱，子类 → 父类的类型宽化），invokeExact 则要求精确匹配——参数类型和返回类型必须与方法句柄的类型（MethodType）完全一致，否则抛出 WrongMethodTypeException。A 错误：JIT 可以对反射调用做内联优化。JDK 8+ 通过 Inflation 机制（反射调用阈值 15 次后切换到动态生成的字节码版本），再经过足够多的调用会被 JIT 内联。C 错误：invoke 和 invokeExact 的性能优势并非「始终优于」反射——首次调用 MethodHandle 的 invokedynamic 也需要引导（bootstrap），在简单场景下反射可能更快。D 错误：invokeExact 的 return 类型也需要精确匹配，不能随意赋值。\n\n扩展延伸：MethodHandle 比反射使用更复杂但更底层——可以通过 asType() 方法生成适配不同签名的 MethodHandle 变体。invokedynamic 的核心应用是 Lambda 表达式和 Java 17+ 的 switch 模式匹配。性能对比：MethodHandle 在复杂调用链场景下比反射快 10-30%，但简单场景差距不大。VarHandle（JDK 9+）替代 Unsafe 的原子操作，也基于 MethodHandle 实现。","options":["A) 反射调用方法时 JIT 编译器无法对目标方法做内联优化","B) MethodHandle 的 invokeExact 方法要求参数类型和返回类型与目标方法严格匹配，不会自动进行类型转换","C) MethodHandle 的 invoke 方法性能始终优于传统反射","D) invoke 和 invokeExact 的返回类型可以随意赋值，编译器会自动类型推断"],"hints":["invoke 和 invokeExact 在类型匹配上的区别","为什么 JIT 可以内联反射调用"],"tags":["Java","反射","MethodHandle","invokedynamic"],"id":1841},{"category":"java_advanced","difficulty":"medium","type":"choice","title":"注解处理与 AbstractProcessor","content":"关于 Java 注解（Annotation）处理机制，以下说法正确的是？","answer":"C) 通过 AbstractProcessor 在编译期处理注解时，生成的 Java 源文件会自动参与编译，无需额外的手动编译步骤。\n\n解析：AbstractProcessor 是 JSR 269 注解处理 API 的核心类。通过实现 process() 方法，可以生成新的 Java 源文件（通过 Filer.createSourceFile()）。这些生成的源文件会在当前编译轮次（round）结束后被 javac 自动编译，并参与后续处理轮次。A 错误：@Retention(RetentionPolicy.SOURCE) 的注解只在源码中保留，编译后丢弃，运行时反射无法获取。B 错误：@Target 限制注解使用位置，但违反 @Target 约束的代码会在编译期报错（不是运行时），抛出的不是 RuntimeException，而是编译错误。D 错误：@Repeatable 允许在同一位置重复使用注解，适用于类、方法、字段等任何合理位置，不限于方法和字段。需要定义一个容器注解来存储重复的注解。\n\n扩展延伸：注解生命周期三阶段——SOURCE：源码保留（APT 可在编译期处理）。CLASS：编译到 class 文件但运行时不可反射访问（如在字节码增强框架中使用）。RUNTIME：运行时可通过 getAnnotation() 反射获取（Spring 多数注解）。APT 的实际应用——Lombok（@Getter/@Setter/@Builder 生成代码）、Dagger（依赖注入代码生成）、MapStruct（实体转换代码生成）、Google Auto（自动生成 META-INF/services）。JDK 9+ 的重复注解使用容器注解（@Repeatable 容器容器 Annotation 的 value 方法返回重复注解数组）。","options":["A) @Retention(RetentionPolicy.SOURCE) 的注解在运行时可以通过 getAnnotation() 反射获取","B) @Target 限制注解使用位置，当注解使用在错误目标上时运行时抛出 IllegalAnnotationException","C) AbstractProcessor 在编译期处理注解时生成的 Java 源文件会自动参与当前编译，无需手动编译","D) @Repeatable 允许同一个注解在同一位置重复使用，但只适用于方法和字段"],"hints":["RetentionPolicy 的三个值分别代表什么阶段","APT 和运行时反射获取注解的能力有什么区别"],"tags":["Java","注解","APT","AbstractProcessor"],"id":1842},{"category":"java_advanced","difficulty":"hard","type":"choice","title":"JMM happens-before 规则","content":"以下关于 Java 内存模型（JMM）happens-before 规则的说法，正确的是？","answer":"D) 线程 A 中调用 thread.join() 成功返回后，被 join 线程中的所有操作 happens-before 线程 A 中 join() 返回之后的任何操作。\n\n解析：这是 JMM 中线程终止规则（Thread Termination Rule）的准确描述。当一个线程调用另一个线程的 join() 且成功返回时，被 join 线程中已执行的所有操作都建立 happens-before 关系于 join() 之后的代码，保证了被线程修改的共享变量对主线程可见。A 错误：volatile 规则的正确表述是「对 volatile 变量的写操作 happens-before 后续对同一 volatile 变量的读操作」，缺少「后续」限定词导致语义不精确——不是任意读都能看到写，必须是在同步顺序中排在写之后的读。B 错误：synchronized 规则是「对监视器锁的解锁（monitorexit）happens-before 后续对同一锁的加锁（monitorenter）」。B 的选项缺少「同一锁」这个关键限定。C 错误：final 字段的初始化保障需要满足「对象构造过程中不发生 this 引用逸出」（即对象引用不能在构造函数完成前被其他线程访问），否则 final 字段也可能看不见正确值。\n\n扩展延伸：JMM 的六条 happens-before 规则——程序次序规则、管程锁定规则、volatile 变量规则、线程启动规则（start() happens-before 被启动线程中的任何操作）、线程终止规则（join()）、线程中断规则和对象终结规则。happens-before 是偏序关系，具有传递性。常见的可见性保证手段：volatile、synchronized、final + 正确构造、Lock、Atomic 类、Thread.start()/join()。as-if-serial 语义保证单线程内不影响执行结果的重排序是允许的。","options":["A) 一个线程对 volatile 变量的写操作 happens-before 任意其他线程对该 volatile 变量的读操作","B) synchronized 块的释放（解锁）happens-before 后续任意线程进入任意 synchronized 块","C) 对 final 字段的写入 happens-before 构造函数返回，因此 final 字段在任何情况下对所有线程都立即可见","D) 线程 A 中调用 thread.join() 成功返回后，被 join 线程中的所有操作 happens-before 线程 A 中 join() 之后的代码"],"hints":["happens-before 规则中「后续」和「同一锁」这两个限定词为什么重要","this 引用逸出对 final 字段的可见性有什么影响"],"tags":["Java","JMM","happens-before","内存模型","并发"],"id":1843},{"category":"java_advanced","difficulty":"medium","type":"choice","title":"双亲委派模型的局限与 SPI","content":"关于 Java 双亲委派模型（Parent Delegation Model）和线程上下文类加载器，以下说法正确的是？","answer":"A) JDBC 驱动加载使用线程上下文类加载器（Thread Context ClassLoader）打破双亲委派模型，因为 DriverManager 在引导类加载器中注册，而具体驱动实现在应用类路径中。\n\n解析：双亲委派模型是类加载器在加载类时先委托父加载器的机制。核心目的：保证核心库的类型安全（如 java.lang.Object 总是同一个类）。局限：当由启动类加载器加载的核心类（如 DriverManager）需要加载由应用类加载器管理的类（如 MySQL JDBC 驱动）时，双亲委派无法逆向委托。解决方案是线程上下文类加载器（TCCL）——核心类通过 TCCL 获取当前线程的类加载器来加载应用类。B 错误：findClass 用于查找而非 loadClass。双亲委派是 loadClass 的逻辑——先委托父加载器，失败后调 findClass。自定义类加载器应重写 findClass 而非 loadClass（违背双亲委派时除外）。C 错误：ClassLoader.getResource() 和 getResources() 也是遵循双亲委派的（先委派父加载器搜索，找不到再自己搜）。D 错误：ThreadContextClassLoader 在 Java 9 模块系统（JPMS）下仍然存在和使用，没有被移除——SPI 加载（ServiceLoader）在 JDK 9+ 中虽然做了模块化改进，但 TCCL 机制仍然保留。\n\n扩展延伸：双亲委派被打破的三种场景——1）SPI 机制（JDBC/JCE/JNDI）通过 TCCL 加载实现。2）Tomcat 的 WebappClassLoader 先加载 Web 应用类再委托（隔离不同 Web 应用）。3）OSGi 模块化框架。Java 9 模块系统（JPMS）引入了模块层概念，ServiceLoader 在模块中可以直接通过 provides/uses 声明服务而不需要 TCCL，但 TCCL 机制向后兼容保留。自定义类加载器典型应用——热部署（每次加载新版本的 class）、加密 class 文件解密、字节码增强。","options":["A) JDBC 驱动加载使用线程上下文类加载器（Thread ContextClassLoader）打破双亲委派模型","B) 自定义类加载器应重写 loadClass 方法以遵循双亲委派模型","C) ClassLoader 的 getResource() 方法不遵循双亲委派模型，只搜索当前类加载器所在路径","D) 线程上下文类加载器是 Java 8 引入的机制，在 Java 9 模块系统下已不再需要"],"hints":["为什么引导类加载器加载的 DriverManager 需要访问应用类路径上的 JDBC 驱动","Tomcat 如何实现 Web 应用之间的类隔离"],"tags":["Java","类加载器","双亲委派","SPI","TCCL"],"id":1844},{"category":"java_advanced","difficulty":"hard","type":"choice","title":"Java 反射在框架中的核心应用","content":"以下关于 Java 反射在主流框架中应用的说法，错误的是？","answer":"C) Spring 通过反射调用 Bean 的 setter 方法注入依赖时，优先使用 setAccessible(true) 以调用 setter 方法，但如果 setter 不存在则会直接通过 Field.set() 注入。\n\n解析：Spring IoC 的依赖注入（@Autowired）优先使用字段直接注入（Field.set()）而非 setter 方法。当在字段上标注 @Autowired 时，Spring 通过反射直接设置字段值（Field.setAccessible(true) + Field.set()），不需要 setter 方法。只有在方法上标注 @Autowired 时才通过 Method.invoke() 调用 setter。C 的说法颠倒了主次顺序——Spring 既支持字段注入也支持 setter 注入，但字段注入是更常见的方式，且不依赖 setter 是否存在。A 正确：Jackson（或绝大多数 JSON 库）通过反射获取无参构造器创建实例，然后通过 setter/字段反射填充属性。如果类没有无参构造器会抛出异常（除非有特殊处理如 @JsonCreator）。B 正确：MyBatis 通过 JDK Proxy 动态代理 Mapper 接口，在 InvocationHandler.invoke() 中解析方法上的 @Select/@Insert 等注解，生成对应的 SQL 语句并执行。D 正确：Hibernate 通过反射处理实体类的 @Entity/@Table/@Column 等注解构建对象关系映射，通过反射获取字段值构造 SQL 参数以及从 ResultSet 反射填充实体属性。\n\n扩展延伸：反射在框架中的三大用途——1）类型分析：扫描类上的注解、方法签名、字段信息，用于配置映射（Spring/MyBatis/Hibernate）。2）动态调用：通过 Method.invoke() 动态执行方法（AOP 拦截后调用目标方法）。3）动态创建：Class.newInstance() 或 Constructor.newInstance() 创建对象实例（框架中的 Bean 创建）。JPA 规范要求实体类必须有无参构造器，原因正是 Hibernate 通过反射 Constructor.newInstance() 创建实例。Spring 的 CGLIB 代理生成子类时也需要通过反射调用父类构造器。","options":["A) Jackson 通过反射查找无参构造器来反序列化 JSON 为 Java 对象，因此无参构造器缺失会导致反序列化失败","B) MyBatis 通过 JDK 动态代理创建 Mapper 接口的代理对象，在代理中通过反射解析 @Select/@Insert 等注解生成 SQL","C) Spring 通过反射调用 Bean 的 setter 方法注入依赖，优先使用 setter，setter 不存在时再通过 Field.set() 注入","D) Hibernate 通过反射获取实体类上的 @Entity/@Table 注解构建 ORM 映射，并通过反射读写实体属性"],"hints":["Spring 的 @Autowired 标注在字段上和标注在 setter 方法上分别怎么注入","MyBatis Mapper 接口为什么不需要实现类"],"tags":["Java","反射","Spring","MyBatis","Hibernate"],"id":1845},{"category":"java_advanced","difficulty":"hard","type":"choice","title":"JVM 处理 OOM 的几种类型","content":"以下哪种情况会导致 java.lang.StackOverflowError 而非 OutOfMemoryError？","options":["A) 不断创建字符串放入常量池","B) 递归调用深度过大","C) CGLIB 动态生成大量代理类","D) 分配超大数组"],"answer":"B) 递归调用深度过大\n\n解析：StackOverflowError 在线程请求的栈深度超过 JVM 允许的最大值时抛出，典型场景是递归调用过深（没有正确终止条件）。A 选项导致堆 OOM（字符串常量池在堆中）。C 选项导致 Metaspace OOM（类元数据存储在元空间）。D 选项导致堆 OOM（超大数组直接在堆上分配）。\n\n扩展延伸：StackOverflowError 可以通过 -Xss 参数调大栈容量（如 -Xss2m）。每个递归调用创建一个栈帧（局部变量表 + 操作数栈 + 动态链接 + 方法出口）。栈帧过大（如局部变量多）也会减少可递归的深度。递归改迭代是根本解决方案。","hints":["StackOverflowError 和 OutOfMemoryError 分别对应哪个运行时数据区","-Xss 参数如何调整栈大小"],"tags":["JVM","OOM","错误"],"id":1851},{"category":"java_advanced","difficulty":"hard","type":"choice","title":"CMS 垃圾回收器的工作阶段","content":"以下哪个不是 CMS 垃圾回收器的工作阶段？","options":["A) 初始标记（Initial Mark）","B) 并发标记（Concurrent Mark）","C) 并发转移（Concurrent Move）","D) 并发清理（Concurrent Sweep）"],"answer":"C) 并发转移（Concurrent Move）\n\n解析：CMS 有 6 个阶段：初始标记（STW）→ 并发标记 → 并发预清理 → 重新标记（STW，Final Remark）→ 并发清理 → 并发重置。CMS 对存活对象的转移（移动）不是并发的——它只能并发清理，无法并发压缩，这导致 CMS 产生大量内存碎片。CMS 在无法分配新对象时触发 Full GC 进行 Serial Old 单线程压缩（STW 时间长）。\n\n扩展延伸：CMS 在 JDK 9 被标记为废弃（JEP 291），JDK 14 正式移除。替代方案：G1（默认）、ZGC（低延迟场景）。CMS 的并发模式失败（Concurrent Mode Failure）在 CMS 并发标记期间如果老年代被填满会触发。","hints":["CMS 没有并发转移能力，这是它产生内存碎片的根本原因","CMS 在 JDK 14 被正式移除"],"tags":["JVM","GC","CMS"],"id":1852},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"强软弱虚引用回收时机","content":"以下哪种引用类型的对象在内存充足时不会回收，但在内存不足（即将 OOM）时会被回收？","options":["A) 强引用（Strong Reference）","B) 软引用（Soft Reference）","C) 弱引用（Weak Reference）","D) 虚引用（Phantom Reference）"],"answer":"B) 软引用（Soft Reference）\n\n解析：软引用在内存充足时不会被回收，只有在内存不足（即将抛出 OOM）时才会被 GC 回收。弱引用（WeakReference）只要 GC 发生就会被回收（不管内存是否充足）。强引用永远不会被 GC 回收（除非引用被置 null）。虚引用（PhantomReference）的 get() 始终返回 null，主要用于跟踪对象被回收的时刻（通过 ReferenceQueue）。软引用适合做内存敏感缓存（如图片缓存）。\n\n扩展延伸：JDK 默认的 SoftReference 在最近一次 GC 后如果对象存活超过 -XX:SoftRefLRUPolicyMSPerMB（默认 1000ms）也会被回收。这意味着软引用实际上不一定是「内存不足才回收」——如果 JVM 认为堆增长太多，也可能提前回收。","hints":["软引用非常适合做内存敏感型缓存","SoftRefLRUPolicyMSPerMB 参数控制软引用在多长时间内不被回收"],"tags":["JVM","引用","GC"],"id":1853},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"Java 8 接口默认方法的冲突解决规则","content":"当一个类继承了父类并实现了接口，父类和接口有相同签名的方法时，以下哪个描述正确？","options":["A) 接口方法优先于父类方法","B) 父类方法优先于接口默认方法","C) 编译报错，必须重写","D) 运行时选择实际类型的方法"],"answer":"B) 父类方法优先于接口默认方法\n\n解析：Java 的类优先原则（Class Wins）：当一个类从父类继承的方法与接口的默认方法冲突时，父类的方法优先，接口的默认方法被忽略。这个规则确保接口的默认方法不会破坏已有的类继承体系。如果两个接口有相同签名的默认方法，实现类必须重写该方法。\n\n扩展延伸：JDK 8 引入默认方法是为了集合库的演化（在不破坏现有实现的前提下为 Collection 添加 stream()、forEach() 等）。接口也可以有静态方法（utility 方法，如 Comparator.comparing）。JDK 9 增加了接口私有方法，用于在接口内共享公共代码。","hints":["类优先于接口的设计原因是什么（向后兼容性）","两个接口冲突时需要手动解决"],"tags":["Java 8","接口","默认方法"],"id":1854},{"category":"java_advanced","difficulty":"medium","type":"choice","title":"try-with-resources 异常抑制机制","content":"当 try-with-resources 块中 try 块抛出了异常且 close() 也抛出异常时，以下哪个描述正确？","options":["A) try 块异常被忽略，close() 异常被抛出","B) close() 异常被抑制（Suppressed），try 块异常被抛出","C) 两个异常都被抛出，造成 JVM 崩溃","D) 不会抛出任何异常"],"answer":"B) close() 异常被抑制（Suppressed），try 块异常被抛出\n\n解析：try-with-resources 会记住 try 块抛出的异常作为主异常，close() 抛出的异常作为被抑制的异常（Suppressed Exception）附加到主异常上。通过主异常的 getSuppressed() 方法可以获取被抑制的异常数组。这与传统 try-finally 的行为相反——传统 try-finally 中 finally 的异常会覆盖 try 的异常（导致原始异常丢失）。\n\n扩展延伸：Throwable.addSuppressed() 和 getSuppressed() 是 JDK 7 为 try-with-resources 添加的方法。如果 try 块正常执行而 close() 抛出异常，close() 异常会直接抛出（没有主异常需要抑制）。try-with-resources 编译后展开为 try-catch-finally 结构，其中 catch 块处理 try 的异常并记录，finally 调 close() 时如果抛出异常则通过 addSuppressed 添加到记录的主异常上。","hints":["try-with-resources 的异常处理是 try 块异常优先","传统 try-finally 的异常行为相反（finally 异常覆盖 try 异常）"],"tags":["Java","异常","try-with-resources"],"id":1855},{"category":"java_advanced","difficulty":"hard","type":"choice","title":"ZGC 的核心特点","content":"关于 ZGC 的特点，以下哪个描述是错误的？","options":["A) ZGC 使用染色指针（Colored Pointers）在指针中编码状态","B) ZGC 通过读屏障（Load Barrier）实现并发标记和并发重定位","C) ZGC 的停顿时间会随着堆大小增加而线性增长","D) ZGC 在 JDK 11 以实验性功能引入，JDK 15 正式发布"],"answer":"C) ZGC 的停顿时间会随着堆大小增加而线性增长\n\n解析：ZGC 的核心卖点是停顿时间与堆大小无关（无论 1GB 还是 1TB，停顿时间都在 10ms 以下），这是它区别于 G1 和 CMS 的根本优势。A 正确——染色指针在 64 位指针的高 4 位编码 Marked0/Marked1/Remapped/Finalizable 等状态。B 正确——读屏障在对象引用加载时执行检查，是实现并发标记和并发重定位自愈机制的关键。D 正确——ZGC 在 JDK 11 作为实验特性发布（JEP 333），JDK 15 转为正式特性（JEP 377）。\n\n扩展延伸：ZGC 的停顿时间主要来自初始标记（Mark Start）和最终标记（Mark End）的根扫描，这部分时间与 GC Roots 数量有关，与堆大小无关。而并发标记阶段的线程是和应用线程并行运行的，不产生停顿。","hints":["ZGC 的设计目标就是极低且可预测的停顿时间","ZGC 的停顿时间不受堆大小影响"],"tags":["JVM","ZGC","GC","低延迟"],"id":1856},{"category":"java_advanced","difficulty":"hard","type":"choice","title":"虚拟线程与平台线程的区别","content":"以下关于虚拟线程（Virtual Threads）和平台线程（Platform Threads）的说法，正确的是？","options":["A) 虚拟线程由操作系统调度，平台线程由 JVM 调度","B) 虚拟线程在 synchronized 块中阻塞时不会被 pinned","C) 虚拟线程适合 CPU 密集型任务，平台线程适合 IO 密集型任务","D) 虚拟线程使用 Continuation 实现上下文保存和恢复"],"answer":"D) 虚拟线程使用 Continuation 实现上下文保存和恢复\n\n解析：A 错误——虚拟线程由 JVM 调度（用户态线程），平台线程由操作系统调度（内核线程）。B 错误——虚拟线程在 synchronized 块中阻塞时会被 pinned（固定在载体线程上），因为 synchronized 在 JVM 层面使用了 MonitorEnter/MonitorExit 字节码，与载体的平台线程深度绑定。C 错误——虚拟线程适合 IO 密集型任务（创建和切换开销低），对于 CPU 密集型任务，虚拟线程没有优势（CPU 计算本身是绑定的），平台线程反而更直接。D 正确——虚拟线程的核心机制是 Continuation（可暂停/恢复的执行上下文），通过 Yield 操作实现虚拟线程的挂起和恢复。\n\n扩展延伸：虚拟线程的 pinned 场景还包括执行 native 方法或调用 JNI 时。避免 pinned 的方法是使用 ReentrantLock 替代 synchronized。JDK 21 正式发布虚拟线程（JEP 444），同时也引入了 StructuredTaskScope 实现结构化并发。","hints":["虚拟线程是用户态线程，由 JVM 调度而非 OS","synchronized 块中的阻塞会导致虚拟线程 pinned"],"tags":["JVM","虚拟线程","Loom","并发"],"id":1857},{"category":"java_advanced","difficulty":"hard","type":"choice","title":"结构化并发（Structured Concurrency）","content":"关于 JDK 21 引入的结构化并发（StructuredTaskScope），以下哪个描述是错误的？","options":["A) 结构化并发将并发任务的生命周期绑定到代码块的词法作用域","B) StructuredTaskScope.shutdownOnSuccess() 在任一子任务成功时关闭所有其他子任务","C) 结构化并发中，子任务抛出的异常会自动传播到父作用域","D) 结构化并发只适用于虚拟线程，不适用于平台线程"],"answer":"D) 结构化并发只适用于虚拟线程，不适用于平台线程\n\n解析：结构化并发（JEP 428，JDK 21 预览，JDK 22 第二次预览）是一种编程范式，将并发任务的生命周期与代码块的作用域绑定。核心类 StructuredTaskScope 适用于任意线程（包括平台线程和虚拟线程），不限于虚拟线程。A 正确——新的 StructuredTaskScope 会在所有子任务完成（或 scope 关闭）后才返回，确保没有任务泄漏（Task Leak）。B 正确——shutdownOnSuccess() 在任一子任务成功时关闭 scope，取消其他未完成的子任务，典型的\"抢答模式\"（如多个微服务副本之间的重试）。C 正确——子任务的异常会被统一处理，结构化并发提供了更好的错误传播和控制。\n\n扩展延伸：使用 StructuredTaskScope 的模式——try (var scope = new StructuredTaskScope.ShutdownOnFailure()) { Future<Integer> f1 = scope.fork(() -> fetchFromA()); Future<String> f2 = scope.fork(() -> fetchFromB()); scope.join(); scope.throwIfFailed(); return combine(f1.resultNow(), f2.resultNow()); }——scope 关闭等待所有子任务完成，没有泄漏风险。","hints":["结构化并发解决的是任务泄漏（子任务生命周期超过父作用域）问题","StructuredTaskScope 的 fork-join 模式类似结构化编程中的 try-with-resources"],"tags":["JVM","结构化并发","Loom","并发"],"id":1858},{"category":"java_advanced","difficulty":"hard","type":"choice","title":"Scoped Values 的作用","content":"关于 JDK 21 正式发布的 Scoped Values（JEP 446），以下说法正确的是？","options":["A) ScopedValues 可以修改值，而且修改后对所有线程可见","B) ScopedValues 是 ThreadLocal 的替代方案，设计为不可变且更安全","C) ScopedValues 只能在虚拟线程中使用","D) ScopedValues 的值在线程间自动共享，不需要显式传递"],"answer":"B) ScopedValues 是 ThreadLocal 的替代方案，设计为不可变且更安全\n\n解析：Scoped Values 是 ThreadLocal 的替代方案——1）不可变性（Immutable）：值一旦绑定，在作用域内不可修改（不像 ThreadLocal 可以随时 set/get，容易产生混乱）。2）确定性：值通过调用栈向下传播，子线程自动继承父线程的 Scoped Values（相比 ThreadLocal 的子线程继承行为更明确）。3）轻量级：设计上比 ThreadLocal 更轻量，特别适合虚拟线程场景（大量线程时 ThreadLocal 的内存开销和与管理问题）。A 错误——Scoped Values 不可修改（Immutable），不能在绑定后改变值。C 错误——Scoped Values 同样适用于平台线程（不限于虚拟线程）。D 错误——值需要显式创建和绑定作用域（通过 ScopedValue.where(key, value).run(() -> {...})），在线程间通过调用栈传播。\n\n扩展延伸：使用方式——public static final ScopedValue<User> LOGGED_IN_USER = ScopedValue.newInstance(); ScopedValue.where(LOGGED_IN_USER, user).run(() -> handleRequest()); ——在 run 方法内部及其调用的所有方法中都可以通过 LOGGED_IN_USER.get() 获取用户信息。与传统 ThreadLocal 相比，ScopedValue 不存储可修改的状态，每次绑定创建一个新的作用域，避免了 ThreadLocal 常见的值意外泄漏和忘记清理的问题。","hints":["ScopedValues 是不可变的，通过调用栈传播","ScopedValues 解决了 ThreadLocal 在虚拟线程场景下的问题"],"tags":["JVM","ScopedValues","ThreadLocal","Loom"],"id":1859},{"category":"java_advanced","difficulty":"medium","type":"choice","title":"jlink 和 jdeps 的用途","content":"以下关于 JDK 工具 jlink 和 jdeps 的说法，正确的是？","options":["A) jdeps 用于创建自定义 Java 运行时镜像，jlink 用于分析类文件的依赖","B) jlink 用于创建自定义 Java 运行时镜像，jdeps 用于分析类文件的依赖","C) jlink 和 jdeps 都用于性能分析，只是角度不同","D) jlink 用于生成 JVM 堆转储，jdeps 用于线程转储"],"answer":"B) jlink 用于创建自定义 Java 运行时镜像，jdeps 用于分析类文件的依赖\n\n解析：jlink（JEP 282，JDK 9 引入）——将模块和其依赖打包成自定义运行时镜像，只包含应用需要的模块。常用于 Docker 镜像瘦身（将 300MB+ 的 JDK 裁剪到 40MB 左右）。用法：jlink --module-path $JAVA_HOME/jmods:target --add-modules my.module --output custom-runtime。jdeps（JDK 8 引入）——分析 .class 文件和 JAR 包的依赖关系。可以找出类级别的依赖、模块依赖、以及 JDK 内部 API 的引用（对排查 IllegalAccessError 有帮助）。用法：jdeps -summary -recursive myapp.jar。\n\n扩展延伸：jlink 的输出是一个独立的目录结构，包含 bin/conf/lib 等子目录，可以直接运行（./custom-runtime/bin/java --module my.module/MyMain）。结合 jdeps 可以先分析应用的模块依赖，再用 jlink 裁剪最小运行时。jlink 还支持 --compress 和 --strip-debug 等选项进一步优化体积。注意：使用 jlink 要求应用及其依赖全部模块化（module-info.java）。非模块化应用可以考虑 jdeps 的 --generate-module-info 选项生成模块描述符。","hints":["jlink 用于构建最小运行时镜像（裁剪 JDK）","jdeps 用于依赖分析（找出模块依赖和内部 API 使用）"],"tags":["JVM","JLink","jdeps","模块化"],"id":1860},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"虚拟线程的线程模型与调度方式","content":"关于 Java 虚拟线程的线程模型和调度方式，以下描述正确的是？","answer":"C) 虚拟线程采用 M:N 调度模型，JVM 管理多个虚拟线程映射到少量平台线程，阻塞时自动卸载。解析：虚拟线程使用 M:N 调度（M 个虚拟线程映射到 N 个平台线程）。JVM 内置的 carrier thread scheduler（基于 ForkJoinPool）负责调度。当虚拟线程执行阻塞 I/O、锁等待或 Thread.sleep() 时，JVM 自动执行 unmount 操作释放载体线程。虚拟线程创建成本极低（微秒级），可创建百万级实例。注意虚拟线程不适用于 CPU 密集型任务——计算密集型操作不会触发 unmount，无法利用轻量级优势。","options":["A) 虚拟线程一对一映射到内核线程，由 OS 完全调度","B) 虚拟线程使用 1:1 调度模型，每个虚拟线程独占一个平台线程","C) 虚拟线程采用 M:N 调度模型，JVM 管理多个虚拟线程映射到少量平台线程，阻塞时自动卸载","D) 虚拟线程共享一个全局线程池，所有虚拟线程排队执行"],"hints":["对比传统平台线程的 1:1 模型和虚拟线程的 M:N 模型","虚拟线程在什么情况下会 pin 住载体线程无法卸载"],"tags":["虚拟线程","Project Loom","线程模型","调度","Java 21"],"id":1875},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"StructuredTaskScope 的关闭策略","content":"关于 StructuredTaskScope 的 ShutdownOnFailure 和 ShutdownOnSuccess 两种内置策略，以下说法正确的是？","answer":"A) ShutdownOnSuccess 在任意子任务成功时立即关闭 scope，其他未完成任务被取消。解析：ShutdownOnSuccess 在第一个子任务成功返回结果时立即调用 shutdown()，取消 scope 内所有尚未完成的子任务。主线程调用 result() 获取成功子任务的返回值。ShutdownOnFailure 则相反——任意子任务失败时关闭 scope，取消其他未完成任务，主线程抛出异常。两者都保证了不会出现任务泄漏。自定义策略可以实现 Spi 接口定义自己的关闭逻辑。注意结构化并发在 JDK 21 中为预览特性，JDK 23 为第三次预览。","options":["A) ShutdownOnSuccess 在任意子任务成功时立即关闭 scope，其他未完成任务被取消","B) ShutdownOnFailure 在所有子任务完成后才决定是否关闭 scope","C) 两种策略的 scope 在 try 块结束后仍可继续提交新任务","D) ShutdownOnSuccess 的结果必须在所有子任务完成后才能获取"],"hints":["ShutdownOnSuccess 是取第一个成功结果，ShutdownOnFailure 是第一个失败就取消全部","StructuredTaskScope 实现了 AutoCloseable，必须使用 try-with-resources"],"tags":["结构化并发","StructuredTaskScope","Project Loom","Java 21"],"id":1876},{"category":"java_advanced","difficulty":"hard","type":"choice","title":"FFM API Arena 的内存释放机制","content":"关于 FFM API 中 Arena 的内存释放时机，以下说法错误的是？","answer":"B) Arena.ofConfined() 创建的 Arena 可以在多个线程之间共享访问。解析：Arena.ofConfined() 创建的 Arena 只能由创建它的线程访问和使用，其他线程尝试访问会抛异常。Arena 有三种类型：1）ofAuto()——内存由 GC 自动回收（当 Arena 不可达时）；2）ofConfined()——线程限制，仅创建线程可访问，close() 时显式释放；3）ofShared()——多线程共享，所有线程可访问，最后一个 close() 调用者负责释放。Arena 都实现了 AutoCloseable，推荐使用 try-with-resources 确保及时释放堆外内存。Arena 释放时，其分配的所有 MemorySegment 变为无效状态，再次访问抛出 IllegalStateException。","options":["A) Arena.ofAuto() 分配的内存在没有引用时由 GC 自动释放","B) Arena.ofConfined() 创建的 Arena 可以在多个线程之间共享访问","C) Arena.ofShared() 支持多个线程同时访问和释放内存","D) Arena 实现了 AutoCloseable，推荐用 try-with-resources 管理生命周期"],"hints":["ofConfined 和 ofShared 的线程访问限制不同","ofShared 的释放由最后一个 close() 调用者负责"],"tags":["FFM API","Arena","内存管理","Project Panama","Java 22"],"id":1877},{"category":"java_advanced","difficulty":"hard","type":"choice","title":"Project Valhalla 值类型与对象标识","content":"关于 Project Valhalla 的值类型（Value Types）和内联类（Inline Classes），以下说法正确的是？","answer":"C) 内联类没有对象标识（identity），因此不能用作锁对象，也不能用 == 做引用比较。解析：内联类（JDK 未来特性，@__inline）的核心特征是无标识（identity-less）。这意味着：1）实例没有对象头（mark word + klass pointer），内存占用更低；2）不能作为 synchronized 的锁对象（因为没有 monitor）；3）== 比较的是值而非引用地址；4）数组可扁平化存储，减少指针间接访问开销。值类型是不可变的，所有字段隐式为 final。内联类不能继承其他类，也不能被继承。因为缺少标识，null 引用语义也不同——内联类默认值为零值（zero-initialized），而非 null。","options":["A) 内联类与普通类的内存布局完全相同","B) 内联类可以作为 synchronized 同步语句的锁对象","C) 内联类没有对象标识，因此不能用作锁对象，也不能用 == 做引用比较","D) 内联类的 == 和 equals() 始终返回相同结果"],"hints":["对象标识（identity）是每个 Java 对象独立性的基础，内联类去除了这个属性","零值（zero value）和 null 的区别是理解内联类的关键"],"tags":["Project Valhalla","值类型","内联类","JVM","对象标识"],"id":1878},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"Stream Gatherers 自定义中间操作","content":"关于 JDK 22 预览的 Stream Gatherers 特性，以下说法正确的是？","answer":"D) Gatherer 接口包含 initializer、integrator、combiner 和 finisher 四个组件，用于构建自定义中间操作。解析：Stream Gatherers（JDK 22 预览）通过 Gatherer 接口支持自定义中间操作。四个组件：1）initializer——提供可变状态容器；2）integrator——处理每个元素，可选地将元素 publish 到下游；3）combiner——并行时合并两个状态容器；4）finisher——在所有元素处理完后做最终转换。内置的 Gatherers 工具类提供 windowFixed（定长窗口）、fold（折叠）、scan（扫描，产生中间结果）、mapConcurrent（并发映射）等。windowFixed(3) 可将流 `[1,2,3,4,5,6]` 转换为 `[[1,2,3],[4,5,6]]`。","options":["A) Stream Gatherers 只能用作终结操作（terminal operation）","B) Gatherer 接口只需要实现 integrator 一个方法即可","C) Stream Gatherers 不支持并行流操作","D) Gatherer 接口包含 initializer、integrator、combiner 和 finisher 四个组件"],"hints":["Gatherer 的 combiner 组件是支持并行化的关键","Gatherers.windowFixed 和 Gatherers.scan 是内置收集器的代表"],"tags":["Stream API","Gatherers","Java 22","函数式编程","并行"],"id":1879},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"虚拟线程 carrier 线程复用机制","content":"关于虚拟线程的 carrier 线程（载体线程）复用机制，以下描述正确的是？","answer":"B) 虚拟线程在阻塞 I/O 时从 carrier 卸载，carrier 被归还给 ForkJoinPool 供其他虚拟线程复用。解析：虚拟线程的 carrier 线程是 ForkJoinPool 中的平台线程，默认数量等于 CPU 核心数。当虚拟线程遇到阻塞 I/O（如 socket.read、锁等待）时，JVM 自动执行 unmount 操作，将虚拟线程的栈帧内容保存到堆上，carrier 线程被释放回 ForkJoinPool 供其他虚拟线程调度。阻塞操作完成后，虚拟线程被重新 mount 到某个可用的 carrier 线程继续执行。注意 synchronized 块和 native 方法不会触发卸载，会导致 carrier 被 Pin 住无法复用。","options":["A) 每个虚拟线程创建时分配一个固定的 carrier 线程，虚拟线程生命周期内 carrier 不变","B) 虚拟线程在阻塞 I/O 时从 carrier 卸载，carrier 被归还给 ForkJoinPool 供其他虚拟线程复用","C) 虚拟线程的 carrier 线程数量等于 CPU 核心数乘以 2，且运行时不可调整","D) 虚拟线程结束后其 carrier 线程也被销毁并归还给 OS"],"hints":["carrier 线程由 ForkJoinPool 管理，思考虚拟线程阻塞时 carrier 的去向","思考哪些操作会导致 carrier 被 Pin 住无法卸载"],"tags":["virtual-thread","carrier-thread","ForkJoinPool","mount-unmount","Java 21"],"id":1880},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"StructuredTaskScope 异常传播策略","content":"关于 StructuredTaskScope 的 ShutdownOnFailure 和 ShutdownOnSuccess 两种内置策略，以下说法正确的是？","answer":"A) ShutdownOnFailure 在任意子任务失败时立即关闭 scope 并取消其余子任务；ShutdownOnSuccess 在任意子任务成功时立即关闭 scope 并取消其余子任务。解析：ShutdownOnFailure 策略在任意子任务抛出异常时立即调用 shutdown()，取消所有尚未完成的子任务。主线程在 join() 后调用 throwIfFailed() 重新抛出第一个异常。适用于必须在所有子任务都成功才能继续的场景。ShutdownOnSuccess 策略则在第一个子任务成功返回时立即关闭 scope，主线程通过 result() 获取第一个成功结果。适用于多数据源并行查询取最快结果的场景。两种策略都使用 try-with-resources 确保 scope 正确关闭，不会遗留未完成的任务。","options":["A) ShutdownOnFailure 在任意子任务失败时立即关闭 scope 并取消其余子任务；ShutdownOnSuccess 在任意子任务成功时立即关闭 scope 并取消其余子任务","B) ShutdownOnFailure 和 ShutdownOnSuccess 都等待所有子任务完成后统一处理结果","C) ShutdownOnFailure 只捕获第一个子任务的异常并忽略后续子任务的异常","D) ShutdownOnSuccess 需要等待所有子任务完成才能通过 result() 获取结果"],"hints":["两种策略名字已经暗示了触发关闭的条件——Failure 或 Success","思考「全有或全无」和「谁先完成用谁」分别对应哪种策略"],"tags":["structured-concurrency","StructuredTaskScope","ShutdownOnFailure","ShutdownOnSuccess","Java 21"],"id":1881},{"category":"java_advanced","difficulty":"hard","type":"choice","title":"FFM API Arena 作用域管理","content":"关于 FFM API 中 Arena 的作用域管理和内存释放机制，以下说法正确的是？","answer":"B) Arena 使用 try-with-resources 自动释放所有分配的内存段，无需手动释放每个 MemorySegment。解析：Arena 实现了 AutoCloseable 和 SegmentAllocator 接口。使用 try-with-resources 包围时，try 块结束时自动调用 arena.close()，所有由此 Arena 分配的 MemorySegment 都被释放（变为无效状态）。JVM 有三种 Arena：Arena.ofAuto()（GC 自动回收）、Arena.ofConfined()（线程限制，显式关闭）、Arena.ofShared()（多线程共享，显式关闭）。ofConfined 只能由创建线程访问，性能最高。ofShared 多线程可同时访问，但关闭时由最后一个 close() 调用者负责。注意：释放后继续访问对应 MemorySegment 会抛出 IllegalStateException。","options":["A) Arena 使用引用计数管理内存，引用归零时由 GC 自动释放","B) Arena 使用 try-with-resources 自动释放所有分配的内存段，无需手动释放每个 MemorySegment","C) Arena 分为 confined 和 shared 两种，其中 shared arena 的访问性能比 confined 更高","D) Arena 分配的内存必须为每个 MemorySegment 单独调用 close() 释放"],"hints":["Arena 实现了 AutoCloseable，思考 try-with-resources 如何工作","ofConfined 和 ofShared 在线程访问限制上的差异"],"tags":["FFM API","Arena","MemorySegment","memory-management","panama"],"id":1882},{"category":"java_advanced","difficulty":"hard","type":"choice","title":"Valhalla 值类型 JIT 优化原理","content":"关于 Project Valhalla 的值类型（Value Types）和内联类（Inline Classes）在 JIT 编译中的优化，以下说法正确的是？","answer":"A) 值类型可以将对象内联展开到栈帧或父对象中，消除堆分配和指针间接访问。解析：值类型（内联类，@__inline）的核心特征是无对象标识（identity-less）。JIT 编译器因此可以将值类型的实例内联展开（scalar replacement / flattening），直接存储在栈帧的局部变量槽中或嵌入到父对象的字段中，无需堆分配和通过指针访问。这意味着：1）内存局部性更好，减少缓存未命中；2）减少 GC 压力（堆上对象更少）；3）数组可扁平化存储（连续排列值而非引用数组）。但值类型不可变，所有字段隐式 final，不能继承或被继承。没有 null 引用语义——默认值为零值。注意 synchronized 不适用于值类型。","options":["A) 值类型可以将对象内联展开到栈帧或父对象中，消除堆分配和指针间接访问","B) 值类型在 JIT 编译后与普通引用类型的性能完全一致，无额外优化","C) JIT 对值类型的优化仅限于字符串常量池内联，不涉及标量替换","D) 值类型必须通过引用访问，无法实现标量化替换（scalar replacement）"],"hints":["值类型没有对象标识，这是 JIT 做内联展开的前提条件","标量替换（Scalar Replacement）是 JIT 将对象拆解为字段的关键技术"],"tags":["Valhalla","value-types","inline-class","JIT","scalar-replacement"],"id":1883},{"category":"java_advanced","difficulty":"easy","type":"choice","title":"Stream Gatherers 自定义实现","content":"关于 JDK 22 预览的 Stream Gatherers 特性，以下说法正确的是？","answer":"C) Gatherer 接口的 integrator() 是核心方法，处理每个元素并通过 Downstream.push() 决定是否向下游发射。解析：Stream Gatherers 通过 Gatherer 接口支持自定义中间操作。Gatherer 包含四个组件：initializer（初始化可变状态）、integrator（处理每个元素，调用 downstream.push() 发射结果）、combiner（并行时合并状态）、finisher（处理完成后做最终转换）。其中 integrator 是唯一必须实现的方法，其余有默认实现。integrator 返回 boolean 值——返回 false 表示不再接受更多元素（提前终止）。内置 Gatherers 工具类提供 windowFixed（定长窗口）、fold（折叠）、scan（扫描产生中间结果）、mapConcurrent（并发映射）等。注意 Gatherer 支持并行流——通过 combiner 实现任务拆分和结果合并。","options":["A) Gatherer 接口必须实现 initializer、integrator、combiner 和 finisher 全部四个方法","B) Stream Gatherers 只能处理有限流，对无限流直接抛出异常","C) Gatherer 接口的 integrator() 是核心方法，处理每个元素并通过 Downstream.push() 决定是否向下游发射","D) Gatherer 的 finisher 只能做清理操作，无法向下游发射最终元素"],"hints":["integrator 是唯一必须实现的方法，其他组件有默认实现","Downstream.push() 的调用时机决定了下游能否收到该元素"],"tags":["Stream API","Gatherers","gatherer","Java 22","integrator"],"id":1884},{"category":"java_advanced","difficulty":"easy","type":"multiple_choice","title":"线程池的拒绝策略","content":"ThreadPoolExecutor 内置了哪些拒绝策略？","answer":"A)、B)、C)、D)。解析：ThreadPoolExecutor 内置了 4 种拒绝策略：AbortPolicy（默认，抛 RejectedExecutionException）、CallerRunsPolicy（调用者线程直接执行任务，降低提交速度）、DiscardPolicy（静默丢弃）、DiscardOldestPolicy（丢弃队列中最老的任务后重试提交）。实际开发中还可以自定义 RejectedExecutionHandler 实现更复杂的降级策略，如写入 MQ 或数据库。","options":["A) AbortPolicy","B) CallerRunsPolicy","C) DiscardPolicy","D) DiscardOldestPolicy"],"hints":["线程池的拒绝策略都实现了 RejectedExecutionHandler 接口"],"tags":["并发","线程池"],"id":2288},{"category":"java_advanced","difficulty":"hard","type":"multiple_choice","title":"synchronized 锁升级过程","content":"关于 JDK 6 引入的 synchronized 锁升级机制，以下说法哪些是正确的？","answer":"A)、C)、D)。解析：JDK 6 优化了 synchronized 的锁机制，引入锁升级（膨胀）过程：无锁 → 偏向锁（只有一个线程访问）→ 轻量级锁（少量竞争，CAS 自旋）→ 重量级锁（大量竞争，阻塞）。偏向锁在 JDK 15 中默认关闭，JDK 21 中被移除。轻量级锁通过 CAS 自旋尝试获取锁，避免线程阻塞带来的上下文切换开销。重量级锁依赖操作系统互斥量实现，线程阻塞和唤醒开销最大。","options":["A) 锁升级的顺序是：偏向锁 → 轻量级锁 → 重量级锁","B) 偏向锁永久有效，不会撤销","C) 轻量级锁通过 CAS 自旋获取锁","D) 重量级锁会导致线程阻塞和上下文切换"],"hints":["锁升级是为了减少不必要的同步开销","不同锁的适用场景不同"],"tags":["并发","synchronized"],"id":2289},{"category":"java_advanced","difficulty":"easy","type":"multiple_choice","title":"JVM 运行时数据区域","content":"以下哪些属于 JVM 运行时数据区（Runtime Data Areas）？","answer":"A)、B)、D)。解析：JVM 运行时数据区包括：程序计数器（PC Register，线程私有，记录当前线程执行的字节码地址）、虚拟机栈（Java Stack，线程私有，存储栈帧）、本地方法栈（Native Method Stack，线程私有，支持 native 方法）、堆（Heap，所有线程共享，存储对象实例）、方法区（Method Area，JDK 8 后由 Metaspace 实现）。直接内存（Direct Memory）是 NIO 在堆外分配的内存，不属于 JVM 规范定义的运行时数据区。","options":["A) 程序计数器","B) Java 虚拟机栈","C) 直接内存","D) 方法区"],"hints":["直接内存由 NIO 管理，不在 JVM 运行时数据区规范中"],"tags":["JVM","内存管理"],"id":2290},{"category":"java_advanced","difficulty":"easy","type":"multiple_choice","title":"可作为 GC Roots 的对象","content":"以下哪些对象可以作为 GC Roots？","answer":"A)、B)、C)。解析：可作为 GC Roots 的对象包括：虚拟机栈中引用的对象（本地变量表中的引用）、方法区中静态属性引用的对象、方法区中常量池引用的对象、本地方法栈中 JNI 引用的对象（全局 JNI 引用）、活跃线程（Thread 对象）。通过 GC Roots 可达性分析，从这些根对象出发，无法到达的对象即为可回收对象。未被引用的字符串常量可能已被判定为无用常量，不能作为 GC Root。","options":["A) 虚拟机栈中引用的对象","B) 方法区中静态属性引用的对象","C) 本地方法栈中 JNI 引用的对象","D) 字符串常量池中未被引用的常量"],"hints":["GC Roots 是活跃的引用起点"],"tags":["JVM","GC"],"id":2291},{"category":"java_advanced","difficulty":"hard","type":"multiple_choice","title":"Java 8 Stream 的特性","content":"以下关于 Java 8 Stream 的描述，哪些是正确的？","answer":"A)、B)、D)。解析：Stream 本身不存储数据，而是对数据源（集合、数组等）的视图描述；Stream 操作是惰性求值的，中间操作（如 filter、map）不会立即执行，遇到终止操作（如 collect、forEach）才触发实际计算；Stream 的一次性体现在一旦执行了终止操作，该 Stream 就被消费了，不能再次使用。Stream 不改变数据源，操作结果通常是新的 Stream 或值。","options":["A) Stream 不存储数据，是对数据源的一个视图","B) 中间操作是惰性的，遇到终止操作才执行","C) Stream 可以多次遍历，执行终止操作后仍可使用","D) Stream 操作不会修改数据源"],"hints":["Stream 与集合的区别","终止操作会消费 Stream"],"tags":["Java 8","Stream"],"id":2292},{"category":"java_advanced","difficulty":"easy","type":"multiple_choice","title":"创建线程的方式","content":"以下哪些是 Java 中创建线程或提交异步任务的方式？","answer":"A)、B)、D)。解析：创建线程有三种方式：继承 Thread 重写 run()、实现 Runnable 接口传给 Thread、实现 Callable 接口（有返回值、可抛异常）配合 FutureTask 或线程池。ThreadPoolExecutor.submit(Callable) 使用 Callable 接口。Thread.start() 是启动线程的正确方式，直接调用 run() 只是在当前线程执行普通方法，不会创建新线程。","options":["A) 继承 Thread 类重写 run() 方法","B) 实现 Runnable 接口传入 Thread","C) 直接调用 Thread 对象的 run() 方法","D) 实现 Callable 接口配合 ExecutorService"],"hints":["Callable 和 Runnable 的主要区别","start() 和 run() 的区别是什么"],"tags":["并发","线程"],"id":2296},{"category":"java_advanced","difficulty":"easy","type":"multiple_choice","title":"Optional 的正确使用","content":"以下关于 Java Optional 的使用建议，哪些是正确的？","answer":"A)、B)、C)。解析：Optional 是用来表示值可能为空的容器，核心是提供函数式处理空值的方式，避免 NPE。推荐用法：orElse() 提供默认值、orElseGet() 延迟求值（Supplier）、ifPresent() 判空后处理、orElseThrow() 明确抛出异常。不推荐用法：get() 前用 isPresent() 检查（等于换了个方式写 if null）、将 Optional 作为方法参数（增加调用方的负担只能传 null 或 Optional.of）、将 Optional 用于序列化/持久化字段。","options":["A) 使用 orElse() 提供默认值","B) 使用 orElseThrow() 明确抛出异常","C) 使用 map() 和 flatMap() 链式操作","D) 将 Optional 作为实体类字段"],"hints":["Optional 的设计初衷是返回值，不是字段类型","orElse 和 orElseGet 有什么区别"],"tags":["Java 8","Optional"],"id":2297},{"category":"java_advanced","difficulty":"easy","type":"multiple_choice","title":"ConcurrentHashMap 的分段锁","content":"关于 ConcurrentHashMap 的线程安全机制，以下哪些描述是正确的？","answer":"A)、B)、C)。解析：JDK 7 ConcurrentHashMap 使用 Segment（分段锁）继承 ReentrantLock，将数据分为 16 段，每段独立加锁，理论上支持 16 个线程并发写。JDK 8 分段锁已被取代：直接使用 Node 数组 + CAS + synchronized（只锁链表/红黑树头节点），并发粒度更细、内存占用更少。JDK 8 还在链表转红黑树时使用 TreeBin 的读写锁优化并发。ConcurrentHashMap 的迭代器是弱一致性（Weakly Consistent）的——迭代期间允许修改，不抛 ConcurrentModificationException。","options":["A) JDK 7 中使用 Segment 分段锁实现线程安全","B) JDK 8 中使用 CAS + synchronized 实现线程安全","C) 迭代器是弱一致性的，不抛 ConcurrentModificationException","D) ConcurrentHashMap 不允许 null 键，但允许 null 值"],"hints":["分段锁的设计演进","ConcurrentHashMap 和 HashTable 的性能差异来源"],"tags":["并发","ConcurrentHashMap"],"id":2300},{"category":"java_advanced","difficulty":"hard","type":"multiple_choice","title":"ThreadLocal 内存泄漏","content":"以下关于 ThreadLocal 可能导致内存泄漏的描述，哪些是正确的？","answer":"A)、C)、D)。解析：ThreadLocalMap 的 Entry 继承 WeakReference，key（ThreadLocal 实例）是弱引用，value 是强引用。当 ThreadLocal 对象没有外部强引用时，GC 会回收 key，但 value 仍然存在。此时 Entry 的 key 为 null，value 无法被访问（thread 存活期间不会被回收），造成内存泄漏。最佳实践：每次使用后调用 remove() 清理。Tomcat 等 Web 服务器使用线程池，线程复用会加剧泄漏风险——一个请求的 ThreadLocal 数据可能被下一个请求读到。","options":["A) ThreadLocalMap 的 Entry key 是弱引用","B) ThreadLocal 默认会在线程结束时自动清理所有数据","C) 线程池场景下 ThreadLocal 内存泄漏风险更大","D) 推荐每次使用后调用 remove() 方法清理"],"hints":["弱引用会在 GC 时被回收","线程池中线程复用导致 ThreadLocal 值无法被自动回收"],"tags":["并发","ThreadLocal","内存泄漏"],"id":2301},{"category":"java_advanced","difficulty":"hard","type":"multiple_choice","title":"JIT 编译优化","content":"以下关于 JIT（Just-In-Time）编译的描述，哪些是正确的？","answer":"A)、B)、D)。解析：JIT 将热点代码（HotSpot，执行次数达阈值后）编译为本地机器码，大幅提升执行效率。阈值由 -XX:CompileThreshold 控制（Client 模式 1500，Server 模式 10000）。逃逸分析（Escape Analysis）是 JIT 的关键优化：如果对象不逃逸方法或线程，可做栈上分配（消除堆分配）和同步消除（去掉不必要的锁）。方法内联（Inlining）将小方法体直接嵌入调用处，减少方法调用开销——这是 JIT 最重要的优化之一。JDK 8u40+ 支持分层编译（Tiered Compilation），结合 C1（轻量快速）和 C2（深度优化）的优势。","options":["A) JIT 将热点代码编译为本地机器码","B) 逃逸分析可实现栈上分配和同步消除","C) 所有代码都会被执行 JIT 编译","D) 方法内联是 JIT 最重要的优化手段之一"],"hints":["JIT 只编译热点代码，不是所有代码","逃逸分析 -XX:+DoEscapeAnalysis 默认开启"],"tags":["JVM","JIT","性能优化"],"id":2302},{"category":"java_advanced","difficulty":"easy","type":"multiple_choice","title":"String 不可变性","content":"以下关于 Java String 不可变性的描述，哪些是正确的？","answer":"A)、B)、C)。解析：A) String 被 final 修饰，不可被继承。B) String 内部使用 private final char[] value（JDK 8）或 private final byte[] value（JDK 9+）存储，value 引用不可变。C) substring() 在 JDK 7u6+ 中通过 new String() 创建新对象（JDK 7u6 之前共享 char[] 但已修复）。D 错误：String 不是通过「写时复制」实现的——写时复制是 CopyOnWriteArrayList 的实现策略。字符串常量池（String Pool）在堆中（JDK 7+），通过 intern() 方法放入。","options":["A) String 类被 final 修饰，不能被继承","B) String 内部使用 final 字符数组存储，创建后内容不可变","C) substring() 方法在 JDK 7u6 以后创建新的字符数组，不再共享原数组","D) String 的不可变性通过写时复制（Copy-on-Write）机制实现"],"hints":["String 的 final char[] 保证引用不变但内容不变吗——真正的不变性靠的是不提供修改数组内容的方法","JDK 7u6 之前 substring() 的内存泄漏问题——共享 char[] 导致大字符串无法被 GC"],"tags":["String","不可变性","Java 基础"],"id":2303},{"category":"java_advanced","difficulty":"easy","type":"multiple_choice","title":"类加载双亲委派模型","content":"以下关于 Java 类加载双亲委派模型的描述，哪些是正确的？","answer":"A)、B)、D)。解析：A) 双亲委派的核心——先让父加载器尝试加载，父加载器无法加载时才自己加载。B) 三层的默认加载器：启动类加载器 Bootstrap（C++ 实现，加载 rt.jar）、扩展类加载器 Extension（JDK 8 加载 jre/lib/ext，JDK 9 改为平台类加载器 Platform ClassLoader）、应用类加载器 Application（加载 classpath）。C 错误：双亲委派是先委托父加载器，不是先自己尝试。D) 破坏双亲委派的场景：JDBC（通过 SPI，线程上下文类加载器加载 Driver 实现）、Tomcat（每个 WebApp 有自己的类加载器优先加载 Web 应用的类）。","options":["A) 双亲委派模型的工作流程是：先委托父类加载器加载，父加载器无法加载时才由子加载器自己加载","B) Java 默认有三层类加载器：Bootstrap ClassLoader -> Extension ClassLoader -> Application ClassLoader","C) 双亲委派模型中，类加载器会先尝试自己加载类，加载失败才委托给父加载器","D) 破坏双亲委派的常见场景包括 JDBC 的 SPI 机制和 Web 容器（如 Tomcat）"],"hints":["双亲委派的「先父后子」和「先自己再父」是相反的——理解这个顺序对排查 ClassNotFoundException 有帮助","JDBC 为什么需要线程上下文类加载器——Bootstrap 不知道 MySQL Driver 的存在"],"tags":["类加载","双亲委派","JVM","SPI"],"id":2304},{"category":"java_advanced","difficulty":"easy","type":"multiple_choice","title":"Java 异常处理","content":"以下关于 Java 异常处理的描述，哪些是正确的？","answer":"A)、C)、D)。解析：A) Error 是 JVM 内部错误（OutOfMemoryError、StackOverflowError），程序不应捕获。B 错误：受检异常（Checked Exception）必须 catch 或 throws，非受检异常（RuntimeException）不需要。C) try-with-resources（JDK 7+）中 AutoCloseable 的资源会自动关闭。D) finally 唯一不执行的情况是 System.exit() 或 JVM 崩溃。注意：如果 finally 中有 return 语句，会覆盖 try 中的 return（这是一种不好的实践，阿里规约也禁止在 finally 中使用 return）。","options":["A) Error 类及其子类表示程序无法处理的严重错误，不应捕获","B) 所有异常都是受检异常（Checked Exception），必须显式捕获或声明抛出","C) try-with-resources 语句可以自动关闭实现了 AutoCloseable 接口的资源","D) finally 块在 try 块执行 return 后仍然会执行，除非 JVM 退出"],"hints":["受检异常和非受检异常的设计哲学——什么时候用哪一种","finally 中的 return 为什么被称为「坏味道」——它会吞掉 try 中的异常"],"tags":["异常","基础","语言特性"],"id":2305},{"category":"java_advanced","difficulty":"easy","type":"multiple_choice","title":"泛型擦除与桥接方法","content":"以下关于 Java 泛型擦除（Type Erasure）的描述，哪些是正确的？","answer":"A)、B)、D)。解析：A) 泛型信息在编译后从字节码中移除，运行时 List<Integer> 和 List<String> 是同一个 Class 对象。B) 编译器在必要时生成桥接方法（Bridge Method）保持多态——当子类继承泛型父类并指定具体类型时，编译器生成参数类型为 Object 的桥接方法内部调用具体类型的方法。C 错误：Java 不支持 List<int>，泛型类型不能是基本类型。D) 通过反射可以在运行时获取部分泛型信息（如父类的泛型参数 TypeReference 模式）。getClass() 获取字节码，getGenericSuperclass() 获取包含泛型参数的父类类型。","options":["A) Java 的泛型在编译后进行类型擦除，运行时不存在泛型类型信息","B) 编译器在必要时会生成桥接方法（Bridge Method）来保持多态性","C) Java 泛型支持基本类型，如 List<int> 是合法的","D) 泛型擦除后仍可通过反射获取某些泛型信息（如父类的泛型参数）"],"hints":["桥接方法为什么在泛型擦除后是必要的——ArrayList 继承 List<String> 时 add(Object) 和 add(String) 的关系","TypeReference/TypeToken 模式如何绕过类型擦除——在父类中保留泛型参数信息"],"tags":["泛型","类型擦除","桥接方法","反射"],"id":2306},{"category":"java_advanced","difficulty":"easy","type":"multiple_choice","title":"JVM 判定对象可回收的方法","content":"JVM 判定一个对象是否可回收使用哪些方法？","answer":"A)、B)。\n\n解析：JVM 判定对象是否可回收主要使用可达性分析（Reachability Analysis）——从 GC Roots 出发，不可达的对象被判定为可回收。引用计数法（Reference Counting）不是 JVM 使用的方法（无法解决循环引用问题）。对象在 finalize() 方法中可能自救（重新被引用），但 finalize() 只执行一次。A 正确——可达性分析是主要方法。B 也正确——对于 G1 和 ZGC 等区域性 GC，还会使用 Remembered Set / Card Table 来跟踪跨代/跨区域引用。C 错误——引用计数法是 Python/Objective-C 使用的方式，JVM 不使用。D 错误——并发标记完成后还有最终标记/重新标记阶段处理并发期间的引用变化。","options":["A) 可达性分析（Reachability Analysis）","B) Remembered Set + 卡表（Card Table）","C) 引用计数法（Reference Counting）","D) 并发标记（Concurrent Marking）完成后立即回收"],"hints":["主流 JVM 使用可达性分析而非引用计数法","跨代引用通过 Remembered Set 和卡表跟踪"],"tags":["JVM","GC","可达性分析"],"id":2316},{"category":"java_advanced","difficulty":"hard","type":"multiple_choice","title":"JVM 参数分类与内存设置","content":"以下哪些 JVM 参数用于设置堆内存大小？","answer":"A)、B)、C)。\n\n解析：A)-Xms 设置初始堆大小，B)-Xmx 设置最大堆大小，C)-Xmn 设置新生代大小（不推荐 JDK 9+，优先用 -XX:NewSize/-XX:MaxNewSize），D)-Xss 设置线程栈大小（不是堆内存）。实际调优中通常将 -Xms 和 -Xmx 设为相同值，避免运行时动态调整堆大小导致性能抖动。E 错误——-XX:PermSize 设置永久代初始大小（JDK 8 之前），JDK 8+ 已不存在。\n\n扩展延伸：其他关键参数——-XX:NewRatio 设置老年代/新生代比例（默认 2，新生代为堆的 1/3）。-XX:SurvivorRatio 设置 Eden 与单个 Survivor 的比例（默认 8）。-XX:MaxMetaspaceSize 和 -XX:MetaspaceSize 控制元空间。容器化环境需注意 UseContainerSupport（JDK 8u191+ 默认开启）使 JVM 感知容器内存限制。","options":["A) -Xms","B) -Xmx","C) -Xmn","D) -Xss","E) -XX:PermSize"],"hints":["-X 参数和 -XX 参数的区别是什么","为什么生产环境通常把 -Xms 和 -Xmx 设相同值"],"tags":["JVM","参数","调优"],"id":2317},{"category":"java_advanced","difficulty":"hard","type":"multiple_choice","title":"Java 线程安全实现的层次","content":"以下哪些是 Java 中实现线程安全的方式？","answer":"A)、B)、D)。\n\n解析：线程安全实现层次 1）不可变——final + 不可变对象（如 String），天然线程安全。2）互斥同步——synchronized、ReentrantLock、ReadWriteLock（悲观锁）。3）非阻塞同步——CAS + volatile（乐观锁），AtomicInteger 等原子类。4）无同步方案——ThreadLocal（线程本地存储不共享）、可重入代码（不依赖堆上的共享数据）。C 错误——volatile 不保证原子性，不能解决所有线程安全问题（如 i++ 需要原子类或锁）。\n\n扩展延伸：线程安全等级（Brian Goetz 分类）——1）不可变（Immutable）——永远安全。2）绝对线程安全——不管运行时环境如何都不需要额外同步（Java 中几乎没有完全做到，如 Vector 的复合操作仍需外部同步）。3）相对线程安全——单独操作安全（synchronized 修饰方法），但复合操作需要额外同步。4）线程兼容——非线程安全，需要调用方自行同步（ArrayList、HashMap）。5）线程对立——即使调用方同步也无法安全使用（如 Thread.suspend()，已废弃）。","options":["A) 使用 synchronized 关键字","B) 使用 ReentrantLock","C) 使用 volatile 关键字","D) 使用 ThreadLocal 实现线程封闭"],"hints":["volatile 不能替代锁——它不保证原子性","ThreadLocal 是线程封闭，不涉及共享"],"tags":["并发","线程安全","锁"],"id":2318},{"category":"java_advanced","difficulty":"hard","type":"multiple_choice","title":"G1 GC 的 Mixed GC 过程","content":"关于 G1 垃圾回收器的 Mixed GC（混合回收）阶段，以下哪些描述是正确的？","answer":"A)、C)、D)。\n\n解析：G1 的 Mixed GC 在并发标记完成后触发，不仅回收年轻代，还回收标记为垃圾最多的老年代 Region（根据 -XX:G1MixedGCLiveThresholdPercent 判断存活对象比例）。B 错误——Mixed GC 必须依赖并发标记周期（CMS）的结果来确定哪些老年代 Region 值得回收。G1 的工作分为三种类型：Young GC（仅年轻代，Eden 满时触发）、并发标记周期（Concurrent Marking Cycle，CMS，当堆使用率达 -XX:InitiatingHeapOccupancyPercent=45% 时触发）、Mixed GC（回收年轻代 + 部分老年代，在 CMS 后触发）。D 正确——-XX:G1HeapWastePercent（默认 5%）控制并发标记后触发 Mixed GC 的条件——只有当可回收的垃圾比例超过该值时才触发。\n\n扩展延伸：G1 的停顿预测模型基于历史平均停顿时间，通过 -XX:MaxGCPauseMillis（默认 200ms）控制目标。G1 选择回收 Region 时优先选择回收收益大的（垃圾最多的 Region）。如果时间预算允许，继续选择更多 Region 直到时间用完或所有标记的老年代 Region 都回收了。","options":["A) Mixed GC 不仅回收年轻代，还回收部分老年代 Region","B) Mixed GC 不需要并发标记阶段，可以独立触发","C) G1 的停顿时间目标通过 -XX:MaxGCPauseMillis 控制","D) G1 通过 -XX:G1HeapWastePercent 控制触发 Mixed GC 的时机"],"hints":["Mixed GC 的前提是并发标记周期已完成","G1 优先回收垃圾比例最多的 Region"],"tags":["JVM","G1","GC"],"id":2319},{"category":"java_advanced","difficulty":"medium","type":"multiple_choice","title":"Java 线程的优先级","content":"以下关于 Java 线程优先级的描述，哪些是正确的？","answer":"A)、C)、D)。\n\n解析：A 正确——Java 中线程优先级范围是 1（MIN_PRIORITY）到 10（MAX_PRIORITY），默认 5（NORM_PRIORITY）。B 错误——线程优先级不能保证执行顺序！优先级只是给操作系统调度器的建议，实际操作系统（尤其是 Linux）可能忽略 Java 的优先级映射。Windows 有 7 个优先级级别，Linux 默认不将 Java 的优先级映射到原生线程优先级（需要使用实时调度策略或调整 nice 值）。C 正确——优先级高的线程获得更多 CPU 时间片（但不保证）。D 正确——线程优先级依赖具体操作系统和 JVM 实现。\n\n扩展延伸：代码中应避免依赖线程优先级来控制执行顺序——这可能导致跨平台行为不一致。更好的方式是使用显式的同步工具（CountDownLatch、Semaphore 等）控制执行流程。线程优先级在实时系统（Real-Time Java）中有实际意义，但在通用 Linux 服务器上效果有限。","options":["A) Java 线程优先级范围是 1~10，默认 5","B) 设置优先级可以保证高优先级线程先执行","C) 优先级高的线程获得更多 CPU 时间片的概率更大","D) 线程优先级在不同操作系统上的表现可能不同"],"hints":["线程优先级是建议性的，不同操作系统的映射不同","不要依赖线程优先级来控制执行顺序——应用锁或同步工具"],"tags":["并发","线程","优先级"],"id":2320},{"category":"java_advanced","difficulty":"medium","type":"multiple_choice","title":"ConcurrentHashMap 在 JDK 8 中的改进","content":"相比 JDK 7，JDK 8 的 ConcurrentHashMap 做了哪些重要改进？（多选）","options":["A) 用 Node 数组 + 链表/红黑树替代 Segment 分段锁","B) 使用 CAS + synchronized 实现并发安全","C) 引入了分段锁机制提高并发性能","D) 引入了 countCell 计数机制减少竞争"],"answer":"A)、B)、D)。\n\n解析：JDK 8 对 ConcurrentHashMap 进行了大幅重写——A 正确：JDK 7 使用 Segment（继承 ReentrantLock）分段锁，默认 16 个 Segment。JDK 8 废弃了 Segment 结构，改为 Node 数组 + 链表/红黑树，锁粒度从 Segment 级别降低到 Bucket 级别（每个桶独立加锁）。B 正确：JDK 8 中，空桶用 CAS 插入第一个节点，碰撞时用 synchronized 锁住桶的头节点进行插入和扩容。C 错误：分段锁是 JDK 7 的做法（默认 16 个 Segment，并发度 16），JDK 8 已经用更细粒度的桶锁替代了分段锁。D 正确：JDK 8 引入了 CounterCell 数组（类似 LongAdder 的分段计数方式）来维护 size 计数，减少了多线程 put 时的计数竞争。\n\n扩展延伸：JDK 8 的 ConcurrentHashMap 在链表长度 > 8 且数组长度 ≥ 64 时转为红黑树，优化了哈希冲突严重时的查找性能。此外，JDK 8 的 CHM 还优化了扩容——支持多线程并发协助扩容（通过 ForwardingNode 数组标识已迁移的桶）。JDK 8 的 size() 方法使用 sumCount() 累加 CounterCell 数组和 baseCount，不再需要加锁。","hints":["JDK 7 的 Segment 锁粒度是 16 个分区","JDK 8 的锁粒度是每个桶（Bucket），而且用 synchronized 替代 ReentrantLock"],"tags":["Java","并发","ConcurrentHashMap","集合"],"id":2321},{"category":"java_advanced","difficulty":"medium","type":"multiple_choice","title":"ThreadPoolExecutor 的拒绝策略","content":"ThreadPoolExecutor 提供了哪些拒绝策略（RejectedExecutionHandler）？（多选）","options":["A) AbortPolicy——抛出 RejectedExecutionException","B) DiscardPolicy——静默丢弃新任务","C) DiscardOldestPolicy——丢弃队列中最旧的任务，然后重新提交","D) CallerRunsPolicy——由提交任务的线程直接运行该任务"],"answer":"A)、B)、C)、D)。\n\n解析：JDK 提供了四种内置拒绝策略（全部正确）：A——AbortPolicy（默认策略）：线程池无法接收新任务时抛出 RejectedExecutionException。调用方捕获异常处理。B——DiscardPolicy：直接丢弃新提交的任务，不抛出任何异常。适用于不重要、可丢弃的任务（如日志记录）。C——DiscardOldestPolicy：丢弃工作队列中最旧的（head of queue）未处理任务，然后重新提交当前任务。适用于任务的新鲜度比完成度更重要的场景。D——CallerRunsPolicy：由提交任务的线程（调用 execute/submit 的线程）直接运行该任务。这提供了一种简单的节流机制——主线程运行任务时无法提交更多任务，从而降低任务提交速率。\n\n扩展延伸：除了四种内置策略，还可以自定义 RejectedExecutionHandler 实现特殊逻辑（如将任务写入消息队列以便后续重试、阻塞提交线程直到队列有空位等）。注意 CallerRunsPolicy 的风险——如果主线程也执行任务，它可能会被长时间阻塞，导致应用程序的响应性下降。同时，由于提交任务的线程执行了任务，它不再是\"提交者\"，提交速率自然下降，形成反馈节流。DiscardOldestPolicy 需要与有界队列配合使用（如 ArrayBlockingQueue），在无界队列上它永远不会触发（因为队列永远不会满）。","hints":["AbortPolicy 是默认策略（抛出异常）","CallerRunsPolicy 通过让提交线程执行任务来实现节流"],"tags":["Java","并发","线程池","拒绝策略"],"id":2322},{"category":"java_advanced","difficulty":"hard","type":"multiple_choice","title":"synchronized 和 ReentrantLock 的对比","content":"以下关于 synchronized 和 ReentrantLock 的描述，哪些是正确的？（多选）","options":["A) ReentrantLock 支持尝试获取锁（tryLock）、可中断获取锁","B) synchronized 在 JDK 8 之后性能已经优于 ReentrantLock","C) ReentrantLock 可以创建多个 Condition 实现精细化的等待/通知","D) synchronized 是 JVM 层面的锁，ReentrantLock 是 API 层面的锁"],"answer":"A)、C)、D)。\n\n解析：A 正确——ReentrantLock 提供了 tryLock()（尝试获取锁，立即返回 boolean）、tryLock(timeout, unit)（限时尝试）、lockInterruptibly()（可中断获取）等灵活方法，synchronized 不支持这些操作。B 错误——JDK 6 对 synchronized 进行了大量优化（偏向锁、轻量级锁、锁粗化、锁消除），使 synchronized 在大多数场景下与 ReentrantLock 性能相当甚至更优。但性能对比不是简单说 synchronized 优于 ReentrantLock，而是两者在不同场景下各有所长。不过 JDK 8 后，官方更推荐在不需要高级功能时优先使用 synchronized。C 正确——ReentrantLock 通过 newCondition() 可以创建多个 Condition 对象（如生产者-消费者模式中的 notFull 和 notEmpty 两个条件），而 synchronized 的 wait/notify 只有一个隐式条件。D 正确——synchronized 是 Java 语言关键字，由 JVM 通过 monitor 指令（monitorenter/monitorexit）实现。ReentrantLock 是 java.util.concurrent.locks 包中的类，基于 AQS（AbstractQueuedSynchronizer）实现，完全是 Java API 级别。\n\n扩展延伸：JDK 6+ 中，synchronized 的性能经过大规模优化后，在竞争不激烈时优于 ReentrantLock（偏向锁 + 轻量级锁优化）。在激烈竞争下两者接近。选择建议：如果不需要 tryLock、可中断、多 Condition、公平锁等高级功能，优先使用 synchronized 以减少代码复杂度和出错可能性。虚拟线程场景下，synchronized 会导致 pinned 问题，此时推荐使用 ReentrantLock。","hints":["ReentrantLock 提供 tryLock、可中断、多 Condition 等高级功能","JDK 6+ 对 synchronized 做了大量优化，性能与 ReentrantLock 相当"],"tags":["Java","并发","synchronized","ReentrantLock","锁"],"id":2323},{"category":"java_advanced","difficulty":"hard","type":"multiple_choice","title":"happens-before 规则","content":"以下哪些属于 JMM（Java 内存模型）中定义的 happens-before 规则？（多选）","options":["A) 程序次序规则——同一个线程中，写在前面的操作 happens-before 后面的操作","B) volatile 变量规则——对一个 volatile 变量的写 happens-before 后面对该变量的读","C) 传递性——如果 A happens-before B, B happens-before C，则 A happens-before C","D) 线程启动规则——Thread.start() happens-before 该线程中的任何操作"],"answer":"A)、B)、C)、D)。\n\n解析：JMM 的 happens-before 规则是判断数据竞争（Data Race）和定义内存可见性的依据。全选正确：A——程序次序规则（Program Order Rule）：单线程内，按代码顺序，前面的操作 happens-before 后面的操作（不考虑重排序的等效性）。B——volatile 变量规则（Volatile Variable Rule）：对 volatile 的写操作 happens-before 对同一 volatile 的读操作（保证可见性）。C——传递性（Transitivity）：happens-before 关系具有传递性，这是推导其他规则的基础。D——线程启动规则（Thread Start Rule）：主线程调用 t.start() happens-before 线程 t 的任何操作。\n\n扩展延伸：完整的 happens-before 规则还包括：监视器锁规则（Monitor Lock Rule——对锁的 unlock happens-before 后续对该锁的 lock）、线程终止规则（Thread Termination Rule——线程中所有操作 happens-before 其他线程检测到该线程已终止，通过 t.join() 或 t.isAlive()）、线程中断规则（Thread Interruption Rule——调用 interrupt() happens-before 被中断线程检测到中断）、对象终结规则（Finalizer Rule——对象构造完成 happens-before finalize() 的执行）。这些规则共同定义了 JMM 的内存可见性保证。","hints":["happens-before 是 JMM 中判断两个操作是否有序的规则","传递性规则使得我们可以推导出跨多个规则的 happens-before 关系"],"tags":["Java","JMM","happens-before","并发"],"id":2324},{"category":"java_advanced","difficulty":"medium","type":"multiple_choice","title":"CompletableFuture 的异步回调方法","content":"以下关于 CompletableFuture 异步回调的描述，哪些是正确的？（多选）","options":["A) thenApply 对结果进行转换，返回新的 CompletableFuture","B) thenAccept 消费结果，不返回新值","C) thenRun 在上一个阶段完成后执行一个 Runnable，不依赖前阶段的结果","D) exceptionally 处理前阶段的异常并提供替代结果"],"answer":"A)、B)、C)、D)。\n\n解析：全选正确。A——thenApply(Function<T,R>) 将前阶段的结果通过 Function 转换为新值，返回 CompletableFuture<R>（类似 Stream.map）。B——thenAccept(Consumer) 消费前阶段的结果，返回 CompletableFuture<Void>，不产生新值（类似 Stream.forEach）。C——thenRun(Runnable) 在前阶段完成后执行一个动作，不关心前阶段的结果，返回 CompletableFuture<Void>。D——exceptionally(Function<Throwable,T>) 在前阶段异常完成时处理异常（类似 catch），返回替代结果。\n\n扩展延伸：CompletableFuture 的回调方法分三类——1）非异步版本（thenApply/thenAccept/thenRun）：在触发该回调的线程中执行（可能是前阶段线程或调用 complete 的线程）。2）异步版本（thenApplyAsync/thenAcceptAsync/thenRunAsync）：在 ForkJoinPool.commonPool() 或指定 Executor 中执行。3）组合方法：thenCompose（flatMap 风格，用于链式组合依赖的 Future）、thenCombine（合并两个独立的 Future 结果）、allOf（等待所有完成）、anyOf（任意一个完成）。异常处理链：exceptionally → handle（无论正常/异常都处理）→ whenComplete（类似 finally，不改变结果）。建议在异步回调中始终指定自定义 Executor（避免使用共享的 commonPool 导致任务饥饿）。","hints":["thenApply 做转换，thenAccept 做消费，thenRun 做后续动作","exceptionally 类似于 catch，handle 类似于 try-catch-finally"],"tags":["Java","并发","CompletableFuture","异步"],"id":2325},{"category":"java_advanced","difficulty":"easy","type":"true_false","title":"volatile 保证原子性","content":"volatile 关键字可以保证对变量的操作是原子性的。","answer":"错误。解析：volatile 保证可见性和禁止指令重排序，但不保证原子性。例如 count++ 包含读取、加1、写入三步，volatile 不能保证这三步的原子性。需要原子性时应使用 synchronized、Lock 或 AtomicInteger 等原子类。","tags":["并发","volatile"],"options":["正确","错误"],"id":2396},{"category":"java_advanced","difficulty":"easy","type":"true_false","title":"synchronized 是悲观锁","content":"Java 中的 synchronized 属于悲观锁。","answer":"正确。解析：synchronized 默认假设并发冲突会发生，因此使用阻塞式加锁。但在 JDK 6 之后引入了锁升级机制（偏向锁→轻量级锁→重量级锁），轻量级锁通过 CAS 自旋实现，融合了乐观锁思想，但整体上仍属于悲观锁范畴。","tags":["并发","synchronized"],"options":["正确","错误"],"id":2397},{"category":"java_advanced","difficulty":"hard","type":"true_false","title":"G1 是 JDK 8 默认的垃圾回收器","content":"JDK 8 的默认垃圾回收器是 G1（Garbage First）。","answer":"错误。解析：JDK 8 的默认垃圾回收器是 Parallel Scavenge + Parallel Old（并行回收器）。G1 从 JDK 9 才开始成为默认垃圾回收器。","tags":["JVM","GC"],"options":["正确","错误"],"id":2398},{"category":"java_advanced","difficulty":"easy","type":"true_false","title":"方法区在 JDK 8 中被移除","content":"JDK 8 中移除了方法区（Method Area），使用元空间（Metaspace）替代。","answer":"正确。解析：JDK 8 中永久代（PermGen，方法区的实现）被移除，由元空间（Metaspace）替代。区别在于：永久代使用 JVM 堆内存，元空间使用本地内存（Native Memory），不再受 JVM 最大内存限制。","tags":["JVM","内存结构"],"options":["正确","错误"],"id":2399},{"category":"java_advanced","difficulty":"easy","type":"true_false","title":"线程池核心线程会被回收","content":"ThreadPoolExecutor 中，如果 allowCoreThreadTimeOut 设置为 true，核心线程也会因空闲超时被回收。","answer":"正确。解析：默认情况下核心线程即使空闲也会存活。但调用 allowCoreThreadTimeOut(true) 后，核心线程也会受 keepAliveTime 控制，超时后会被回收。这在低负载场景下可以节省线程资源。","tags":["并发","线程池"],"options":["正确","错误"],"id":2400},{"category":"java_advanced","difficulty":"easy","type":"true_false","title":"Stream 可以重复使用","content":"Java 8 的 Stream 执行完终止操作后可以再次遍历。","answer":"错误。解析：Stream 执行终止操作（如 collect、forEach）后就被消费了，不能再次使用。Stream 是一次性的，如果需要重新遍历，必须重新创建 Stream。这类似于迭代器只能单向遍历一次。","tags":["Java 8","Stream"],"options":["正确","错误"],"id":2401},{"category":"java_advanced","difficulty":"easy","type":"true_false","title":"Lambda 表达式会生成匿名内部类","content":"Lambda 表达式在编译时会生成匿名内部类。","answer":"错误。解析：Lambda 表达式不会编译为匿名内部类。编译器使用 invokedynamic 指令在运行时动态生成实现，避免了匿名内部类每次加载时的类文件生成开销。这是性能优于匿名内部类的原因之一。","tags":["Java 8","Lambda"],"options":["正确","错误"],"id":2402},{"category":"java_advanced","difficulty":"hard","type":"true_false","title":"单例模式的双重检查锁需要 volatile","content":"双重检查锁定（Double-Checked Locking）实现单例时，instance 变量需要用 volatile 修饰。","answer":"正确。解析：不加 volatile 可能导致指令重排序：instance = new Singleton() 分为分配内存→初始化对象→赋值三步，可能先赋值（引用不为 null）后初始化，导致其他线程拿到未初始化的对象。volatile 禁止重排序解决此问题。","tags":["并发","单例"],"options":["正确","错误"],"id":2403},{"category":"java_advanced","difficulty":"easy","type":"true_false","title":"Arrays.asList 返回的 List 可修改","content":"Arrays.asList() 返回的 List 支持 add() 和 remove() 操作，可以动态增删元素。","options":["正确","错误"],"answer":"错误。\n\n解析：Arrays.asList() 返回的是基于原数组的固定长度视图（java.util.Arrays.ArrayList 内部类），不支持 add/remove 操作（会抛出 UnsupportedOperationException）。但 set() 方法可以修改元素，且修改会同步反映到原数组。需要可变 List 应使用 new ArrayList<>(Arrays.asList(array))。\n\n扩展延伸：类似的陷阱——List.of()（JDK 9+）返回的也是不可变 List，不支持任何修改操作（包括 set）。subList 返回的视图支持结构修改但受限于原 List。","hints":["Arrays.asList 返回的是固定长度视图，不是 ArrayList","Java 9 的 List.of() 也是不可变的"],"tags":["Java","集合","Arrays","陷阱"],"id":2418},{"category":"java_advanced","difficulty":"easy","type":"true_false","title":"Java 8 的 Optional 可以为 null","content":"Optional.ofNullable() 允许传入 null 值，如果原始值为 null 返回 Optional.empty()。","options":["正确","错误"],"answer":"正确。\n\n解析：Optional.ofNullable(value) 在 value 为 null 时返回 Optional.empty()，不会抛 NPE。而 Optional.of(value) 如果传入 null 会立即抛出 NullPointerException。Optional.ofNullable 是安全创建 Optional 的方式。再次强调——Optional 主要用于返回值类型，不应作为字段、方法参数或集合元素使用。\n\n扩展延伸：Optional 的常见用法——optional.orElse(defaultValue)、optional.orElseGet(() -> expensiveComputation())、optional.orElseThrow(() -> new CustomException())、optional.map(...).filter(...).ifPresent(...)。orElse 和 orElseGet 的区别——orElse 的参数即使值存在也会求值，orElseGet 只在值不存在时执行 Supplier。","hints":["ofNullable 与 of 的区别在于是否允许 null","orElse 和 orElseGet 的求值时机不同"],"tags":["Java 8","Optional"],"id":2419},{"category":"java_advanced","difficulty":"easy","type":"true_false","title":"finally 块中 return 的不良实践","content":"finally 块中不应该包含 return 语句，因为 finally 的 return 会覆盖 try/catch 中的 return 或异常。","options":["正确","错误"],"answer":"正确。\n\n解析：finally 块中的 return 语句是 Java 中广为人知的不良实践（阿里巴巴 Java 规范也明确禁止）。原因 1）finally 中的 return 会覆盖 try 块中的 return 值。2）如果 try 块抛出了异常，finally 中的 return 会吞掉该异常（异常不会传播出去）。finally 块的正确用法是仅用于释放资源（关闭文件、释放锁等），不放置业务逻辑。\n\n扩展延伸：finally 中的 return 覆盖规则——try 中 return 1 首先被求值（1 被保存到栈中），然后 finally 执行并 return 3，此时 try 中保存的返回值 1 被丢弃，最终返回 3。异常吞没——try 块异常已经记录但 finally 的 return 直接返回导致异常无法传播到调用方。","hints":["finally 中的 return 会覆盖 try 中的 return 和异常","阿里巴巴 Java 规约禁止在 finally 中使用 return"],"tags":["Java","异常","finally","不良实践"],"id":2420},{"category":"java_advanced","difficulty":"hard","type":"true_false","title":"JVM 栈上分配的条件","content":"JVM 中所有不逃逸的对象都会被分配到栈上（栈上分配）。","options":["正确","错误"],"answer":"错误。\n\n解析：栈上分配（Stack Allocation）是逃逸分析的优化结果之一，但不是所有不逃逸的对象都会被栈上分配。JVM 的 C2 编译器通过逃逸分析判断对象不逃逸后，实际执行的是标量替换（Scalar Replacement）——将对象分解为多个独立标量（原始类型字段），在栈上分配这些标量，而不是在栈上分配对象本身。标量替换后栈中只有零散的基本类型字段，没有对象实体。\n\n扩展延伸：逃逸分析的三种优化——1）栈上分配（通过标量替换实现）。2）同步消除（Lock Elimination）——去掉不会逃逸到其他线程的锁。3）标量替换本身。并非所有不逃逸对象都会被优化——对象字段过多或太大时，JIT 可能放弃标量替换。逃逸分析是 C2 编译器的优化，C1 仅做有限支持。","hints":["栈上分配实际是通过标量替换实现的","不是所有不逃逸的对象都会被优化"],"tags":["JVM","逃逸分析","栈上分配"],"id":2421},{"category":"java_advanced","difficulty":"easy","type":"true_false","title":"G1 GC 是分代垃圾回收器","content":"G1（Garbage First）垃圾回收器也是一种分代（Generational）垃圾回收器，拥有年轻代和老年代的概念。","options":["正确","错误"],"answer":"正确。\n\n解析：G1 虽是分区（Region）设计，但仍然保留分代概念。G1 中的 Region 分为 Eden Region、Survivor Region、Old Region 和 Humongous Region。Eden 和 Survivor 构成年轻代，Old 构成老年代。G1 的 Young GC 回收 Eden + Survivor，Mixed GC 回收年轻代 + 部分老年代 Region。注意 G1 与传统的分代 GC（如 Parallel、CMS）的区别——传统分代 GC 中年轻代和老年代是连续的内存块，G1 的 Region 可以动态改变角色（Eden 用完可以变成 Old）。\n\n扩展延伸：ZGC 和 Shenandoah（某些配置下）是不分代的（Non-generational），即没有年轻代和老年代的概念，所有对象在同一个堆中处理。不过 ZGC 的 JEP 439（Generational ZGC，JDK 21 引入）又重新引入了分代概念，以提升性能（减少了 Full GC 频率，降低了 CPU 开销）。这也说明了分代假设（大多数对象朝生夕死）对于 GC 性能的重要性。","hints":["G1 的 Region 角色可以是 Eden、Survivor、Old、Humongous","G1 有 Young GC 和 Mixed GC（回收年轻代 + 部分老年代）"],"tags":["JVM","G1","GC","分代"],"id":2423},{"category":"java_advanced","difficulty":"easy","type":"true_false","title":"ConcurrentHashMap 允许 null key","content":"ConcurrentHashMap 的 key 和 value 都允许为 null。","options":["正确","错误"],"answer":"错误。\n\n解析：ConcurrentHashMap 不允许 null key 和 null value，这是它和 HashMap 的重要区别（HashMap 允许一个 null key 和多个 null value）。原因是 ConcurrentHashMap 的作者 Doug Lea 认为：在多线程环境下，可以通过 get(key) 返回 null 来推断两种情况——1）该 key 不存在；2）该 key 对应的 value 就是 null。这两种情况的含义完全不同，但在并发环境下无法简单区分（因为可能其他线程正在修改）。HashMap 的 containsKey() 方法可以区分，但 CHM 在多线程中不能可靠使用 containsKey 来判断。所以 CHM 直接禁止 null value，避免歧义。\n\n扩展延伸：Hashtable 也不允许 null key/value（作为线程安全的遗留类，JDK 1.0 就如此设计）。HashMap 允许 null：null key 的 hashCode 为 0，存储在 index 0 的桶中。ConcurrentSkipListMap 允许 null key 吗？不允许（NavigableMap 的实现通常不允许 null key，因为比较器在排序时无法处理 null）。","hints":["Doug Lea 认为 null value 在并发 Map 中会导致二义性问题","HashMap 允许 null key/value，但 ConcurrentHashMap 和 Hashtable 都不允许"],"tags":["Java","并发","ConcurrentHashMap","null"],"id":2425}];
